/**
 * inneranimalmedia Worker
 * Serves: ASSETS (public homepage) + DASHBOARD (auth, dashboard pages).
 * Durable Objects: IAM_COLLAB, CHESS_SESSION (stubs until full logic restored from R2).
 * Browser: MYBROWSER -- Playwright for /api/browser/* and /api/playwright/* when binding is configured.
 * --remote only; no local dependencies.
 */

import { DurableObject } from "cloudflare:workers";
// @cloudflare/playwright loaded dynamically at runtime
let playwrightLaunch = null;

const DOCS_SCREENSHOTS_PUBLIC_BASE = 'https://docs.inneranimalmedia.com';
const DASHBOARD_SCREENSHOTS_PUBLIC_BASE = 'https://pub-b845a8f899834f0faf95dc83eda3c505.r2.dev';

/**
 * Store agent/browser tool screenshots. Prefer env.DOCS_BUCKET (public: docs.inneranimalmedia.com).
 * Fallback: env.DASHBOARD (legacy pub r2.dev), then env.R2 (legacy URL; pre-deploy safety).
 */
async function putAgentBrowserScreenshotToR2(env, buf, contentType) {
  const ct = contentType || 'image/png';
  const blen = buf?.byteLength ?? buf?.length ?? 0;
  if (env.DOCS_BUCKET) {
    const ts = Date.now();
    const id = crypto.randomUUID();
    const key = `screenshots/agent/${ts}-${id}.png`;
    await env.DOCS_BUCKET.put(key, buf, { httpMetadata: { contentType: ct } });
    const screenshot_url = `${DOCS_SCREENSHOTS_PUBLIC_BASE}/${key}`;
    void insertAiGenerationLog(env, {
      generationType: 'browser_screenshot_r2',
      responseText: screenshot_url,
      metadataJson: { bucket: 'DOCS_BUCKET', r2_key: key, byte_length: blen, content_type: ct },
    });
    return { screenshot_url, job_id: id };
  }
  if (env.DASHBOARD) {
    const id = crypto.randomUUID();
    const key = `screenshots/${id}.png`;
    await env.DASHBOARD.put(key, buf, { httpMetadata: { contentType: ct } });
    const screenshot_url = `${DASHBOARD_SCREENSHOTS_PUBLIC_BASE}/${key}`;
    void insertAiGenerationLog(env, {
      generationType: 'browser_screenshot_r2',
      responseText: screenshot_url,
      metadataJson: { bucket: 'DASHBOARD', r2_key: key, byte_length: blen, content_type: ct },
    });
    return { screenshot_url, job_id: id };
  }
  if (env.R2) {
    const id = crypto.randomUUID();
    const key = `screenshots/${id}.png`;
    await env.R2.put(key, buf, { httpMetadata: { contentType: ct } });
    const screenshot_url = `${DASHBOARD_SCREENSHOTS_PUBLIC_BASE}/${key}`;
    void insertAiGenerationLog(env, {
      generationType: 'browser_screenshot_r2',
      responseText: screenshot_url,
      metadataJson: { bucket: 'R2', r2_key: key, byte_length: blen, content_type: ct },
    });
    return { screenshot_url, job_id: id };
  }
  throw new Error('No R2 bucket for screenshots');
}

function normalizeThemeSlug(value) {
  if (!value || typeof value !== 'string') return null;
  return value.startsWith('theme-') ? value.substring(6) : value;
}

/** Parse cms_themes row.config JSON for theme API responses. */
function parseCmsThemeRowConfig(themeRow) {
  const cfg = (themeRow?.config && typeof themeRow.config === 'string')
    ? (() => { try { return JSON.parse(themeRow.config); } catch (_) { return {}; } })()
    : (typeof themeRow?.config === 'object' && themeRow?.config !== null ? themeRow.config : {});
  return cfg && typeof cfg === 'object' ? cfg : {};
}

/** Truecolor ANSI foreground from #RRGGBB (terminal login scenes). */
function hexToAnsi(hex) {
  if (!hex || typeof hex !== 'string' || !hex.startsWith('#') || hex.length < 7) return '';
  const r = parseInt(hex.slice(1, 3), 16);
  const g = parseInt(hex.slice(3, 5), 16);
  const b = parseInt(hex.slice(5, 7), 16);
  if (Number.isNaN(r) || Number.isNaN(g) || Number.isNaN(b)) return '';
  return `\u001b[38;2;${r};${g};${b}m`;
}

/** Replace %%TOKEN%% placeholders in terminal.login_scene using theme cssVars (hex only). */
function resolveSceneTokens(scene, cssVars) {
  if (!scene || !cssVars || typeof cssVars !== 'object') return scene;
  const get = (...keys) => {
    for (const k of keys) {
      const v = cssVars[k];
      if (v && typeof v === 'string' && v.startsWith('#')) return hexToAnsi(v);
    }
    return '';
  };
  return String(scene)
    .replace(/%%PRIMARY%%/g, get('--color-primary'))
    .replace(/%%BG%%/g, get('--bg-canvas'))
    .replace(/%%SURFACE%%/g, get('--bg-elevated', '--bg-surface'))
    .replace(/%%TEXT%%/g, get('--color-text', '--text-primary'))
    .replace(/%%MUTED%%/g, get('--text-muted'))
    .replace(/%%CYAN%%/g, get('--accent-cyan', '--color-primary-hover', '--color-primary'))
    .replace(/%%ORANGE%%/g, get('--accent-orange', '--color-primary'))
    .replace(/%%YELLOW%%/g, get('--accent-warning', '--text-muted'))
    .replace(/%%GREEN%%/g, get('--accent-success', '--color-success'))
    .replace(/%%RED%%/g, get('--accent-danger', '--color-danger'))
    .replace(/%%RESET%%/g, '\u001b[0m')
    .replace(/%%BOLD%%/g, '\u001b[1m')
    .replace(/%%DIM%%/g, '\u001b[2m');
}

/** GET /api/settings/theme JSON body (variables + optional terminal / monaco). */
function themeApiPayloadFromRow(slug, themeRow) {
  const cfg = parseCmsThemeRowConfig(themeRow);
  const variables = variablesFromCmsThemeConfig(cfg);
  const cssVars = cfg.cssVars && typeof cfg.cssVars === 'object' ? cfg.cssVars : {};
  const rawScene = cfg.terminal?.login_scene ?? null;
  const terminalOut = cfg.terminal
    ? {
      ...cfg.terminal,
      login_scene: rawScene ? resolveSceneTokens(rawScene, cssVars) : null,
    }
    : null;
  return {
    theme: slug,
    name: themeRow?.name || slug,
    variables,
    is_dark: cfg.is_dark ?? 1,
    monaco_theme: cfg.monaco_theme ?? 'vs-dark',
    terminal: terminalOut,
  };
}

/** Merge cms_themes.config into API `variables` (GET /api/settings/theme). Supports cssVars (camelCase) and css_vars. */
function variablesFromCmsThemeConfig(cfg) {
  if (!cfg || typeof cfg !== 'object') cfg = {};
  const variables = {};
  const mergeCssVars = (obj) => {
    if (!obj || typeof obj !== 'object') return;
    for (const k of Object.keys(obj)) {
      if (obj[k] == null) continue;
      const key = k.startsWith('--') ? k : `--${String(k).replace(/^-+/, '')}`;
      variables[key] = String(obj[k]);
    }
  };
  mergeCssVars(cfg.cssVars);
  mergeCssVars(cfg.css_vars);
  if (cfg.bg != null) variables['--bg-canvas'] = cfg.bg;
  if (cfg.surface != null) variables['--bg-elevated'] = cfg.surface;
  if (cfg.nav != null) variables['--bg-nav'] = cfg.nav;
  else if (cfg.bg != null) variables['--bg-nav'] = cfg.bg;
  if (cfg.bg != null) {
    variables['--bg-overlay'] = cfg.bg;
    variables['--bg-primary'] = cfg.bg;
  }
  if (cfg.surface != null) variables['--bg-secondary'] = cfg.surface;
  if (cfg.text != null) {
    variables['--text-primary'] = cfg.text;
    variables['--text-nav'] = cfg.text;
  }
  if (cfg.textSecondary != null) {
    variables['--text-secondary'] = cfg.textSecondary;
    variables['--text-nav-muted'] = cfg.textSecondary;
    variables['--text-muted'] = cfg.textSecondary;
    variables['--color-text'] = cfg.text;
  }
  if (cfg.border != null) {
    variables['--border'] = cfg.border;
    variables['--border-nav'] = cfg.border;
    variables['--color-border'] = cfg.border;
  }
  if (cfg.primary != null) {
    variables['--accent'] = cfg.primary;
    variables['--accent-primary'] = cfg.primary;
    variables['--color-primary'] = cfg.primary;
  }
  if (cfg.primaryHover != null) {
    variables['--accent-hover'] = cfg.primaryHover;
    variables['--accent-secondary'] = cfg.primaryHover;
  }
  if (cfg.radius != null) variables['--border-radius'] = cfg.radius;
  if (cfg.fontFamily != null) variables['--font-family'] = cfg.fontFamily;
  if (cfg.statusBar != null) variables['--status-bar-bg'] = String(cfg.statusBar);
  if (cfg.statusBarText != null) variables['--status-bar-text'] = String(cfg.statusBarText);
  if (cfg.repoSwitcher != null) variables['--repo-switcher-bg'] = String(cfg.repoSwitcher);
  variables['--transition'] = typeof cfg.transition === 'string' ? cfg.transition : 'all 0.2s ease';
  return variables;
}

/** Plaintext wrangler `TENANT_ID` — never substitute a literal tenant string. */
function tenantIdFromEnv(env) {
  if (!env || env.TENANT_ID == null) return null;
  const s = String(env.TENANT_ID).trim();
  return s || null;
}

/** Prefer session/routing tenant, then env `TENANT_ID` (may be null). */
function resolveTelemetryTenantId(env, explicitTenantId) {
  if (explicitTenantId != null && String(explicitTenantId).trim() !== '') {
    return String(explicitTenantId).trim();
  }
  return tenantIdFromEnv(env) || null;
}

/** Default D1 workspace_id for prod telemetry rows (resolve per-user later). */
const IAM_DEFAULT_WORKSPACE_ID = 'ws_inneranimalmedia';

/** Parse `cms_themes.config` JSON for theme API responses. */
function parseCmsThemeConfig(raw) {
  if (raw == null) return {};
  try {
    return typeof raw === 'string' ? JSON.parse(raw) : (raw && typeof raw === 'object' ? raw : {});
  } catch (_) {
    return {};
  }
}

/**
 * Map cms_themes.config-derived CSS variables to agent-dashboard `index.css` tokens
 * (`--bg-app`, `--text-main`, terminal chrome, accents).
 */
function mergeAgentDashboardIdeTokens(variables, cfg) {
  const data = { ...variables };
  const get = (k) =>
    data[k] != null && String(data[k]).trim() !== '' ? String(data[k]) : null;
  if (!data['--bg-app']) {
    data['--bg-app'] = get('--bg-canvas') || get('--bg-surface') || (cfg.bg != null ? String(cfg.bg) : null);
  }
  if (!data['--bg-panel']) {
    data['--bg-panel'] = get('--bg-elevated') || get('--bg-panel') || (cfg.surface != null ? String(cfg.surface) : null);
  }
  if (!data['--text-main']) {
    data['--text-main'] =
      get('--color-text') || get('--text-primary') || (cfg.text != null ? String(cfg.text) : null);
  }
  if (!data['--text-muted']) {
    data['--text-muted'] =
      get('--text-muted') || get('--text-secondary') || (cfg.textSecondary != null ? String(cfg.textSecondary) : null);
  }
  if (!data['--text-heading'] && data['--text-main']) data['--text-heading'] = data['--text-main'];
  if (!data['--border-subtle'] && get('--border')) data['--border-subtle'] = get('--border');
  if (!data['--border-focus'] && get('--color-primary')) data['--border-focus'] = get('--color-primary');
  if (!data['--scene-bg'] && data['--bg-app']) data['--scene-bg'] = data['--bg-app'];
  if (!data['--terminal-surface'] && data['--bg-panel']) data['--terminal-surface'] = data['--bg-panel'];
  if (!data['--terminal-chrome'] && data['--bg-panel']) data['--terminal-chrome'] = data['--bg-panel'];
  if (!data['--terminal-tab-muted'] && data['--text-muted']) data['--terminal-tab-muted'] = data['--text-muted'];
  const primary = get('--color-primary');
  if (!data['--solar-cyan'] && primary) data['--solar-cyan'] = primary;
  if (!data['--solar-blue'] && primary) data['--solar-blue'] = primary;
  return data;
}

/** Build `/api/themes/active` payload from a cms_themes row (joined or direct). */
function activeThemeJsonFromCmsRow(row) {
  if (!row?.slug) return null;
  const fam = (row.theme_family || '').toLowerCase();
  const isDark = fam === 'dark' || (fam !== 'light' && fam !== 'high_contrast_light' && !fam);
  const cfg = parseCmsThemeConfig(row.config);
  const base = variablesFromCmsThemeConfig(cfg);
  const data = mergeAgentDashboardIdeTokens(base, cfg);
  const resolvedDark =
    typeof cfg.is_dark === 'boolean'
      ? cfg.is_dark
      : typeof cfg.is_dark === 'number'
        ? cfg.is_dark !== 0
        : isDark;
  const out = {
    name: row.name || row.slug,
    slug: row.slug,
    is_dark: resolvedDark,
    data,
  };
  if (cfg.terminal && typeof cfg.terminal === 'object') out.terminal = cfg.terminal;
  if (cfg.monaco != null && String(cfg.monaco).trim() !== '') out.monaco_theme = String(cfg.monaco).trim();
  return out;
}

/**
 * Active theme from settings + cms_themes: prefer row with matching workspace_id, else tenant default (workspace_id NULL).
 */
async function loadActiveCmsThemeFromSettings(env, tid, workspaceParam) {
  const ws = workspaceParam != null && String(workspaceParam).trim() !== '' ? String(workspaceParam).trim() : null;
  if (!tid || !env.DB) return null;
  if (ws) {
    const row = await env.DB.prepare(
      `SELECT ct.name, ct.slug, ct.theme_family, ct.config
       FROM settings s
       JOIN cms_themes ct ON ct.slug = s.setting_value
       WHERE s.setting_key = 'appearance.theme' AND s.tenant_id = ?
       AND ct.workspace_id = ?
       LIMIT 1`
    ).bind(tid, ws).first();
    if (row?.slug) return row;
  }
  return await env.DB.prepare(
    `SELECT ct.name, ct.slug, ct.theme_family, ct.config
     FROM settings s
     JOIN cms_themes ct ON ct.slug = s.setting_value
     WHERE s.setting_key = 'appearance.theme' AND s.tenant_id = ?
     AND (ct.workspace_id IS NULL OR TRIM(ct.workspace_id) = '')
     LIMIT 1`
  ).bind(tid).first();
}

/** Slug-based cms_themes lookup: workspace-specific row first, else global (workspace_id NULL). */
async function loadCmsThemeBySlug(env, slug, workspaceParam) {
  const ws = workspaceParam != null && String(workspaceParam).trim() !== '' ? String(workspaceParam).trim() : null;
  if (!env.DB || !slug) return null;
  if (ws) {
    const row = await env.DB.prepare(
      `SELECT name, slug, theme_family, config FROM cms_themes
       WHERE (slug = ? OR name = ?) AND workspace_id = ?
       LIMIT 1`
    ).bind(slug, slug, ws).first();
    if (row?.slug) return row;
  }
  return await env.DB.prepare(
    `SELECT name, slug, theme_family, config FROM cms_themes
     WHERE (slug = ? OR name = ?) AND (workspace_id IS NULL OR TRIM(workspace_id) = '')
     LIMIT 1`
  ).bind(slug, slug).first();
}

/** R2 S3 API host from `CLOUDFLARE_ACCOUNT_ID` (no hardcoded account id). */
function getR2S3Host(env) {
  if (!env || env.CLOUDFLARE_ACCOUNT_ID == null) return null;
  const id = String(env.CLOUDFLARE_ACCOUNT_ID).trim();
  return id ? `${id}.r2.cloudflarestorage.com` : null;
}

/** Cached superadmin identifiers: auth_users.id, users.id (OAuth), emails (TTL 5m). */
let SUPERADMIN_IDS_CACHE = null;
let SUPERADMIN_IDS_CACHE_TIME = 0;

function invalidateSuperadminIdentifiersCache() {
  SUPERADMIN_IDS_CACHE = null;
  SUPERADMIN_IDS_CACHE_TIME = 0;
}

async function getSuperadminAuthIds(env) {
  if (!env?.DB) {
    return { authIds: new Set(), userIds: new Set(), emails: new Set() };
  }
  const now = Date.now();
  if (SUPERADMIN_IDS_CACHE && now - SUPERADMIN_IDS_CACHE_TIME < 300000) {
    return SUPERADMIN_IDS_CACHE;
  }
  try {
    const result = await env.DB.prepare(
      `SELECT au.id AS auth_id, au.email, u.id AS user_id
       FROM auth_users au
       LEFT JOIN users u ON u.auth_id = au.id
       WHERE COALESCE(au.is_superadmin, 0) = 1`
    ).all();
    const cache = { authIds: new Set(), userIds: new Set(), emails: new Set() };
    for (const row of result.results || []) {
      if (row.auth_id) cache.authIds.add(row.auth_id);
      if (row.user_id) cache.userIds.add(row.user_id);
      if (row.email) cache.emails.add(String(row.email).toLowerCase().trim());
    }
    SUPERADMIN_IDS_CACHE = cache;
    SUPERADMIN_IDS_CACHE_TIME = now;
    return cache;
  } catch (e) {
    console.warn('[getSuperadminAuthIds]', e?.message ?? e);
    return { authIds: new Set(), userIds: new Set(), emails: new Set() };
  }
}

async function isSuperadminEmail(env, email) {
  const em = String(email || '').trim().toLowerCase();
  if (!em || !env?.DB) return false;
  try {
    const row = await env.DB.prepare(
      `SELECT 1 FROM auth_users WHERE LOWER(email) = ? AND COALESCE(is_superadmin, 0) = 1 LIMIT 1`
    ).bind(em).first();
    return !!row;
  } catch (e) {
    console.warn('[isSuperadminEmail]', e?.message ?? e);
    return false;
  }
}

/** True if auth_sessions / KV user_id is a superadmin (email, auth_users.id, or users.id from OAuth). */
async function isSuperadminSessionUserKey(env, userKey) {
  const k = String(userKey || '').trim();
  if (!k || !env?.DB) return false;
  try {
    const cache = await getSuperadminAuthIds(env);
    if (k.includes('@')) return cache.emails.has(k.toLowerCase());
    return cache.authIds.has(k) || cache.userIds.has(k);
  } catch (e) {
    console.warn('[isSuperadminSessionUserKey]', e?.message ?? e);
    return false;
  }
}

/**
 * Superadmin dashboard session: id is always the cookie session UUID (same shape as non-superadmin sessions).
 * Profile fields come from auth_users + users.user_key = superadmin_group_id.
 */
async function buildSuperadminContext(env, sessionId, sessionUserKey) {
  const key = String(sessionUserKey || '').trim();
  if (!key) throw new Error('empty session user key');
  let authRow = null;
  if (key.includes('@')) {
    authRow = await env.DB.prepare(
      `SELECT id, email, name, superadmin_group_id FROM auth_users WHERE LOWER(email) = LOWER(?) LIMIT 1`
    ).bind(key).first();
  } else {
    authRow = await env.DB.prepare(
      `SELECT id, email, name, superadmin_group_id FROM auth_users WHERE id = ? LIMIT 1`
    ).bind(key).first();
    if (!authRow) {
      try {
        authRow = await env.DB.prepare(
          `SELECT au.id, au.email, au.name, au.superadmin_group_id
           FROM users u
           INNER JOIN auth_users au ON u.auth_id = au.id
           WHERE u.id = ? LIMIT 1`
        ).bind(key).first();
      } catch (e) {
        console.warn('[buildSuperadminContext] users join', e?.message ?? e);
      }
    }
  }
  if (!authRow?.superadmin_group_id) {
    throw new Error('Superadmin session user missing superadmin_group_id');
  }
  let userProfile = null;
  try {
    userProfile = await env.DB.prepare(
      `SELECT display_name, role, default_workspace_id FROM users WHERE user_key = ? LIMIT 1`
    ).bind(authRow.superadmin_group_id).first();
  } catch (e) {
    console.warn('[buildSuperadminContext] users profile', e?.message ?? e);
  }
  const loginEmail = String(authRow.email || key).toLowerCase();
  const displayName =
    (userProfile && userProfile.display_name) || authRow.name || 'User';
  const role = (userProfile && userProfile.role) || 'superadmin';
  const workspaceId =
    (userProfile && userProfile.default_workspace_id) || 'ws_inneranimalmedia';
  return {
    id: sessionId,
    email: loginEmail,
    user_id: authRow.superadmin_group_id,
    _session_user_id: loginEmail,
    name: displayName,
    role,
    permissions: ['*'],
    tenant_id: null,
    workspace_id: workspaceId,
    is_active: 1,
    is_superadmin: 1,
  };
}

async function resolveAgentsamUserKey(env, authUser) {
  if (!authUser?.id) return null;
  // removed hardcoded sam_primeaux shortcut
  if (!env?.DB) return authUser.id;
  try {
    const row = await env.DB.prepare(
      `SELECT superadmin_group_id FROM auth_users WHERE id = ? AND COALESCE(is_superadmin, 0) = 1 LIMIT 1`
    ).bind(authUser.id).first();
    if (row?.superadmin_group_id) return row.superadmin_group_id;
  } catch (_) { }
  const em = String(authUser.email || '').trim();
  if (em) {
    try {
      const byEmail = await env.DB.prepare(
        `SELECT superadmin_group_id FROM auth_users WHERE LOWER(email) = LOWER(?) AND COALESCE(is_superadmin, 0) = 1 LIMIT 1`
      ).bind(em).first();
      if (byEmail?.superadmin_group_id) return byEmail.superadmin_group_id;
    } catch (_) { }
  }
  return authUser.id;
}

/** Zero Trust / mac tunnel — only superadmin-group users may restart connections (POST /api/tunnel/restart). */
async function isSamOnlyUser(env, authUser) {
  if (!authUser) return false;
  // sam_primeaux shortcut removed — use superadmin DB check
  if (!env?.DB) return false;
  const email = String(authUser.email || '').toLowerCase();
  if (email && (await isSuperadminEmail(env, email))) return true;
  const uid = String(authUser.id || '').trim();
  if (uid) {
    const ids = await getSuperadminAuthIds(env);
    if (ids.authIds.has(uid) || ids.userIds.has(uid)) return true;
  }
  return false;
}

function sessionIsPlatformSuperadmin(session) {
  return !!(session && (session.is_superadmin === 1 || session.is_superadmin === true));
}

