/** Use Workers AI to generate a short conversation name and UPDATE agent_conversations. Call from waitUntil so chat response is not blocked. */
async function generateConversationName(env, conversationId, firstUserMessage) {
  if (!env.AI || !conversationId || !firstUserMessage || typeof firstUserMessage !== 'string') return;
  const text = firstUserMessage.trim().slice(0, 500);
  if (!text) return;
  try {
    const out = await env.AI.run('@cf/meta/llama-3.1-8b-instruct', {
      messages: [{ role: 'user', content: `Summarize this message as a short chat title, max 6 words, no quotes: ${text}` }],
      max_tokens: 20,
    });
    const name = (out?.result?.response ?? out?.response ?? (typeof out === 'string' ? out : '')).trim().slice(0, 80);
    if (name) {
      await env.DB.prepare('UPDATE agent_conversations SET name=? WHERE id=?').bind(name, conversationId).run();
    }
  } catch (e) {
    console.warn('[agent/chat] generateConversationName failed:', e?.message ?? e);
  }
}

/** Persist user + assistant turns to Supabase agent_memory (Hyperdrive pg + Workers AI embed). Never throws. */
async function persistAgentMemoryHyperdrive(env, { sessionId, userText, assistantText, modelKey, provider }) {
  if (!env.HYPERDRIVE?.connectionString) return;
  const sid = String(sessionId || '').trim();
  const u = String(userText || '').slice(0, 50000);
  const a = String(assistantText || '').slice(0, 50000);
  if (!sid || !a) return;
  const ts = new Date().toISOString();
  const metaBase = { model: modelKey || null, provider: provider || null, timestamp: ts };
  const metaUser = JSON.stringify(metaBase);
  const metaAsst = JSON.stringify(metaBase);
  const { Client } = await import('pg');
  const client = new Client({ connectionString: env.HYPERDRIVE.connectionString });
  await client.connect();
  try {
    let userVecLiteral = null;
    if (env.AI && u) {
      try {
        const _uResp = await env.AI.run('@cf/baai/bge-large-en-v1.5', { text: [u] });
        const _uRaw = _uResp?.data ?? _uResp;
        const _uVec = (Array.isArray(_uRaw) ? _uRaw : _uRaw?.data)?.[0];
        if (_uVec && Array.isArray(_uVec)) userVecLiteral = '[' + _uVec.join(',') + ']';
      } catch (e) { console.warn('[agent_memory] user embed failed', e?.message ?? e); }
    }
    if (userVecLiteral) {
      await client.query(
        `INSERT INTO agent_memory (session_id, agent_id, role, content, metadata, embedding) VALUES ($1, $2, 'user', $3, $4::jsonb, $5::vector)`,
        [sid, 'agent-sam', u, metaUser, userVecLiteral]
      );
    } else {
      await client.query(
        `INSERT INTO agent_memory (session_id, agent_id, role, content, metadata) VALUES ($1, $2, 'user', $3, $4::jsonb)`,
        [sid, 'agent-sam', u, metaUser]
      );
    }
    let vecLiteral = null;
    if (env.AI && a) {
      try {
        const modelResp = await env.AI.run('@cf/baai/bge-large-en-v1.5', { text: [a] });
        const raw = modelResp?.data ?? modelResp;
        const vector = (Array.isArray(raw) ? raw : raw?.data)?.[0];
        if (vector && Array.isArray(vector)) vecLiteral = '[' + vector.join(',') + ']';
      } catch (e) {
        console.warn('[agent_memory] embed failed', e?.message ?? e);
      }
    }
    if (vecLiteral) {
      await client.query(
        `INSERT INTO agent_memory (session_id, agent_id, role, content, metadata, embedding) VALUES ($1, $2, 'assistant', $3, $4::jsonb, $5::vector)`,
        [sid, 'agent-sam', a, metaAsst, vecLiteral]
      );
    } else {
      await client.query(
        `INSERT INTO agent_memory (session_id, agent_id, role, content, metadata) VALUES ($1, $2, 'assistant', $3, $4::jsonb)`,
        [sid, 'agent-sam', a, metaAsst]
      );
    }
  } catch (e) {
    console.warn('[agent_memory] persist failed', e?.message ?? e);
  } finally {
    await client.end().catch(() => { });
  }
}

/**
 * Phase 0: Preflight Classification (Gemini Flash Lite)
 * Rapid, low-token intent and tier detection.
 */
async function preflightClassify(message, env) {
  const SYSTEM = `Classify the user message. Respond with JSON only, no markdown:
{"tier":"fast|moderate|complex","intent":"mixed","needs_tools":true|false}
fast=greeting/status/factual, moderate=lookup/explain/single-tool, complex=multi-step/build/agent`;

  function parseClassify(text) {
    const s = text.indexOf('{'), e = text.lastIndexOf('}');
    if (s === -1 || e === -1) throw new Error('no JSON braces');
    const p = JSON.parse(text.slice(s, e + 1));
    return { tier: p.tier || 'moderate', intent: p.intent || 'mixed', needsTools: p.needs_tools ?? true };
  }

  // Priority 1: Gemini Flash — $0.000004/call
  const geminiKey = env.GOOGLE_AI_API_KEY || env.GEMINI_API_KEY;
  if (geminiKey) {
    try {
      const res = await fetch(
        `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-lite:generateContent?key=${geminiKey}`,
        {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            systemInstruction: { parts: [{ text: SYSTEM }] },
            contents: [{ role: 'user', parts: [{ text: message.slice(0, 500) }] }],
            generationConfig: { maxOutputTokens: 100, temperature: 0 },
          })
        }
      );
      if (res.ok) {
        const data = await res.json();
        const text = data?.candidates?.[0]?.content?.parts?.[0]?.text || '';
        return parseClassify(text);
      }
    } catch (_) {}
  }

  // Priority 2: Workers AI — free tier
  if (env.AI) {
    try {
      const res = await env.AI.run('@cf/meta/llama-3.1-8b-instruct', {
        messages: [{ role: 'system', content: SYSTEM }, { role: 'user', content: message.slice(0, 500) }],
        max_tokens: 100,
      });
      return parseClassify(res?.response || '');
    } catch (_) {}
  }

  // Priority 3: OpenAI gpt-5.4-nano via Responses API
  if (env.OPENAI_API_KEY) {
    try {
      const res = await fetch('https://api.openai.com/v1/responses', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${env.OPENAI_API_KEY}` },
        body: JSON.stringify({
          model: 'gpt-5.4-nano',
          input: [{ role: 'system', content: SYSTEM }, { role: 'user', content: message.slice(0, 500) }],
          reasoning: { effort: 'none' },
          text: { verbosity: 'low' },
          max_output_tokens: 100,
        })
      });
      if (res.ok) {
        const data = await res.json();
        return parseClassify(data.output_text || '');
      }
    } catch (_) {}
  }

  console.warn('[preflightClassify] all providers failed, using default');
  return { tier: 'moderate', intent: 'mixed', needsTools: true };
}

/**
 * Phase 0: Tiered Context Assembly
 * Loads core tools + intent-matched tools and caches the result.
 */
async function buildTieredContext(env, tier, intent, agentId, mode) {
  if (tier === 'fast') return { tools: [] };
  
  const cacheKey = `compiled_ctx:${tier}:${intent}:${agentId}:${mode}`;
  if (env.SESSION_CACHE) {
    try {
      const cached = await env.SESSION_CACHE.get(cacheKey);
      if (cached) return JSON.parse(cached);
    } catch (_) {}
  }

  // Tier 0: 10 Core Always-On Tools
  const CORE_TOOLS = ['d1_query', 'terminal_execute', 'r2_read', 'r2_list', 'r2_search', 'knowledge_search', 'workspace_search', 'human_context_list', 'generate_execution_plan', 'sequential_thinking'];
  
  const toolResults = await env.DB.prepare(
    `SELECT tool_name, description, input_schema, tool_category 
     FROM mcp_registered_tools 
     WHERE enabled = 1 AND is_degraded = 0 
     AND (
       tool_name IN (${CORE_TOOLS.map(() => '?').join(',')})
       OR (intent_tags LIKE ('%' || ? || '%') AND ? != 'mixed')
     )
     ORDER BY sort_priority ASC, tool_name ASC`
  ).bind(...CORE_TOOLS, intent, intent).all();

  const toolDeclarations = (toolResults.results || []).map(t => {
    let schema = {};
    try { schema = typeof t.input_schema === 'string' ? JSON.parse(t.input_schema) : (t.input_schema || {}); } catch (_) { }
    return {
      name: t.tool_name,
      description: (t.description || t.tool_name).slice(0, 500),
      parameters: schema.type === 'object' ? schema : { type: 'object', properties: {}, required: [] }
    };
  });

  const result = { tools: toolDeclarations };
  if (env.SESSION_CACHE) {
    await env.SESSION_CACHE.put(cacheKey, JSON.stringify(result), { expirationTtl: 300 }).catch(() => {});
  }
  return result;
}

/** Load active model pricing for telemetry cost math (keyed by model_key). */
async function loadAiModelRatesMap(env) {
  if (!env?.DB) return {};
  try {
    const { results } = await env.DB.prepare(
      `SELECT model_key, input_rate_per_mtok, output_rate_per_mtok,
              cache_read_rate_per_mtok, cache_write_rate_per_mtok,
              pricing_unit, cost_per_unit
       FROM ai_models WHERE COALESCE(is_active, 0) = 1`
    ).all();
    const map = {};
    for (const r of results || []) {
      const k = r.model_key != null ? String(r.model_key) : '';
      if (k) map[k] = r;
    }
    return map;
  } catch (e) {
    console.warn('[loadAiModelRatesMap]', e?.message ?? e);
    return {};
  }
}

/**
 * Unified telemetry + spend write. Maps cache read/write to cache_read_input_tokens / cache_creation_input_tokens.
 * Stores routing_decision_id, agent_run_id, previews, etc. in metadata_json (no migration required).
 * Never throws.
 */
async function writeTelemetry(env, data, modelRates) {
  const {
    sessionId, tenantId, provider, model,
    inputTokens, outputTokens, cacheReadTokens, cacheWriteTokens,
    latencyMs, toolCallCount, toolNamesUsed,
    promptPreview, responsePreview,
    finishReason, success, errorMessage,
    routingDecisionId, agentRunId,
    computedCostUsdOverride,
  } = data;

  const modelKey = model != null ? String(model) : '';
  const rates = modelKey && modelRates ? modelRates[modelKey] : null;
  let estimatedCost = null;
  if (computedCostUsdOverride != null && Number.isFinite(Number(computedCostUsdOverride))) {
    estimatedCost = Number(computedCostUsdOverride);
  } else if (rates) {
    estimatedCost = computeUsdFromModelRatesRow(modelKey, rates, inputTokens, outputTokens, cacheReadTokens, cacheWriteTokens);
  }

  const telemetryId = `tel_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
  const metaObj = {
    routing_decision_id: routingDecisionId || null,
    agent_run_id: agentRunId || null,
    tool_call_count: toolCallCount || 0,
    tool_names_used: toolNamesUsed || [],
    prompt_preview: (promptPreview || '').slice(0, 500),
    response_preview: (responsePreview || '').slice(0, 500),
    finish_reason: finishReason || null,
    success: !!success,
    error_message: errorMessage || null,
    request_latency_ms: latencyMs ?? null,
  };
  const metaJson = JSON.stringify(metaObj);
  const tin = Math.floor(Number(inputTokens) || 0);
  const tout = Math.floor(Number(outputTokens) || 0);
  const crd = Math.floor(Number(cacheReadTokens) || 0);
  const cwd = Math.floor(Number(cacheWriteTokens) || 0);
  const totIn = tin + crd + cwd;
  const tid = resolveTelemetryTenantId(env, tenantId);
  if (!tid) {
    console.warn('[writeTelemetry] missing tenant_id; inserting agent_telemetry with NULL tenant (spend_ledger skipped)');
  }
  const sid = sessionId != null ? String(sessionId) : null;

  // agent_telemetry: 20 columns = 17 ? + unixepoch(timestamp) + unixepoch(created_at) + unixepoch(updated_at); .bind supplies 17 values.
  try {
    await env.DB.prepare(
      `INSERT INTO agent_telemetry (
        id, tenant_id, session_id, metric_type, metric_name, metric_value, timestamp, metadata_json,
        model_used, provider, input_tokens, output_tokens,
        cache_read_input_tokens, cache_creation_input_tokens,
        computed_cost_usd, total_input_tokens,
        event_type, severity, created_at, updated_at
      ) VALUES (?,?,?,?,?,?,unixepoch(),?,?,?,?,?,?,?,?,?,?,?,unixepoch(),unixepoch())`
    ).bind(
      telemetryId, tid ?? null, sid,
      'agent_chat', 'llm_turn', 1, metaJson,
      modelKey, String(provider || 'unknown'),
      tin, tout, crd, cwd,
      estimatedCost != null ? estimatedCost : 0,
      totIn,
      'chat', success ? 'info' : 'warning'
    ).run();
  } catch (e) {
    console.error('telemetry agent_telemetry:', e);
  }

  if (tid && estimatedCost !== null && Number(estimatedCost) > 0) {
    try {
      const sp = spendLedgerProvider(String(provider || 'unknown'));
      const spFixed = sp === 'workers_ai' ? 'cloudflare_workers_ai' : sp;
      const lid = 'sl_' + crypto.randomUUID().replace(/-/g, '').slice(0, 16).toLowerCase();
      await env.DB.prepare(
        `INSERT INTO spend_ledger (id, tenant_id, workspace_id, brand_id, provider, source, occurred_at, amount_usd, model_key, tokens_in, tokens_out, session_tag, project_id, ref_table, ref_id)
         VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)`
      ).bind(
        lid, tid, 'default', 'inneranimalmedia', spFixed, 'api_direct',
        Math.floor(Date.now() / 1000), estimatedCost, modelKey, tin, tout,
        sid || 'unknown', 'proj_inneranimalmedia_main_prod_013',
        'agent_telemetry', telemetryId
      ).run();
    } catch (e) {
      console.error('telemetry spend_ledger:', e);
    }
  }

  return telemetryId;
}

/** Parse Workers AI stream JSON line or result object for { prompt_tokens, completion_tokens }. */
function extractWorkersAiUsageFromJson(j) {
  if (!j || typeof j !== 'object') return null;
  const u = j.usage && typeof j.usage === 'object' ? j.usage : j;
  const pt = u.prompt_tokens ?? u.input_tokens;
  const ct = u.completion_tokens ?? u.output_tokens;
  if (pt == null && ct == null) return null;
  return { prompt_tokens: Math.floor(Number(pt) || 0), completion_tokens: Math.floor(Number(ct) || 0) };
}

function computeUsdFromModelRatesRow(modelKey, ratesRow, inputTokens, outputTokens, cacheReadTokens, cacheWriteTokens) {
  if (!ratesRow) return 0;
  const unit = (ratesRow.pricing_unit || 'usd_per_mtok').toLowerCase();

  if (unit === 'free' || unit === 'subscription') return 0;

  if (unit === 'neurons_per_mtok') {
    // Workers AI neurons: $0.011 / 1,000 neurons (0.000011 per neuron)
    // input_rate_per_mtok stores neurons per 1M tokens
    const inRate = Number(ratesRow.input_rate_per_mtok) || 0;
    const outRate = Number(ratesRow.output_rate_per_mtok) || 0;
    const inCost = (Number(inputTokens) || 0) * inRate * 0.000011 / 1_000_000;
    const outCost = (Number(outputTokens) || 0) * outRate * 0.000011 / 1_000_000;
    return inCost + outCost;
  }

  if (unit === 'per_image' || unit === 'per_second' || unit === 'per_character') {
    // cost_per_unit is flat fee per image/sec/char. outputTokens represents unit count.
    return (Number(outputTokens) || 0) * (Number(ratesRow.cost_per_unit) || 0);
  }

  // Default: usd_per_mtok
  const inR = Number(ratesRow.input_rate_per_mtok) || 0;
  const outR = Number(ratesRow.output_rate_per_mtok) || 0;
  const cr = Number(ratesRow.cache_read_rate_per_mtok) || 0;
  const cw = Number(ratesRow.cache_write_rate_per_mtok) || 0;
  return (
    (Number(inputTokens) || 0) * inR +
    (Number(outputTokens) || 0) * outR +
    (Number(cacheReadTokens) || 0) * cr +
    (Number(cacheWriteTokens) || 0) * cw
  ) / 1_000_000;
}

/** If tool name matches a skill row, log invocation (PRAGMA-aligned columns). */
async function maybeInsertSkillInvocationForTool(env, { toolName, tenantId, sessionId, inputTokens, outputTokens, latencyMs, success }) {
  if (!env?.DB || !toolName) return;
  const tn = String(toolName).trim();
  if (!tn) return;
  try {
    const row = await env.DB.prepare(
      `SELECT id FROM agentsam_skill WHERE is_active = 1 AND (
        LOWER(name) = LOWER(?) OR LOWER(COALESCE(slash_trigger,'')) = LOWER(?) OR LOWER(COALESCE(slash_trigger,'')) = LOWER(?)
      ) LIMIT 1`
    ).bind(tn, tn, '/' + tn.replace(/^\//, '')).first();
    if (!row?.id) return;
    const uid = 'sam_primeaux';
    await env.DB.prepare(
      `INSERT INTO agentsam_skill_invocation (
        skill_id, user_id, workspace_id, conversation_id, trigger_method, input_summary,
        success, duration_ms, tokens_in, tokens_out, invoked_at
      ) VALUES (?,?,?,?,?,?,?,?,?,?,datetime('now'))`
    ).bind(
      row.id,
      uid,
      'default',
      sessionId || null,
      'api',
      'agent_chat',
      success ? 1 : 0,
      Math.floor(Number(latencyMs) || 0),
      Math.floor(Number(inputTokens) || 0),
      Math.floor(Number(outputTokens) || 0)
    ).run();
  } catch (e) {
    console.warn('[agentsam_skill_invocation]', e?.message ?? e);
  }
}

/** Mark agentsam_agent_run row completed with same cost/tokens as agent_telemetry (id = run row PK). */
async function completeAgentsamAgentRun(env, runId, conversationId, inputTokens, outputTokens, costUsd) {
  if (!runId || !env?.DB) return;
  try {
    await env.DB.prepare(
      `UPDATE agentsam_agent_run SET cost_usd = ?, input_tokens = ?, output_tokens = ?, completed_at = datetime('now'), status = 'completed', conversation_id = COALESCE(conversation_id, ?) WHERE id = ?`
    ).bind(Number(costUsd) || 0, Math.floor(Number(inputTokens) || 0), Math.floor(Number(outputTokens) || 0), conversationId || null, runId).run();
  } catch (e) {
    console.warn('[agentsam_agent_run] completion', e?.message ?? e);
  }
}

async function failAgentsamAgentRun(env, runId, conversationId, errorMessage) {
  if (!runId || !env?.DB) return;
  try {
    await env.DB.prepare(
      `UPDATE agentsam_agent_run SET status = 'failed', error_message = ?, completed_at = datetime('now'), conversation_id = COALESCE(conversation_id, ?) WHERE id = ?`
    ).bind(String(errorMessage || '').slice(0, 8000), conversationId || null, runId).run();
  } catch (e) {
    console.warn('[agentsam_agent_run] fail', e?.message ?? e);
  }
}

/** After agentsam_get_agent: complete or fail agentsam_agent_run row linked by idempotency_key = Cursor agent id. */
async function maybeSyncAgentsamAgentRunFromCursorGet(env, apiBody, cursorAgentId) {
  if (!env?.DB || !cursorAgentId) return;
  const root = apiBody.result && typeof apiBody.result === 'object' ? apiBody.result : apiBody;
  const st = String(root.status ?? '').trim().toUpperCase();
  if (st !== 'FINISHED' && st !== 'FAILED') return;
  let row;
  try {
    row = await env.DB.prepare(
      `SELECT id FROM agentsam_agent_run WHERE idempotency_key = ? AND trigger = 'cursor_agent' ORDER BY created_at DESC LIMIT 1`
    )
      .bind(String(cursorAgentId))
      .first();
  } catch (e) {
    console.warn('[agentsam_agent_run] cursor_get lookup', e?.message ?? e);
    return;
  }
  if (!row?.id) return;
  const u = root.usage && typeof root.usage === 'object' ? root.usage : {};
  const inTok = Math.floor(
    Number(root.inputTokens ?? root.input_tokens ?? u.input_tokens ?? u.prompt_tokens ?? 0) || 0,
  );
  const outTok = Math.floor(
    Number(root.outputTokens ?? root.output_tokens ?? u.output_tokens ?? u.completion_tokens ?? 0) || 0,
  );
  const costUsd = Number(root.costUsd ?? root.cost_usd ?? root.estimatedCostUsd ?? root.estimated_cost_usd ?? 0) || 0;
  if (st === 'FINISHED') {
    await completeAgentsamAgentRun(env, row.id, null, inTok, outTok, costUsd);
  } else {
    const errMsg = String(root.error?.message ?? root.error ?? root.message ?? 'FAILED').slice(0, 8000);
    await failAgentsamAgentRun(env, row.id, null, errMsg);
  }
}

async function resolveAgentAiIdForChat(env, agentParam) {
  if (!env?.DB) return null;
  try {
    const ap = agentParam != null ? String(agentParam).trim() : '';
    if (ap) {
      const r = await env.DB.prepare(`SELECT id FROM agentsam_ai WHERE id = ? AND status = 'active' LIMIT 1`).bind(ap).first();
      if (r?.id) return r.id;
    }
    const r2 = await env.DB.prepare(
      `SELECT id FROM agentsam_ai WHERE status = 'active' ORDER BY CASE id WHEN 'ai_sam_v1' THEN 0 ELSE 1 END, sort_order LIMIT 1`
    ).first();
    return r2?.id || null;
  } catch (_) {
    return null;
  }
}

/** Base system instructions for /api/agent/chat — from D1 only (no hardcoded persona). */

async function loadAgentsamAiSystemPromptForChat(env, agentAiId) {
  if (!env?.DB || !agentAiId) return '';
  try {
    const row = await env.DB.prepare(
      `SELECT system_prompt FROM agentsam_ai WHERE id = ? AND status = 'active' LIMIT 1`
    )
      .bind(String(agentAiId))
      .first();
    if (!row || row.system_prompt == null) return '';
    return String(row.system_prompt).trim();
  } catch (_) {
    return '';
  }
}

/** Prepend subagent persona (user_id + sort_order) to system prompt when configured. */
async function loadSubagentPersonaBlock(env, oauthUserId) {
  if (!env?.DB || !oauthUserId) return '';
  try {
    const row = await env.DB.prepare(
      `SELECT personality_tone, instructions_markdown, display_name FROM agentsam_subagent_profile
       WHERE is_active = 1 AND user_id = ?
       ORDER BY sort_order ASC LIMIT 1`
    ).bind(String(oauthUserId)).first();
    if (!row) return '';
    const tone = String(row.personality_tone || '').trim();
    const instr = String(row.instructions_markdown || '').trim();
    const disp = String(row.display_name || '').trim();
    if (!instr && !tone && !disp) return '';
    let s = '';
    if (disp) s += `[Persona: ${disp}]\n`;
    if (tone) s += `Tone: ${tone}.\n`;
    if (instr) s += instr;
    return s.trim();
  } catch (_) {
    return '';
  }
}

/**
 * Load agentsam_subagent_profile.allowed_tool_globs for the signed-in user (id or slug match).
 * Returns undefined if no row, DB error, or column null — caller passes nothing on opts (no extra filtering).
 */
async function loadSubagentAllowedToolGlobs(env, oauthUserId, subagentKey) {
  if (!env?.DB || !oauthUserId) return undefined;
  const k = subagentKey != null ? String(subagentKey).trim() : '';
  if (!k) return undefined;
  try {
    const row = await env.DB.prepare(
      `SELECT allowed_tool_globs FROM agentsam_subagent_profile
       WHERE user_id = ? AND is_active = 1 AND (id = ? OR slug = ?) LIMIT 1`
    ).bind(String(oauthUserId), k, k).first();
    if (!row || row.allowed_tool_globs == null) return undefined;
    const raw = row.allowed_tool_globs;
    const s = typeof raw === 'string' ? raw.trim() : String(raw).trim();
    return s.length ? s : undefined;
  } catch (_) {
    return undefined;
  }
}

/** Start a per-request chat SSE row (linked to conversation for rollup queries). */
async function insertChatSseAgentRun(env, id, conversationId, modelId, sessionLike, agentAiId = null) {
  if (!id || !env?.DB) return;
  const userId = sessionLike?.user_id ?? null;
  if (!userId) return;
  const workspaceId = sessionLike?.workspace_id ?? null;
  const convId = conversationId != null && conversationId !== '' ? conversationId : id;
  await env.DB.prepare(
    `INSERT INTO agentsam_agent_run (id, user_id, workspace_id, conversation_id, status, trigger, model_id, started_at, created_at, agent_ai_id)
     VALUES (?, ?, ?, ?, 'running', 'chat', ?, datetime('now'), datetime('now'), ?)
     ON CONFLICT(id) DO NOTHING`
  )
    .bind(id, userId, workspaceId, convId, modelId || null, agentAiId || null)
    .run();
}

/** After telemetry row exists: link routing_decisions row (by id if provided, else latest for session) to telemetry. */
async function completeRoutingDecisionTelemetry(env, conversationId, telemetryId, inputTokens, outputTokens, costUsd, routingOpts) {
  if (!telemetryId || !env?.DB) return;
  const latencyMs = routingOpts && typeof routingOpts.chatStartMs === 'number'
    ? Date.now() - routingOpts.chatStartMs
    : null;
  try {
    if (routingOpts?.routingDecisionId) {
      await env.DB.prepare(
        `UPDATE routing_decisions SET
          telemetry_id = ?,
          latency_ms = COALESCE(?, latency_ms),
          input_tokens = ?,
          output_tokens = ?,
          cost_usd = ?,
          completed = 1,
          updated_at = unixepoch()
        WHERE id = ?`
      ).bind(
        telemetryId,
        latencyMs,
        Math.floor(Number(inputTokens) || 0),
        Math.floor(Number(outputTokens) || 0),
        Number(costUsd) || 0,
        routingOpts.routingDecisionId
      ).run();
    } else if (conversationId) {
      await env.DB.prepare(
        `UPDATE routing_decisions SET
          telemetry_id = ?,
          latency_ms = ?,
          input_tokens = ?,
          output_tokens = ?,
          cost_usd = ?,
          completed = 1,
          updated_at = unixepoch()
        WHERE id = (
          SELECT id FROM routing_decisions WHERE session_id = ? ORDER BY created_at DESC LIMIT 1
        )`
      ).bind(
        telemetryId,
        latencyMs ?? 0,
        Math.floor(Number(inputTokens) || 0),
        Math.floor(Number(outputTokens) || 0),
        Number(costUsd) || 0,
        conversationId
      ).run();
    }
  } catch (e) {
    console.warn('[routing_decisions] telemetry completion', e?.message ?? e);
  }
  // EMA write-back: update model_routing_rules with observed latency + success signal (α=0.15).
  // isSuccess: error paths emit done with 0 tokens; treat that as failure signal toward 0.0.
  const taskType = routingOpts?.taskType;
  if (!routingOpts || !taskType) return;
  const emaLatency = latencyMs != null ? latencyMs : 0;
  if (taskType && env.DB) {
    try {
      const isSuccess = Number(inputTokens) > 0;
      if (isSuccess) {
        await env.DB.prepare(
          `UPDATE model_routing_rules SET
            avg_latency_ms    = ROUND(COALESCE(avg_latency_ms, ?) * 0.85 + ? * 0.15, 1),
            success_rate      = ROUND(COALESCE(success_rate, 1.0) * 0.85 + 1.0 * 0.15, 4),
            last_evaluated_at = unixepoch()
          WHERE task_type = ? AND is_active = 1`
        ).bind(emaLatency, emaLatency, taskType).run();
      } else {
        // Failure: drive success_rate toward 0.0; latency is meaningless on failed calls
        await env.DB.prepare(
          `UPDATE model_routing_rules SET
            success_rate      = ROUND(COALESCE(success_rate, 1.0) * 0.85 + 0.0 * 0.15, 4),
            last_evaluated_at = unixepoch()
          WHERE task_type = ? AND is_active = 1`
        ).bind(taskType).run();
      }
    } catch (e) {
      console.warn('[model_routing_rules] perf write-back', e?.message ?? e);
    }
  }
}

/** Parallel D1 reads + INSERT into system_health_snapshots; returns the inserted row. */
async function runIntegritySnapshot(env, triggeredBy = 'cron') {
  if (!env?.DB) throw new Error('DB unavailable');
  const tb = ['cron', 'manual', 'deploy', 'api'].includes(String(triggeredBy)) ? String(triggeredBy) : 'api';
  const sqlQ1 = `
    SELECT
      COUNT(*) AS rd_total,
      COALESCE(SUM(CASE WHEN task_type = 'unclassified' THEN 1 ELSE 0 END), 0) AS rd_unclassified_task,
      COALESCE(SUM(CASE WHEN model_selected = 'unknown' THEN 1 ELSE 0 END), 0) AS rd_unknown_model,
      COALESCE(SUM(CASE WHEN rule_source = 'unknown' THEN 1 ELSE 0 END), 0) AS rd_unknown_rule_source,
      COALESCE(SUM(completed), 0) AS rd_completed,
      COALESCE(SUM(CASE WHEN completed = 1 AND latency_ms IS NULL THEN 1 ELSE 0 END), 0) AS rd_missing_latency,
      COALESCE(SUM(CASE WHEN completed = 1 AND cost_usd IS NULL THEN 1 ELSE 0 END), 0) AS rd_missing_cost,
      COALESCE(SUM(CASE WHEN completed = 1 AND input_tokens IS NULL THEN 1 ELSE 0 END), 0) AS rd_missing_tokens,
      ROUND(100.0 * COALESCE(SUM(CASE WHEN completed = 1 AND latency_ms IS NOT NULL AND cost_usd IS NOT NULL THEN 1 ELSE 0 END), 0)
        / NULLIF(COALESCE(SUM(completed), 0), 0), 1) AS rd_pct_complete_valid
    FROM routing_decisions`;
  const sqlQ2 = `
    SELECT
      COALESCE(SUM(CASE WHEN created_at >= (unixepoch() - 86400) THEN 1 ELSE 0 END), 0) AS tel_total_24h,
      COALESCE(SUM(CASE WHEN created_at >= (unixepoch() - 604800) THEN 1 ELSE 0 END), 0) AS tel_total_7d,
      COALESCE(SUM(CASE WHEN created_at >= (unixepoch() - 86400) THEN computed_cost_usd ELSE 0 END), 0) AS tel_cost_24h,
      COALESCE(SUM(CASE WHEN created_at >= (unixepoch() - 604800) THEN computed_cost_usd ELSE 0 END), 0) AS tel_cost_7d
    FROM agent_telemetry`;
  const sqlQ3 = `
    SELECT provider, COUNT(*) AS n, SUM(computed_cost_usd) AS cost
    FROM agent_telemetry WHERE created_at >= (unixepoch() - 604800)
    GROUP BY provider ORDER BY n DESC`;
  const sqlQ4 = `
    SELECT
      COUNT(*) AS tools_total,
      COALESCE(SUM(is_degraded), 0) AS tools_degraded,
      COALESCE(SUM(CASE WHEN modes_json IS NULL OR modes_json = '' THEN 1 ELSE 0 END), 0) AS tools_missing_modes
    FROM mcp_registered_tools WHERE enabled = 1`;
  const sqlQ4b = `
    SELECT tool_name,
      SUM(failure_count) AS failure_count,
      SUM(success_count) AS success_count,
      ROUND(100.0 * SUM(failure_count) / NULLIF(SUM(failure_count) + SUM(success_count), 0), 1) AS fail_pct
    FROM mcp_tool_call_stats
    GROUP BY tool_name
    HAVING SUM(failure_count) > 0
    ORDER BY fail_pct DESC
    LIMIT 5`;
  const sqlQ5 = `
    SELECT
      (SELECT COUNT(*) FROM agent_intent_patterns) AS intents_total,
      (SELECT COUNT(*) FROM agent_intent_patterns WHERE total_executions > 0) AS intents_wired,
      (SELECT COUNT(*) FROM model_routing_rules WHERE is_active = 1) AS routing_rules_active,
      (SELECT COUNT(*) FROM model_routing_rules WHERE is_active = 1 AND provider = 'google') AS routing_rules_with_google,
      (SELECT COUNT(*) FROM provider_prompt_fragments WHERE is_active = 1) AS provider_fragments_active`;
  const sqlQ5b = `
    SELECT intent_slug, total_executions FROM agent_intent_patterns
    WHERE total_executions > 0 ORDER BY total_executions DESC LIMIT 10`;
  const [r1, r2, r3all, r4, r4b, r5, r5b] = await Promise.all([
    env.DB.prepare(sqlQ1).first(),
    env.DB.prepare(sqlQ2).first(),
    env.DB.prepare(sqlQ3).all(),
    env.DB.prepare(sqlQ4).first(),
    env.DB.prepare(sqlQ4b).all(),
    env.DB.prepare(sqlQ5).first(),
    env.DB.prepare(sqlQ5b).all(),
  ]);
  const rd_total = Number(r1?.rd_total) || 0;
  const rd_unclassified_task = Number(r1?.rd_unclassified_task) || 0;
  const rd_unknown_model = Number(r1?.rd_unknown_model) || 0;
  const rd_unknown_rule_source = Number(r1?.rd_unknown_rule_source) || 0;
  const rd_completed = Number(r1?.rd_completed) || 0;
  const rd_missing_latency = Number(r1?.rd_missing_latency) || 0;
  const rd_missing_cost = Number(r1?.rd_missing_cost) || 0;
  const rd_missing_tokens = Number(r1?.rd_missing_tokens) || 0;
  let rd_pct_complete_valid = Number(r1?.rd_pct_complete_valid);
  if (rd_completed === 0) rd_pct_complete_valid = 100;
  else if (!Number.isFinite(rd_pct_complete_valid)) rd_pct_complete_valid = 0;
  const tel_total_24h = Number(r2?.tel_total_24h) || 0;
  const tel_total_7d = Number(r2?.tel_total_7d) || 0;
  const tel_cost_24h = Number(r2?.tel_cost_24h) || 0;
  const tel_cost_7d = Number(r2?.tel_cost_7d) || 0;
  const tel_providers_json = JSON.stringify((r3all?.results ?? []).map((row) => ({
    provider: row.provider,
    n: Number(row.n) || 0,
    cost: Number(row.cost) || 0,
  })));
  const tools_total = Number(r4?.tools_total) || 0;
  const tools_degraded = Number(r4?.tools_degraded) || 0;
  const tools_missing_modes = Number(r4?.tools_missing_modes) || 0;
  const tool_top_failures_json = JSON.stringify(r4b?.results ?? []);
  const intents_total = Number(r5?.intents_total) || 0;
  const intents_wired = Number(r5?.intents_wired) || 0;
  const routing_rules_active = Number(r5?.routing_rules_active) || 0;
  const routing_rules_with_google = Number(r5?.routing_rules_with_google) || 0;
  const provider_fragments_active = Number(r5?.provider_fragments_active) || 0;
  const intents_top_json = JSON.stringify(r5b?.results ?? []);
  const noteParts = [];
  if (rd_missing_cost > 0) noteParts.push('completed routing rows missing cost_usd');
  if (rd_missing_latency > 0) noteParts.push('completed routing rows missing latency_ms');
  if (rd_missing_tokens > 0) noteParts.push('completed routing rows missing input_tokens');
  if (rd_unknown_model > 5) noteParts.push('rd_unknown_model above threshold');
  if (rd_unclassified_task > 10) noteParts.push('rd_unclassified_task above threshold');
  if (tools_degraded > 0) noteParts.push('degraded tools enabled');
  if (rd_pct_complete_valid < 95) noteParts.push('rd_pct_complete_valid below 95');
  if (tools_missing_modes > 0) noteParts.push('enabled tools missing modes_json');
  const isRed = rd_missing_cost > 0 || rd_missing_latency > 0 || rd_unknown_model > 5;
  const isYellow = rd_unclassified_task > 10 || tools_degraded > 0 || rd_pct_complete_valid < 95;
  const health_status = isRed ? 'red' : isYellow ? 'yellow' : 'green';
  const health_notes = noteParts.join(', ');
  const snapId = 'snap_' + crypto.randomUUID().replace(/-/g, '').slice(0, 24).toLowerCase();
  const snapshot_at = Math.floor(Date.now() / 1000);
  await env.DB.prepare(
    `INSERT INTO system_health_snapshots (
      id, triggered_by, snapshot_at,
      rd_total, rd_unclassified_task, rd_unknown_model, rd_unknown_rule_source, rd_completed,
      rd_missing_latency, rd_missing_cost, rd_missing_tokens, rd_pct_complete_valid,
      tel_total_24h, tel_total_7d, tel_cost_24h, tel_cost_7d, tel_providers_json,
      tools_total, tools_degraded, tools_missing_modes, tool_top_failures_json,
      intents_total, intents_wired, intents_top_json,
      routing_rules_active, routing_rules_with_google, provider_fragments_active,
      health_status, health_notes, created_at
    ) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)`
  ).bind(
    snapId, tb, snapshot_at,
    rd_total, rd_unclassified_task, rd_unknown_model, rd_unknown_rule_source, rd_completed,
    rd_missing_latency, rd_missing_cost, rd_missing_tokens, rd_pct_complete_valid,
    tel_total_24h, tel_total_7d, tel_cost_24h, tel_cost_7d, tel_providers_json,
    tools_total, tools_degraded, tools_missing_modes, tool_top_failures_json,
    intents_total, intents_wired, intents_top_json,
    routing_rules_active, routing_rules_with_google, provider_fragments_active,
    health_status, health_notes, snapshot_at
  ).run();
  return await env.DB.prepare('SELECT * FROM system_health_snapshots WHERE id = ?').bind(snapId).first();
}

/**
 * Persist AI-related asset events (images, R2 files, conversions, 3D) to ai_generation_logs.
 * Non-fatal on failure. opts.metadataJson may be object or JSON string.
 */
async function insertAiGenerationLog(env, opts) {
  if (!env?.DB || !opts || !opts.generationType) return;
  const {
    generationType,
    prompt = null,
    model = null,
    responseText = null,
    tokensUsed = null,
    costCents = null,
    qualityScore = null,
    status = 'completed',
    createdBy = 'worker',
    tenantId: rawTenantId = null,
    metadataJson = {},
    sourceKind = 'worker',
    workspaceId = null,
    relatedIdsJson = null,
    courseId = null,
    lessonId = null,
    quizId = null,
    explicitId = null,
    insertOrIgnore = false,
    inputTokens = null,
    outputTokens = null,
    computedCostUsd = null,
    llmProvider = null,
    logConversationId = null,
    codeLanguage = null,
    codeCharCount = null,
  } = opts;
  const tenantId =
    (rawTenantId != null && String(rawTenantId).trim()) ||
    (env.TENANT_ID && String(env.TENANT_ID).trim()) ||
    null;
  if (!tenantId) {
    console.warn('[insertAiGenerationLog] missing tenant_id; skip');
    return;
  }
  const id =
    explicitId != null && String(explicitId).trim()
      ? String(explicitId).trim().slice(0, 120)
      : 'aigl_' + crypto.randomUUID().replace(/-/g, '').slice(0, 24);
  const now = Math.floor(Date.now() / 1000);
  let meta = metadataJson;
  if (meta != null && typeof meta !== 'string') {
    try {
      meta = JSON.stringify(meta);
    } catch (_) {
      meta = '{}';
    }
  }
  if (meta == null || meta === '') meta = '{}';
  const rel =
    relatedIdsJson == null
      ? null
      : typeof relatedIdsJson === 'string'
        ? relatedIdsJson
        : (() => {
          try {
            return JSON.stringify(relatedIdsJson);
          } catch (_) {
            return null;
          }
        })();
  const inTok = inputTokens != null ? Math.floor(Number(inputTokens) || 0) : null;
  const outTok = outputTokens != null ? Math.floor(Number(outputTokens) || 0) : null;
  const costUsdCol = computedCostUsd != null ? Number(computedCostUsd) : null;
  const provCol = llmProvider != null && String(llmProvider).trim() ? String(llmProvider).trim() : null;
  const convCol = logConversationId != null && String(logConversationId).trim() ? String(logConversationId).trim() : null;
  const langCol = codeLanguage != null && String(codeLanguage).trim() ? String(codeLanguage).trim().slice(0, 64) : null;
  const codeChars = codeCharCount != null ? Math.floor(Number(codeCharCount) || 0) : null;

  const insertSql = insertOrIgnore
    ? `INSERT OR IGNORE INTO ai_generation_logs (
        id, course_id, lesson_id, quiz_id, generation_type, prompt, model, response_text,
        tokens_used, cost_cents, quality_score, status, created_by, created_at, completed_at, tenant_id,
        metadata_json, source_kind, workspace_id, related_ids_json,
        input_tokens, output_tokens, computed_cost_usd, provider, conversation_id, code_language, code_char_count
      ) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)`
    : `INSERT INTO ai_generation_logs (
        id, course_id, lesson_id, quiz_id, generation_type, prompt, model, response_text,
        tokens_used, cost_cents, quality_score, status, created_by, created_at, completed_at, tenant_id,
        metadata_json, source_kind, workspace_id, related_ids_json,
        input_tokens, output_tokens, computed_cost_usd, provider, conversation_id, code_language, code_char_count
      ) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)`;
  try {
    await env.DB.prepare(insertSql)
      .bind(
        id,
        courseId,
        lessonId,
        quizId,
        generationType,
        prompt,
        model,
        responseText,
        tokensUsed,
        costCents,
        qualityScore,
        status,
        createdBy,
        now,
        now,
        tenantId,
        meta,
        sourceKind,
        workspaceId,
        rel,
        inTok,
        outTok,
        costUsdCol,
        provCol,
        convCol,
        langCol,
        codeChars
      )
      .run();
  } catch (e) {
    console.warn('[insertAiGenerationLog]', e?.message ?? e);
  }
}

/**
 * Cursor Cloud Agent: when GET /v0/agents/:id returns FINISHED with a PR URL, persist once to
 * agentsam_executions (execution_type cursor_cloud_agent) and ai_generation_logs (idempotent).
 * Does not use deprecated cursor_* tables.
 */
async function maybePersistCursorCloudAgentFinished(env, apiBody, agentId) {
  if (!env?.DB || !apiBody || typeof apiBody !== 'object' || !agentId) return;
  const root = apiBody.result && typeof apiBody.result === 'object' ? apiBody.result : apiBody;
  const st = String(root.status ?? '').trim().toUpperCase();
  if (st !== 'FINISHED') return;
  const t = root.target && typeof root.target === 'object' ? root.target : {};
  const prUrl =
    typeof t.prUrl === 'string'
      ? t.prUrl.trim()
      : typeof t.pr_url === 'string'
        ? t.pr_url.trim()
        : '';
  if (!prUrl || !/^https?:\/\//i.test(prUrl)) return;
  const safeAgent = String(agentId).replace(/[^a-zA-Z0-9_-]/g, '').slice(0, 80);
  if (!safeAgent) return;
  const logId = `aigl_cca_${safeAgent}`;
  const execId = `agentsam_exec_cca_${safeAgent}`;
  const out = JSON.stringify({
    provider: 'cursor_cloud',
    status: root.status,
    pr_url: prUrl,
    branch: t.branchName ?? t.branch_name ?? null,
    repo: root.source?.repository ?? root.source?.repositoryUrl ?? null,
    name: root.name ?? null,
  });
  try {
    await env.DB.prepare(
      `INSERT OR IGNORE INTO agentsam_executions (id, task_id, subagent_id, execution_type, command, output, created_at)
       VALUES (?,?,?,?,?,?,unixepoch())`
    )
      .bind(execId, agentId, null, 'cursor_cloud_agent', 'agentsam_get_agent', out)
      .run();
  } catch (e) {
    console.warn('[maybePersistCursorCloudAgentFinished] agentsam_executions', e?.message ?? e);
  }
  await insertAiGenerationLog(env, {
    generationType: 'cursor_cloud_agent_pr',
    model: 'cursor_cloud',
    prompt: typeof root.name === 'string' ? root.name.slice(0, 2000) : null,
    responseText: prUrl,
    metadataJson: {
      cursor_agent_id: agentId,
      branch: t.branchName ?? t.branch_name ?? null,
      repository: root.source?.repository ?? root.source?.repositoryUrl ?? null,
      agentsam_execution_id: execId,
    },
    sourceKind: 'worker',
    relatedIdsJson: [agentId],
    explicitId: logId,
    insertOrIgnore: true,
  });
}

/** Gemini image models return base64 in part.inlineData; persist to DASHBOARD and log. */
async function persistGeminiPartInlineImage(env, part, modelKey, conversationId) {
  const inl = part?.inlineData || part?.inline_data;
  if (!inl || !inl.data || !env?.DASHBOARD) return;
  const mime = String(inl.mimeType || inl.mime_type || 'image/png');
  let bytes;
  try {
    bytes = Uint8Array.from(atob(String(inl.data).replace(/\s/g, '')), (c) => c.charCodeAt(0));
  } catch {
    return;
  }
  if (!bytes.byteLength) return;
  const ext = mime.includes('jpeg') ? 'jpg' : mime.includes('webp') ? 'webp' : mime.includes('gif') ? 'gif' : 'png';
  const safeMk = String(modelKey || 'gemini').replace(/[^a-zA-Z0-9._-]/g, '_').slice(0, 80);
  const key = `generated/gemini/${safeMk}/${crypto.randomUUID()}.${ext}`;
  try {
    await env.DASHBOARD.put(key, bytes, { httpMetadata: { contentType: mime } });
  } catch (e) {
    console.warn('[persistGeminiPartInlineImage] put', e?.message ?? e);
    return;
  }
  await insertAiGenerationLog(env, {
    generationType: 'gemini_inline_image',
    model: modelKey,
    responseText: key,
    metadataJson: {
      api: 'google_gemini',
      r2_key: key,
      conversation_id: conversationId || null,
      mime_type: mime,
      byte_length: bytes.byteLength,
    },
    relatedIdsJson: conversationId ? [conversationId] : null,
  });
}

/** First fenced code block in assistant text (OpenAI / Google / Anthropic / Workers AI chat). */
async function logAssistantCodeArtifactIfPresent(env, {
  fullText,
  modelKey,
  conversationId,
  provider,
  inputTokens = 0,
  outputTokens = 0,
  computedCostUsd = 0,
}) {
  if (!env?.DB || typeof fullText !== 'string') return;
  const re = /```([^\n`]*?)\s*\n([\s\S]*?)```/;
  const m = fullText.match(re);
  if (!m) return;
  const fenceFirst = (m[1] || '').trim();
  let codeLanguage = 'text';
  if (fenceFirst) {
    const langPart = fenceFirst.split(/\s+/)[0] || '';
    codeLanguage = (langPart.replace(/[^a-zA-Z0-9.#+\-_]/g, '') || 'text').slice(0, 64) || 'text';
  }
  const code = (m[2] || '').trim();
  if (code.length < 40) return;
  const codeCharCount = code.length;
  const rawFilename = fenceFirst.includes(' ')
    ? fenceFirst.slice(fenceFirst.indexOf(' ') + 1).trim().replace(/^(\/\/|#|\/\*)\s*/, '')
    : '';
  await insertAiGenerationLog(env, {
    generationType: 'assistant_code_block',
    model: modelKey,
    responseText: `code:${codeLanguage}:${codeCharCount}c`,
    metadataJson: {
      provider: provider || 'unknown',
      language: codeLanguage,
      filename_hint: rawFilename.slice(0, 120),
      code_length: codeCharCount,
      conversation_id: conversationId || null,
    },
    relatedIdsJson: conversationId ? [conversationId] : null,
    inputTokens: Math.floor(Number(inputTokens) || 0),
    outputTokens: Math.floor(Number(outputTokens) || 0),
    computedCostUsd: Number(computedCostUsd) || 0,
    llmProvider: provider || null,
    logConversationId: conversationId || null,
    codeLanguage,
    codeCharCount,
  });
}

/** INSERT OR IGNORE so FK on agent_messages.conversation_id -> agent_conversations(id) succeeds. Same id used for agent_sessions row (workspace/chat session key). */
async function ensureAgentChatPersistenceParents(env, conversationId, chatUserId, workspaceId = null, modelKey = null) {
  if (!env?.DB || conversationId == null || String(conversationId).trim() === '') return;
  const cid = String(conversationId).trim();
  const uid =
    chatUserId != null && String(chatUserId).trim() !== ''
      ? String(chatUserId).trim()
      : 'sam_primeaux';
  const now = Math.floor(Date.now() / 1000);
  const tenant = (env.TENANT_ID && String(env.TENANT_ID).trim()) || 'system';
  try {
    await env.DB.prepare(
      `INSERT OR IGNORE INTO agent_sessions (id, tenant_id, session_type, status, state_json, started_at, updated_at)
       VALUES (?, ?, 'chat', 'active', '{}', ?, ?)`
    )
      .bind(cid, tenant, now, now)
      .run();
  } catch (e) {
    console.warn('[ensureAgentChatPersistenceParents] agent_sessions', e?.message ?? e);
  }
  try {
    await env.DB.prepare(
      `INSERT OR IGNORE INTO agent_conversations (id, user_id, title, name, created_at, updated_at, is_archived, tenant_id, workspace_id, model)
       VALUES (?, ?, 'Chat', ?, ?, ?, 0, ?, ?, ?)`
    )
      .bind(cid, uid, cid.length > 120 ? cid.slice(0, 120) : cid, now, now, tenant, workspaceId || null, modelKey || null)
      .run();
  } catch (e) {
    console.warn('[ensureAgentChatPersistenceParents] agent_conversations', e?.message ?? e);
  }
}

/** Shared: insert agent_messages (assistant), agent_telemetry, spend_ledger and return payload for done event. ctx optional for non-blocking spend_ledger. */
async function streamDoneDbWrites(env, conversationId, modelRow, fullText, inputTokens, outputTokens, _costUsd, agent_id, ctx, lastUserTextForMemory, agentsamAgentRunId = null, routingOpts = null, cacheCreationInputTokens = 0, cacheReadInputTokens = 0, omitTelemetryWrite = false, chatPersistenceUserId = null) {
  if (env.DB && conversationId != null && String(conversationId).trim() !== '') {
    await ensureAgentChatPersistenceParents(env, conversationId, chatPersistenceUserId, routingOpts?.workspaceId || "ws_inneranimalmedia", modelRow?.model_key || null);
  }
  const safeText = (fullText != null && typeof fullText === 'string') ? fullText : '';
  const safeInput = inputTokens ?? 0;
  const safeOutput = outputTokens ?? 0;
  const safeCacheCreate = cacheCreationInputTokens ?? 0;
  const safeCacheRead = cacheReadInputTokens ?? 0;
  const safeProvider = (modelRow && modelRow.provider != null) ? String(modelRow.provider) : 'unknown';
  const safeModelKey = (modelRow && modelRow.model_key != null) ? String(modelRow.model_key) : 'unknown';
  let rowForTelemetry = modelRow;
  if (safeProvider === 'google' && env?.DB && shouldUseVertexForGoogleModel(env, safeModelKey)) {
    if (typeof modelRow?.input_rate_per_mtok !== 'number' || typeof modelRow?.output_rate_per_mtok !== 'number') {
      rowForTelemetry = await resolveGoogleModelRowForVertexAi(env, modelRow);
    }
  }
  let amountUsd = computeUsdFromModelRatesRow(safeModelKey, rowForTelemetry, safeInput, safeOutput, safeCacheRead, safeCacheCreate);
  if ((!amountUsd || amountUsd === 0) && (safeInput > 0 || safeOutput > 0)) {
    // Fallback if DB row missing rates
    const { rateIn, rateOut } = getSpendRates(safeProvider, safeModelKey);
    amountUsd = (safeInput * rateIn / 1_000_000) + (safeOutput * rateOut / 1_000_000);
  }
  const msgId = crypto.randomUUID();
  const role = 'assistant';
  const fullContent = safeText;
  const tokenCount = (safeInput + safeOutput) || 0;
  const msgR2Key = `agent-sessions/${conversationId}/messages/${msgId}.json`;
  if (env.R2) {
    await env.R2.put(msgR2Key, JSON.stringify({
      id: msgId,
      conversation_id: conversationId,
      role: role,
      content: fullContent,
      token_count: tokenCount || 0,
      thinking_content: null,
      created_at: Date.now(),
    }), {
      httpMetadata: { contentType: 'application/json' },
    }).catch(() => { });
  }
  try {
    await env.DB.prepare(
      "INSERT INTO agent_messages (id, conversation_id, role, content, provider, model, input_tokens, output_tokens, token_count, cost_usd, tenant_id, user_id, r2_key, r2_bucket, created_at) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,unixepoch())"
    ).bind(msgId, conversationId, role, fullContent.slice(0, 500), safeProvider, safeModelKey, safeInput, safeOutput, tokenCount, amountUsd, routingOpts?.tenantId ?? env.TENANT_ID ?? null, chatPersistenceUserId ?? null, msgR2Key, 'iam-platform').run();
  } catch (e) {
    console.error('[agent/chat] agent_messages INSERT failed:', e?.message ?? e);
  }
  const ctxKey = `agent-sessions/${conversationId}/context.json`;
  try {
    const now = Math.floor(Date.now() / 1000);
    await env.DB.prepare(
      "UPDATE agent_conversations SET r2_context_key = ?, message_count = message_count + 1, last_message_at = ?, total_cost_usd = total_cost_usd + ?, model = ?, project_id = COALESCE(project_id, ?) WHERE id = ?"
    ).bind(ctxKey, now, amountUsd || 0, safeModelKey, routingOpts?.projectId ?? null, conversationId).run();
  } catch (e) {
    console.error('[agent/chat] agent_conversations UPDATE failed:', e?.message ?? e);
  }
  let _sessionCtx = { messages: [], message_count: 0 };
  try {
    let kv = null;
    if (env.SESSION_CACHE) {
      kv = await env.SESSION_CACHE.get(`sess_ctx:${conversationId}`, 'json');
    }
    if (kv) {
      _sessionCtx = kv;
    } else if (env.R2) {
      const r2obj = await env.R2.get(ctxKey);
      if (r2obj) _sessionCtx = await r2obj.json();
    }
  } catch (_) { }
  if (!Array.isArray(_sessionCtx.messages)) _sessionCtx.messages = [];
  _sessionCtx.messages.push({
    id: msgId,
    role,
    r2_key: msgR2Key,
    token_count: tokenCount || 0,
    created_at: Date.now(),
    preview: (fullContent || '').slice(0, 120),
  });
  _sessionCtx.message_count = _sessionCtx.messages.length;
  _sessionCtx.last_active = Date.now();
  const ctxStr = JSON.stringify(_sessionCtx);
  await Promise.all([
    env.R2 ? env.R2.put(ctxKey, ctxStr, {
      httpMetadata: { contentType: 'application/json' },
    }).catch(() => { }) : Promise.resolve(),
    env.SESSION_CACHE ? env.SESSION_CACHE.put(
      `sess_ctx:${conversationId}`, ctxStr,
      { expirationTtl: 86400 },
    ).catch(() => { }) : Promise.resolve(),
  ]);
  const spendTenantId = resolveTelemetryTenantId(env, routingOpts?.tenantId);
  const modelRates = (routingOpts && routingOpts.modelRates) ? { ...routingOpts.modelRates } : {};
  if (!modelRates[safeModelKey] && rowForTelemetry) {
    modelRates[safeModelKey] = rowForTelemetry;
  }
  const wWorkers = safeProvider === 'workers_ai' || (safeModelKey && safeModelKey.startsWith('@cf/'));
  let telemetryRowId = null;
  if (!omitTelemetryWrite) try {
    telemetryRowId = await writeTelemetry(env, {
      sessionId: conversationId,
      tenantId: spendTenantId,
      provider: safeProvider,
      model: safeModelKey,
      inputTokens: safeInput,
      outputTokens: safeOutput,
      cacheReadTokens: safeCacheRead,
      cacheWriteTokens: safeCacheCreate,
      latencyMs: routingOpts && typeof routingOpts.chatStartMs === 'number' ? Date.now() - routingOpts.chatStartMs : null,
      toolCallCount: routingOpts?.toolCallCount,
      toolNamesUsed: routingOpts?.toolNamesUsed,
      promptPreview: routingOpts?.promptPreview,
      responsePreview: safeText,
      finishReason: routingOpts?.finishReason,
      success: true,
      errorMessage: null,
      routingDecisionId: routingOpts?.routingDecisionId,
      agentRunId: agentsamAgentRunId,
      computedCostUsdOverride: wWorkers ? amountUsd : undefined,
    }, modelRates);
  } catch (e) {
    console.error('[agent/chat] writeTelemetry failed:', e?.message ?? e);
  }
  try {
    if (conversationId) {
      await env.DB.prepare(
        `UPDATE mcp_agent_sessions
         SET cost_usd = COALESCE(cost_usd, 0) + ?,
             updated_at = unixepoch()
         WHERE conversation_id = ?`
      ).bind(amountUsd ?? 0, conversationId).run();
    }
  } catch (e) {
    console.warn('[streamDoneDbWrites] mcp_agent_sessions cost rollup', e?.message ?? e);
  }
  if (agent_id) {
    try {
      await env.DB.prepare("UPDATE agentsam_ai SET total_runs=total_runs+1, last_run_at=unixepoch(), updated_at=unixepoch() WHERE id=?").bind(agent_id).run();
    } catch (_) { }
  }
  if (ctx && typeof ctx.waitUntil === 'function' && typeof lastUserTextForMemory === 'string' && lastUserTextForMemory.length > 0 && safeText.length > 0) {
    ctx.waitUntil(persistAgentMemoryHyperdrive(env, {
      sessionId: conversationId,
      userText: lastUserTextForMemory,
      assistantText: safeText,
      modelKey: safeModelKey,
      provider: safeProvider,
    }).catch((e) => console.warn('[agent_memory]', e?.message ?? e)));
  }
  if (agentsamAgentRunId) {
    await completeAgentsamAgentRun(env, agentsamAgentRunId, conversationId, safeInput, safeOutput, amountUsd);
  }
  if (telemetryRowId) {
    await completeRoutingDecisionTelemetry(env, conversationId, telemetryRowId, safeInput, safeOutput, amountUsd, routingOpts);
  }
}

/** Return the text of the last user message in apiMessages (for intent classification). */
function getLastUserMessageText(messages) {
  for (let i = messages.length - 1; i >= 0; i--) {
    const m = messages[i];
    if (m.role !== 'user') continue;
    const content = m.content;
    if (typeof content === 'string') return content.trim();
    if (Array.isArray(content)) {
      const text = content.map(c => (c.type === 'text' ? c.text : '')).join('').trim();
      if (text) return text;
    }
    return '';
  }
  return '';
}

/** Token-efficiency caps: hard bounds for prompt sections to reject unbounded assembly. */
const PROMPT_CAPS = {
  DAILY_MEMORY_MAX_CHARS: 2000,
  FILE_CONTEXT_MAX_CHARS: 4000,
  MEMORY_INDEX_MAX_CHARS: 4000,
  /** Unified D1 + pgvector [AGENT CONTEXT] block (total chars). */
  AGENT_CONTEXT_MAX_CHARS: 3000,
  KNOWLEDGE_BLURB_MAX_CHARS: 2000,
  SCHEMA_BLURB_MAX_CHARS: 4000,
  MCP_BLURB_MAX_CHARS: 800,
  RAG_CONTEXT_MAX_CHARS: 3000,
  CONTEXT_INDEX_MAX_CHARS: 4000,
  CONTEXT_INDEX_R2_FULL_MAX_CHARS: 12000,
  TRUNCATION_MARKER: '\n\n[... truncated]',
  SESSION_SUMMARY_MAX_CHARS: 1500,
  LAST_N_VERBATIM_TURNS: 6,
};

function capWithMarker(text, maxChars) {
  if (!text || text.length <= maxChars) return text;
  return text.slice(0, maxChars) + PROMPT_CAPS.TRUNCATION_MARKER;
}

/** Provider-aware system prompt caps — Google/OpenAI get trimmed context to reduce token burn */
const PROVIDER_PROMPT_CAPS = {
  anthropic: {
    COMPILED_CONTEXT_MAX_CHARS: 6000,  // full context for complex tasks
    RAG_CONTEXT_MAX_CHARS: 2000,
    SCHEMA_BLURB_MAX_CHARS: 4000,
    KNOWLEDGE_BLURB_MAX_CHARS: 2000,
    DAILY_MEMORY_MAX_CHARS: 2000,
    MCP_BLURB_MAX_CHARS: 800,
    AGENT_CONTEXT_MAX_CHARS: 3000,
  },
  google: {
    COMPILED_CONTEXT_MAX_CHARS: 800,
    RAG_CONTEXT_MAX_CHARS: 600,
    SCHEMA_BLURB_MAX_CHARS: 0,       // skip schema entirely
    KNOWLEDGE_BLURB_MAX_CHARS: 400,
    DAILY_MEMORY_MAX_CHARS: 400,
    MCP_BLURB_MAX_CHARS: 400,
    AGENT_CONTEXT_MAX_CHARS: 1200,
  },
  openai: {
    COMPILED_CONTEXT_MAX_CHARS: 1200,
    RAG_CONTEXT_MAX_CHARS: 800,
    SCHEMA_BLURB_MAX_CHARS: 0,
    KNOWLEDGE_BLURB_MAX_CHARS: 600,
    DAILY_MEMORY_MAX_CHARS: 600,
    MCP_BLURB_MAX_CHARS: 400,
    AGENT_CONTEXT_MAX_CHARS: 1600,
  },
};

function getProviderCap(provider, capKey) {
  const override = PROVIDER_PROMPT_CAPS[provider];
  if (!override) return PROMPT_CAPS[capKey] ?? Infinity;
  return override[capKey] ?? PROMPT_CAPS[capKey] ?? Infinity;
}

function capForProvider(text, provider, capKey) {
  if (!text) return text;
  const max = getProviderCap(provider, capKey);
  if (max === 0) return '';
  if (text.length <= max) return text;
  return text.slice(0, max) + PROMPT_CAPS.TRUNCATION_MARKER;
}

/** Provider-aware system prompt caps — Google/OpenAI get trimmed context to reduce token burn */
/**
 * pgvector + D1 memory: merge, sort by score DESC, drop D1 rows whose key/value text appears in pgvector blob, cap total chars.
 */
function buildUnifiedAgentContextBlock(d1Rows, pgRows) {
  const pgTexts = [];
  for (const r of pgRows || []) {
    const t = String(r.content ?? r.text ?? r.chunk ?? (typeof r.body === 'string' ? r.body : '') ?? '').trim();
    if (t) pgTexts.push(t);
  }
  const pgLower = pgTexts.join('\n').toLowerCase();

  const lines = [];
  for (const r of pgRows || []) {
    const t = String(r.content ?? r.text ?? r.chunk ?? (typeof r.body === 'string' ? r.body : '') ?? '').trim();
    if (!t) continue;
    const sim = r.similarity ?? r.score;
    const sc = typeof sim === 'number' ? sim : 0.5;
    const oneLine = t.split(/\r?\n/)[0].trim().slice(0, 240);
    lines.push({ score: sc, text: `[${sc.toFixed(2)} | supabase] ${oneLine}` });
  }
  for (const r of d1Rows || []) {
    const key = String(r.key ?? '').trim();
    const val = String(r.value ?? '').trim();
    if (!val && !key) continue;
    const kl = key.toLowerCase();
    const vl = val.toLowerCase();
    if (kl && pgLower.includes(kl)) continue;
    if (vl.length >= 16 && pgLower.includes(vl.slice(0, 64))) continue;
    const sc = Number(r.importance_score);
    const score = Number.isFinite(sc) ? sc : 0.5;
    const preview = val.length > 220 ? val.slice(0, 217) + '...' : val;
    lines.push({ score, text: `[memory | d1] ${key ? `${key}: ` : ''}${preview}` });
  }
  lines.sort((a, b) => b.score - a.score);
  if (!lines.length) return '';
  const head = '[AGENT CONTEXT — ranked by relevance]';
  const body = head + '\n' + lines.map((x) => x.text).join('\n');
  return capWithMarker('\n\n' + body, PROMPT_CAPS.AGENT_CONTEXT_MAX_CHARS);
}

/** Up to 3 terms (length > 3) joined for context_index LIKE search; empty if none. */
function getContextIndexSearchTerm(query) {
  if (typeof query !== 'string' || !query.trim()) return '';
  const terms = query.toLowerCase().split(/\s+/).filter((t) => t.length > 3).slice(0, 3);
  return terms.length ? terms.join(' ') : '';
}

/**
 * Keyword search on context_index (no vectors). Returns [] if table missing or no terms.
 * scope: tenant or bucket scope; rows match scope = 'global' OR scope = ?
 */
async function fetchContextIndex(db, query, scope) {
  const rawTerm = getContextIndexSearchTerm(query);
  if (!db || !rawTerm) return [];
  // Sanitize: truncate, strip LIKE special chars to prevent "pattern too complex"
  const term = rawTerm.slice(0, 60).replace(/[%_\[\]^]/g, " ").trim();
  if (!term) return [];

  const scopeParam = scope && String(scope).trim() ? String(scope).trim() : 'global';

  try {
    const { results } = await db.prepare(
      `SELECT id, title, doc_type, storage_type,
              r2_bucket, r2_key, inline_content, summary
       FROM context_index
       WHERE is_active = 1 AND is_stale = 0
       AND (keywords LIKE ? OR title LIKE ? OR tags LIKE ?)
       AND (scope = 'global' OR scope = ?)
       ORDER BY importance_score DESC
       LIMIT 5`
    ).bind(`%${term}%`, `%${term}%`, `%${term}%`, scopeParam).all();

    return (results || []).map((r) => ({
      id: r.id,
      title: r.title,
      doc_type: r.doc_type,
      storage_type: r.storage_type,
      content: r.inline_content || null,
      r2_key: r.r2_key || null,
      r2_bucket: r.r2_bucket || null,
      summary: r.summary,
    }));
  } catch (e) {
    console.warn('[context_index] fetchContextIndex', e?.message ?? e);
    return [];
  }
}

/** When true, load full R2 body for this hit; otherwise summary-only (or short fallback). */
function contextIndexWarrantsR2FullFetch(queryLower, row) {
  const title = (row.title || '').toLowerCase();
  const summary = (row.summary || '').toLowerCase();
  const qWords = queryLower.split(/\s+/).filter((w) => w.length > 3).slice(0, 6);
  if (qWords.length === 0) return false;
  let overlap = 0;
  for (const qw of qWords) {
    if (title.includes(qw) || summary.includes(qw)) overlap++;
  }
  return overlap >= 2 || (qWords.length === 1 && (title.includes(qWords[0]) || summary.includes(qWords[0])));
}

/**
 * Build prompt text from context_index rows: inline_content verbatim (capped); R2 = summary unless warrant full fetch.
 * @returns {{ text: string, ids: string[] }}
 */
async function buildContextIndexPromptBlock(env, rows, queryLower) {
  if (!rows || !rows.length) return { text: '', ids: [] };
  const ids = [];
  const parts = [];
  const qLow = (queryLower || '').toLowerCase();

  for (const row of rows) {
    ids.push(row.id);
    let body = '';
    if (row.content) {
      body = capWithMarker(String(row.content), PROMPT_CAPS.CONTEXT_INDEX_MAX_CHARS);
    } else if (row.r2_key) {
      const wantFull = contextIndexWarrantsR2FullFetch(qLow, row);
      if (wantFull && env) {
        const bucket = row.r2_bucket || 'iam-platform';
        const binding = getR2Binding(env, bucket);
        if (binding) {
          try {
            const obj = await binding.get(row.r2_key);
            if (obj) {
              const txt = await obj.text();
              body = capWithMarker(txt, PROMPT_CAPS.CONTEXT_INDEX_R2_FULL_MAX_CHARS);
            }
          } catch (e) {
            console.warn('[context_index] R2 get', row.r2_key, e?.message ?? e);
          }
        }
      }
      if (!body) {
        body =
          (row.summary && String(row.summary).trim()) ||
          '(Indexed R2 document: no summary; narrow your question to load full text.)';
      }
    } else {
      body = (row.summary && String(row.summary).trim()) || '';
    }

    const label = row.title || row.id;
    const dtype = row.doc_type || 'doc';
    parts.push(`### ${label} (${dtype})\n${body}`);
  }

  return { text: parts.join('\n\n'), ids };
}

/**
 * Expects table context_search_log(id, searched_at, query_snippet, scope, search_term, context_ids_used, result_count, was_helpful).
 * No-op if table missing.
 */
async function logContextSearch(db, { queryText, scope, searchTerm, contextIds }) {
  if (!db) return;
  try {
    const id = `csl_${crypto.randomUUID()}`;
    const snippet = (queryText || '').slice(0, 500);
    const scopeParam = scope && String(scope).trim() ? String(scope).trim() : 'global';
    const term = searchTerm || '';
    const idsJson = JSON.stringify(contextIds || []);
    const count = Array.isArray(contextIds) ? contextIds.length : 0;
    await db.prepare(
      `INSERT INTO context_search_log
       (id, searched_at, query, query_snippet, scope, search_term, context_ids_used, result_count, was_helpful)
       VALUES (?, unixepoch(), ?, ?, ?, ?, ?, ?, NULL)`
    ).bind(id, snippet, snippet, scopeParam, term, idsJson, count).run();
  } catch (e) {
    console.warn('[context_index] logContextSearch', e?.message ?? e);
  }
}

/** Approximate token count from character length (for prompt telemetry). */
function charsToTokens(chars) {
  if (chars == null || typeof chars !== 'number') return 0;
  return Math.ceil(chars / 4);
}

/** Log section-level prompt telemetry for /api/agent/chat. Logs approximate chars/tokens per section, mode, provider, stream, tool count, message count. */
function logPromptTelemetry(env, payload) {
  const t = payload;
  const coreTokens = charsToTokens(t.coreSystemChars);
  const compiledTokens = charsToTokens(t.compiledContextChars);
  const ragTokens = charsToTokens(t.ragContextChars);
  const fileTokens = charsToTokens(t.fileContextChars);
  const historyTokens = charsToTokens(t.historyChars);
  const toolDefTokens = charsToTokens(t.toolDefChars);
  const totalInputTokens = charsToTokens(t.totalAssembledChars);
  try {
    console.log('[agent/chat] prompt_telemetry', JSON.stringify({
      mode: t.mode,
      provider: t.provider,
      stream: t.stream,
      tool_count: t.toolCount,
      message_count: t.messageCount,
      core_system_chars: t.coreSystemChars,
      core_system_tokens: coreTokens,
      compiled_context_chars: t.compiledContextChars,
      compiled_context_tokens: compiledTokens,
      rag_context_chars: t.ragContextChars,
      rag_context_tokens: ragTokens,
      pgvector_context_chars: t.pgvectorContextChars ?? 0,
      file_context_chars: t.fileContextChars,
      file_context_tokens: fileTokens,
      conversation_history_chars: t.historyChars,
      conversation_history_tokens: historyTokens,
      tool_definitions_chars: t.toolDefChars,
      tool_definitions_tokens: toolDefTokens,
      total_assembled_chars: t.totalAssembledChars,
      total_assembled_tokens_est: totalInputTokens,
    }));
  } catch (e) {
    console.warn('[agent/chat] logPromptTelemetry', e?.message ?? e);
  }
}

/** Mode-specific prompt builders. Sections: { core, memory, kb, mcp, schema, daily, full }. Each section is a string (may be empty). Do not share full payload by default. */
function buildAskContext(sections, ragContext, fileContext, model, indexedContext) {
  let core = (sections && sections.core) || '';
  if (!core && sections && typeof sections.full === 'string') core = capWithMarker(sections.full, 2500);
  const memory = (sections && sections.memory) ? capWithMarker(sections.memory, 1500) : '';
  const fileBlock = fileContext ? capWithMarker(fileContext, 2000) : '';
  let out = core + memory;
  if (indexedContext) out += '\n\n[Context index — matched docs]\n' + capWithMarker(indexedContext, 2500);
  if (ragContext) out += '\n\nRelevant platform context:\n' + capWithMarker(ragContext, 1500);
  out += (fileBlock ? '\n\n' + fileBlock : '');
  return out;
}

function buildPlanContext(sections, ragContext, fileContext, model, indexedContext) {
  let core = (sections && sections.core) || '';
  if (!core && sections && typeof sections.full === 'string') core = capWithMarker(sections.full, 4000);
  const memory = (sections && sections.memory) || '';
  const daily = (sections && sections.daily) || '';
  const fileBlock = fileContext ? capWithMarker(fileContext, PROMPT_CAPS.FILE_CONTEXT_MAX_CHARS) : '';
  let out = core + memory + daily;
  if (indexedContext) out += '\n\n[Context index — matched docs]\n' + capWithMarker(indexedContext, 3500);
  if (ragContext) out += '\n\nRelevant platform context:\n' + ragContext;
  out += (fileBlock ? '\n\n' + fileBlock : '');
  return out;
}

function buildAgentContext(sections, ragContext, fileContext, model, compiledContextBlob, indexedContext) {
  // Prefer compiledContextBlob when explicitly passed (already capped by caller)
  // Fall back to sections.full only when compiledContextBlob is null/undefined
  const rawFull = (compiledContextBlob != null && typeof compiledContextBlob === 'string')
    ? compiledContextBlob
    : (sections && typeof sections.full === 'string')
      ? sections.full
      : (sections ? [sections.core, sections.memory, sections.kb, sections.mcp, sections.schema, sections.daily].filter(Boolean).join('') : '');
  // Apply provider-aware cap as final safety net
  const full = capForProvider(rawFull, model?.provider, 'COMPILED_CONTEXT_MAX_CHARS') || rawFull;
  let out = full;
  const prefixParts = [];
  if (indexedContext) prefixParts.push('[Context index — matched docs]\n' + capWithMarker(indexedContext, PROMPT_CAPS.CONTEXT_INDEX_MAX_CHARS));
  if (ragContext) prefixParts.push('Relevant platform context:\n' + ragContext);
  if (prefixParts.length) out = prefixParts.join('\n\n') + '\n\n' + out;
  out += (fileContext ? '\n\n' + fileContext : '');
  return out;
}

function buildDebugContext(sections, ragContext, fileContext, model, indexedContext) {
  let core = (sections && sections.core) || '';
  if (!core && sections && typeof sections.full === 'string') core = capWithMarker(sections.full, 3000);
  const schema = (sections && sections.schema) || '';
  const fileBlock = fileContext || '';
  let out = core + schema;
  if (indexedContext) out += '\n\n[Context index — matched docs]\n' + capWithMarker(indexedContext, 2000);
  return out + (fileBlock ? '\n\n' + fileBlock : '');
}

function buildModeContext(mode, sections, compiledContextBlob, ragContext, fileContext, model, indexedContext, intent) {
  if (mode === 'ask') return buildAskContext(sections, ragContext, fileContext, model, indexedContext);
  if (mode === 'plan') return buildPlanContext(sections, ragContext, fileContext, model, indexedContext);
  if (mode === 'debug') return buildDebugContext(sections, ragContext, fileContext, model, indexedContext);
  // Intent-aware context filtering — shell needs no memory blob, question uses ask context
  if (intent === 'shell') return fileContext || '';
  if (intent === 'question') return buildAskContext(sections, ragContext, fileContext, model, indexedContext);
  // Intent + provider aware context cap
  // sql/question/shell get minimal context regardless of provider
  const isSimpleIntent = (intent === 'sql' || intent === 'question' || intent === 'shell');
  const compiledCap = isSimpleIntent
    ? 1200  // ~300 tokens max for simple intents on any provider
    : getProviderCap(model?.provider, 'COMPILED_CONTEXT_MAX_CHARS');
  const cappedBlob = compiledContextBlob
    ? (compiledCap === 0 ? '' : compiledContextBlob.slice(0, compiledCap))
    : null;
  const ragCap = isSimpleIntent ? 400 : null;
  const cappedRag = ragContext
    ? (ragCap ? ragContext.slice(0, ragCap) : capForProvider(ragContext, model?.provider, 'RAG_CONTEXT_MAX_CHARS'))
    : ragContext;
  return buildAgentContext(sections, cappedRag, fileContext, model, cappedBlob, indexedContext);
}

/** Filter tools by mode: Plan mode has no tools; Ask and Agent get all (subject to panel policy); Debug gets only terminal/log/read tools. */
function filterToolsByMode(mode, toolDefinitions) {
  if (!Array.isArray(toolDefinitions)) return [];
  if (mode === 'plan') {
    const planToolNames = new Set(['think', 'workspace_write_file', 'workspace_edit_file', 'think', 'workspace_write_file', 'workspace_edit_file', 'd1_query', 'knowledge_search', 'human_context_list', 'context_search', 'platform_info', 'imgx_generate_image', 'r2_write', 'r2_read', 'github_repos', 'github_file', 'generate_execution_plan']);
    return toolDefinitions.filter((t) => t && planToolNames.has(t.name));
  }
  if (mode === 'debug') {
    const debugToolNames = new Set(['terminal_execute', 'workspace_read_file', 'workspace_list_files', 'workspace_search', 'd1_query', 'r2_read', 'r2_list', 'knowledge_search']);
    return toolDefinitions.filter((t) => t && debugToolNames.has(t.name));
  }
  if (mode === 'ask') {
    const askToolNames = new Set(['think', 'think', 'd1_query', 'r2_read', 'r2_list', 'knowledge_search', 'workspace_read_file', 'workspace_list_files', 'workspace_search', 'human_context_list', 'platform_info', 'list_clients', 'list_workers', 'telemetry_query', 'context_search']);
    return toolDefinitions.filter((t) => t && askToolNames.has(t.name));
  }
  if (mode === 'agent') {
    const agentToolNames = new Set(['think', 'terminal_execute', 'workspace_write_file', 'workspace_edit_file', 'workspace_read_file', 'workspace_list_files', 'workspace_search', 'd1_query', 'd1_write', 'r2_read', 'r2_write', 'r2_list', 'r2_search', 'playwright_screenshot', 'a11y_audit_webpage', 'a11y_get_summary', 'knowledge_search', 'human_context_add', 'human_context_list', 'resend_send_email', 'worker_deploy', 'list_workers', 'list_clients', 'platform_info', 'generate_execution_plan', 'context_optimize', 'telemetry_log', 'telemetry_query', 'imgx_generate_image', 'github_repos', 'github_file', 'gdrive_list', 'gdrive_fetch', 'agentsam_run_agent', 'agentsam_get_agent', 'agentsam_list_agents', 'context_search', 'r2_bucket_summary', 'excalidraw_open', 'excalidraw_add_elements', 'excalidraw_load_library', 'excalidraw_export', 'excalidraw_clear', 'preview_in_browser', 'get_r2_url']);
    return toolDefinitions.filter((t) => t && agentToolNames.has(t.name));
  }
  return toolDefinitions.slice(0, 20);
}

/**
 * Normalize mixed allow-list storage: JSON array or comma-separated string (e.g. terminal_execute,r2_*).
 */
function parseMixedToolAllowList(raw) {
  if (raw == null) return [];
  const s = String(raw).trim();
  if (!s) return [];
  if (s.startsWith('[')) {
    try {
      const j = JSON.parse(s);
      if (Array.isArray(j)) return j.map((x) => String(x).trim()).filter(Boolean);
    } catch (_) {
      /* fall through to CSV */
    }
  }
  return s.split(',').map((x) => x.trim()).filter(Boolean);
}

/** Strip D1 id prefix so tool_d1_query matches worker tool d1_query. */
function stripToolPrefixForMatch(s) {
  const t = String(s || '').trim();
  if (t.startsWith('tool_')) return t.slice(5);
  return t;
}

/**
 * Small glob: * matches any substring; patterns like cdt_*, imgx_*, r2_*.
 * Applies stripToolPrefixForMatch to the pattern only (worker tool names never use tool_).
 */
function smallGlobMatch(patternRaw, toolName) {
  const pattern = stripToolPrefixForMatch(String(patternRaw || '').trim());
  const candidate = String(toolName || '').trim();
  if (!pattern || !candidate) return false;
  if (pattern === '*') return true;
  if (!pattern.includes('*')) return pattern === candidate;
  const parts = pattern.split('*').map((p) => p.replace(/[.+?^${}()|[\]\\]/g, '\\$&'));
  try {
    return new RegExp(`^${parts.join('.*')}$`).test(candidate);
  } catch (_) {
    return false;
  }
}

/**
 * Intersect MCP tool rows/defs with agentsam_subagent_profile.allowed_tool_globs (mixed JSON/CSV, tool_ prefix, globs).
 * Empty / null allow list = no extra restriction (pass-through).
 */
function filterToolsByAllowPatterns(toolDefinitions, allowedRaw) {
  if (!Array.isArray(toolDefinitions) || !toolDefinitions.length) return toolDefinitions || [];
  const patterns = parseMixedToolAllowList(allowedRaw);
  if (!patterns.length) return toolDefinitions;
  return toolDefinitions.filter((t) => {
    const name = t && (t.name != null ? t.name : t.tool_name);
    if (name == null || String(name).trim() === '') return false;
    return patterns.some((p) => smallGlobMatch(p, String(name)));
  });
}

