const TOOLCTX_INTENTS_KV_PREFIX = 'toolctx:intents:';
const TOOLCTX_INTENTS_KV_TTL_SEC = 300;

/**
 * Load keyword tool groups from agent_intent_patterns (D1), KV-cached per tenant.
 * @returns {Promise<Array<{ keys: string[], tools: string[] }>|null>} null on D1 error (caller uses fallback)
 */
async function loadIntentKeywordGroupsFromD1(env, tenantId) {
  const tid =
    tenantId != null && String(tenantId).trim() !== ''
      ? String(tenantId).trim()
      : 'global';
  const cacheKey = `${TOOLCTX_INTENTS_KV_PREFIX}${tid}`;
  if (env.SESSION_CACHE) {
    try {
      const raw = await env.SESSION_CACHE.get(cacheKey);
      if (raw) {
        const j = JSON.parse(raw);
        if (j && Array.isArray(j.groups)) return j.groups;
      }
    } catch (_) { }
  }
  if (!env.DB) return null;
  try {
    const r = await env.DB.prepare(
      `SELECT triggers_json, tools_json FROM agent_intent_patterns
       WHERE is_active = 1
         AND tools_json IS NOT NULL
         AND TRIM(tools_json) != ''`
    ).all();
    const groups = [];
    for (const row of r.results || []) {
      const keys = parseMixedToolAllowList(row.triggers_json).map((x) => String(x).toLowerCase()).filter(Boolean);
      const tools = parseMixedToolAllowList(row.tools_json);
      if (keys.length === 0 || tools.length === 0) continue;
      groups.push({ keys, tools });
    }
    if (env.SESSION_CACHE) {
      env.SESSION_CACHE.put(cacheKey, JSON.stringify({ groups, v: 1 }), { expirationTtl: TOOLCTX_INTENTS_KV_TTL_SEC }).catch(() => { });
    }
    return groups;
  } catch (e) {
    console.warn('[loadIntentKeywordGroupsFromD1]', e?.message ?? e);
    return null;
  }
}

/**
 * Intent-aware + keyword-boosted tool filter — D1 triggers_json/tools_json with KV cache; fallback to INTENT_KEYWORD_GROUPS_FALLBACK on D1 failure.
 * `tenantId` may be null — KV cache key becomes `global`; D1 query is not tenant-scoped.
 */
async function filterToolsByIntent(env, tenantId, intent, message, toolDefinitions) {
  const msg = (message || '').toLowerCase();
  const INTENT_MAP = {
    shell: ['terminal_execute', 'workspace_read_file', 'workspace_list_files', 'workspace_search'],
    sql: ['d1_query', 'd1_write', 'platform_info', 'supabase_query', 'supabase_write', 'hyperdrive_query', 'vector_search', 'vector_upsert'],
    question: ['context_search', 'knowledge_search', 'platform_info', 'd1_query', 'human_context_list', 'supabase_query', 'vector_search'],
    plan: ['generate_execution_plan', 'context_search', 'knowledge_search', 'd1_query', 'platform_info'],
    mixed: ['d1_query', 'd1_write', 'context_search', 'knowledge_search', 'platform_info', 'terminal_execute', 'r2_read', 'r2_write', 'human_context_list', 'workspace_read_file', 'workspace_write_file', 'supabase_query', 'vector_search'],
    auto: ['d1_query', 'd1_write', 'context_search', 'knowledge_search', 'platform_info', 'terminal_execute', 'r2_read', 'r2_write', 'human_context_list', 'workspace_read_file', 'workspace_write_file', 'supabase_query', 'vector_search'],
  };
  let keywordGroups = await loadIntentKeywordGroupsFromD1(env, tenantId);
  if (keywordGroups == null) {
    keywordGroups = INTENT_KEYWORD_GROUPS_FALLBACK;
  }
  const intentPatterns = INTENT_MAP[intent] ? INTENT_MAP[intent].slice() : [];
  const keywordPatterns = [];
  for (const group of keywordGroups) {
    if (group.keys.some((k) => msg.includes(k))) {
      for (const p of group.tools) keywordPatterns.push(p);
    }
  }
  let allPatterns = [...new Set(intentPatterns.concat(keywordPatterns))];
  if (allPatterns.length === 0) {
    allPatterns = ['d1_query', 'context_search', 'knowledge_search', 'platform_info', 'human_context_list'];
  }
  const result = toolDefinitions.filter(
    (t) => t && t.name && allPatterns.some((p) => smallGlobMatch(p, t.name))
  );
  return result.slice(0, 50); // Raised cap for Phase 2
}

/** Per-panel tool categories for /dashboard/mcp (request body agent_id). Agent Sam / unknown ids: no filter. */
const PANEL_TOOL_POLICY = {
  mcp_agent_architect: ['context', 'query', 'database'],
  mcp_agent_builder: ['database', 'storage', 'integrations', 'execute', 'image'],
  mcp_agent_tester: ['database', 'browser', 'quality', 'telemetry', 'context'],
  mcp_agent_operator: ['platform', 'terminal', 'storage', 'telemetry', 'database'],
};
const ARCHITECT_READ_ONLY_DB_TOOLS = new Set(['d1_query', 'r2_read', 'r2_list', 'knowledge_search']);

function panelColumnFromRequestAgentId(agentId) {
  if (agentId == null || typeof agentId !== 'string') return 'agent_sam';
  if (agentId === 'agent_sam') return 'agent_sam';
  if (agentId.startsWith('mcp_agent_')) return agentId.slice('mcp_agent_'.length);
  return 'agent_sam';
}

/** @param {string|null|undefined} requestAgentId @param {any[]} rows from mcp_registered_tools */
function filterToolRowsByPanel(requestAgentId, rows) {
  if (!requestAgentId || !Array.isArray(rows) || !PANEL_TOOL_POLICY[requestAgentId]) return rows || [];
  const allow = PANEL_TOOL_POLICY[requestAgentId];
  return rows.filter((t) => {
    const cat = String(t.tool_category || '').toLowerCase();
    if (!allow.includes(cat)) return false;
    if (requestAgentId === 'mcp_agent_architect' && cat === 'database') {
      return ARCHITECT_READ_ONLY_DB_TOOLS.has(t.tool_name);
    }
    return true;
  });
}

/** Log classifyIntent outcomes to agent_intent_execution_log (requires agent_intent_patterns rows for sql|shell|question|mixed). */
async function logAgentIntentExecution(env, userText, intentDetected, confidence = 0.9) {
  if (!env?.DB || !userText || !intentDetected) return;
  const tid = tenantIdFromEnv(env);
  if (!tid) return;
  try {
    const pr = await env.DB.prepare('SELECT id FROM agent_intent_patterns WHERE intent_slug = ? LIMIT 1').bind(intentDetected).first();
    if (!pr?.id) return;
    await env.DB.prepare(
      `INSERT INTO agent_intent_execution_log (tenant_id, intent_pattern_id, user_input, intent_detected, confidence_score, created_at)
       VALUES (?, ?, ?, ?, ?, unixepoch())`
    ).bind(tid, pr.id, String(userText).slice(0, 8000), intentDetected, confidence).run();
  } catch (e) {
    console.warn('[logAgentIntentExecution]', e?.message ?? e);
  }
}

/** Increment pattern execution counters for routing feedback (agent_intent_patterns). */
async function bumpAgentIntentPatternExecutions(env, intentSlug) {
  if (!env?.DB || !intentSlug) return;
  try {
    await env.DB.prepare(
      `UPDATE agent_intent_patterns SET total_executions = total_executions + 1, last_executed_at = unixepoch() WHERE intent_slug = ?`
    ).bind(intentSlug).run();
  } catch (e) {
    console.warn('[bumpAgentIntentPatternExecutions]', e?.message ?? e);
  }
}

