/** GET JSON health endpoint; ok when HTTP ok and body JSON has ok === true. */
async function runWorkflowHttpHealthStep(env, url) {
  const u = String(url || '').trim();
  if (!u) return { ok: false, detail: 'missing health URL' };
  try {
    const ac = typeof AbortSignal !== 'undefined' && typeof AbortSignal.timeout === 'function'
      ? AbortSignal.timeout(20000)
      : undefined;
    const r = await fetch(u, { method: 'GET', headers: { Accept: 'application/json' }, signal: ac });
    const text = await r.text();
    let json = null;
    try {
      json = JSON.parse(text);
    } catch (_) { }
    const healthy = r.ok && json && json.ok === true;
    const detail = healthy
      ? `HTTP ${r.status} ok:true`
      : `HTTP ${r.status} (expected JSON { ok: true }); body: ${text.slice(0, 600)}`;
    return { ok: healthy, detail };
  } catch (e) {
    return { ok: false, detail: String(e?.message || e) };
  }
}

/** Heuristic diff summary for /review (no LLM — Architect role is static analysis only). */
async function runWorkflowGithubDiffReviewStep(env, triggerUserId, step) {
  const repo = String(step.github_repo || 'SamPrimeaux/march1st-inneranimalmedia').trim();
  const baseBranch = String(step.compare_base || 'main').trim() || 'main';
  const uid = String(triggerUserId || '').trim() || 'system';
  const role = step.role === 'tester' ? 'Tester' : 'Architect';
  if (!env.DB) {
    return { ok: false, summary: `${role}: D1 unavailable for GitHub token lookup.` };
  }
  const tokenRow = await getIntegrationToken(env.DB, uid, 'github', '');
  if (!tokenRow?.access_token) {
    return {
      ok: true,
      summary: `${role}: GitHub not connected for ${uid} — skipped diff fetch. Connect GitHub in the dashboard, then re-run /review.`,
    };
  }
  const ghHeaders = {
    Authorization: `Bearer ${tokenRow.access_token}`,
    Accept: 'application/vnd.github+json',
    'User-Agent': 'IAM-AgentWorkflow',
  };
  try {
    const commitsRes = await fetch(
      `https://api.github.com/repos/${repo}/commits?sha=${encodeURIComponent(baseBranch)}&per_page=2`,
      { headers: ghHeaders }
    );
    const commitsText = await commitsRes.text();
    if (!commitsRes.ok) {
      return {
        ok: true,
        summary: `${role}: GitHub commits list failed HTTP ${commitsRes.status}: ${commitsText.slice(0, 400)}`,
      };
    }
    let commits;
    try {
      commits = JSON.parse(commitsText);
    } catch (_) {
      return { ok: true, summary: `${role}: Invalid JSON from GitHub commits.` };
    }
    if (!Array.isArray(commits) || commits.length < 2) {
      return {
        ok: true,
        summary: `${role}: Need at least 2 commits on ${baseBranch} to diff (got ${Array.isArray(commits) ? commits.length : 0}).`,
      };
    }
    const headSha = commits[0].sha;
    const baseSha = commits[1].sha;
    const apiUrl = `https://api.github.com/repos/${repo}/compare/${baseSha}...${headSha}`;
    const res = await fetch(apiUrl, { headers: ghHeaders });
    const errBody = await res.text();
    if (!res.ok) {
      return {
        ok: true,
        summary: `${role}: GitHub compare ${baseSha.slice(0, 7)}...${headSha.slice(0, 7)} failed HTTP ${res.status}: ${errBody.slice(0, 400)}`,
      };
    }
    let data;
    try {
      data = JSON.parse(errBody);
    } catch (_) {
      return { ok: true, summary: `${role}: Invalid JSON from GitHub compare.` };
    }
    const files = Array.isArray(data.files) ? data.files : [];
    const names = files.map((f) => f.filename).filter(Boolean).slice(0, 35);
    const flags = [];
    if (files.length > 40) flags.push(`large diff (${files.length} files)`);
    for (const f of files) {
      const fn = String(f.filename || '');
      const patch = String(f.patch || '');
      const pu = patch.toUpperCase();
      if (/\.sql$/i.test(fn) && /\b(DROP|TRUNCATE|ALTER)\b/.test(pu)) {
        flags.push(`destructive SQL pattern in ${fn}`);
      }
      if (/\/worker\.js$/i.test(fn) || fn === 'worker.js') flags.push('worker.js touched');
    }
    const tail = names.length
      ? `Files (sample): ${names.join(', ')}${files.length > names.length ? ' ...' : ''}.`
      : 'No file list in compare response.';
    const flagStr = flags.length ? ` Flags: ${flags.join('; ')}.` : ' No automated flags.';
    return {
      ok: true,
      summary: `${role}: ${repo} @${baseBranch} (${baseSha.slice(0, 7)}..${headSha.slice(0, 7)}) — ${files.length} file(s). ${tail}${flagStr}`,
    };
  } catch (e) {
    return { ok: true, summary: `${role}: compare error: ${String(e?.message || e)}` };
  }
}

async function agentWorkflowRecordStepSuccess(env, workflowRunId, stepNum, stepName, stepType, t0, lastSummary) {
  const stepId = 'wfs_' + [...crypto.getRandomValues(new Uint8Array(8))].map((b) => b.toString(16).padStart(2, '0')).join('');
  const dur = Date.now() - t0;
  try {
    await env.DB.prepare(
      `INSERT INTO workflow_steps (id, run_id, step_number, step_name, step_type, status, started_at, completed_at, duration_ms, output_summary, metadata)
       VALUES (?,?,?,?,?,?,?,?,?,?,?)`
    ).bind(
      stepId,
      workflowRunId,
      stepNum,
      stepName,
      String(stepType || 'execution'),
      'success',
      Math.floor(t0 / 1000),
      Math.floor(Date.now() / 1000),
      dur,
      String(lastSummary || 'ok').slice(0, 5000),
      '{}'
    ).run();
  } catch (dbErr) {
    console.warn('[executeAgentWorkflowSteps] workflow_steps insert', dbErr?.message ?? dbErr);
  }
  await broadcastAgentWorkflowEvent(env, workflowRunId, {
    type: 'workflow_step',
    runId: workflowRunId,
    stepNumber: stepNum,
    stepName,
    status: 'success',
    output: String(lastSummary || '').slice(0, 2000),
    durationMs: dur,
  });
  return dur;
}

/**
 * Agent `workflow_runs` executor (separate from MCP `executeWorkflowSteps` at ~9788 and ~12625).
 * Runs inside ctx.waitUntil only — HTTP response has already returned.
 */
async function executeAgentWorkflowSteps(env, ctx, workflowRunId, workflowId, workflowName) {
  const tenantId = tenantIdFromEnv(env) || 'global';
  const steps = AGENT_BUILTIN_WORKFLOW_STEPS[workflowName] || [];
  const startedWall = Date.now();
  try {
    await env.DB.prepare(
      `UPDATE workflow_runs SET status = 'running', steps_total = ?, started_at = datetime('now'), updated_at = datetime('now') WHERE id = ?`
    ).bind(steps.length, workflowRunId).run();
  } catch (e) {
    console.warn('[executeAgentWorkflowSteps] start update', e?.message ?? e);
  }

  let stepsCompleted = 0;
  let lastSummary = '';
  let failed = false;
  let failReason = '';
  let triggerUserId = 'system';
  try {
    const tr = await env.DB.prepare('SELECT triggered_by FROM workflow_runs WHERE id = ?').bind(workflowRunId).first();
    if (tr?.triggered_by && String(tr.triggered_by).trim()) triggerUserId = String(tr.triggered_by).trim();
  } catch (_) { }

  for (let i = 0; i < steps.length; i++) {
    const step = steps[i] || {};
    const stepNum = i + 1;
    const stepName = String(step.name || `Step ${stepNum}`);
    const requiresApproval = step.requires_approval === true;
    const stepId = 'wfs_' + [...crypto.getRandomValues(new Uint8Array(8))].map((b) => b.toString(16).padStart(2, '0')).join('');
    const t0 = Date.now();

    try {
      const stepType = String(step.step_type || 'noop');
      if (stepType === 'http_health' && step.url) {
        const hr = await runWorkflowHttpHealthStep(env, String(step.url));
        if (!hr.ok && step.require_approval_when_failed === true) {
          notifySam(
            env,
            {
              subject: `Sandbox health check failed (${workflowName})`,
              body: `Run: ${workflowRunId}\nStep: ${stepName}\n${hr.detail}\n\nA proposal was created. Approve in the agent dashboard to continue to production anyway, or deny to stop the workflow.`,
              category: 'workflow',
            },
            ctx
          );
          const proposalId = 'prop_' + [...crypto.getRandomValues(new Uint8Array(8))].map((b) => b.toString(16).padStart(2, '0')).join('');
          const now = Math.floor(Date.now() / 1000);
          const cmdText = `Workflow ${workflowName} — step "${stepName}": sandbox health failed.\n${hr.detail}\nApprove ONLY if you accept continuing to production despite failed sandbox health.`;
          try {
            await env.DB.prepare(
              `INSERT INTO agent_command_proposals (
              id, tenant_id, agent_session_id, proposed_by, command_source, command_name, command_text, filled_template, rationale, risk_level, status, created_at, updated_at, tool
            ) VALUES (?,?,?,?, 'agent_generated', ?, ?, ?, ?, 'medium', 'pending', ?, ?, 'workflow_approval')`
            ).bind(
              proposalId,
              tenantId,
              workflowRunId,
              'agent-sam',
              `workflow_${workflowName}_health_fail`,
              cmdText,
              cmdText,
              stepName,
              now,
              now
            ).run();
          } catch (insErr) {
            console.warn('[executeAgentWorkflowSteps] health-fail proposal insert', insErr?.message ?? insErr);
            failed = true;
            failReason = String(insErr?.message || insErr);
            break;
          }
          const resolution = await waitForAgentProposalResolution(env, proposalId);
          if (resolution !== 'approved') {
            failed = true;
            failReason = resolution === 'denied' ? 'Denied after failed sandbox health' : 'Timeout after failed sandbox health';
            const dur = Date.now() - t0;
            try {
              await env.DB.prepare(
                `INSERT INTO workflow_steps (id, run_id, step_number, step_name, step_type, status, started_at, completed_at, duration_ms, output_summary, error_message, metadata)
               VALUES (?,?,?,?,?,?,?,?,?,?,?,?)`
              ).bind(
                stepId,
                workflowRunId,
                stepNum,
                stepName,
                stepType,
                'failed',
                Math.floor(t0 / 1000),
                Math.floor(Date.now() / 1000),
                dur,
                failReason,
                hr.detail.slice(0, 2000),
                JSON.stringify({ proposal_id: proposalId })
              ).run();
            } catch (_) { }
            await broadcastAgentWorkflowEvent(env, workflowRunId, {
              type: 'workflow_step',
              runId: workflowRunId,
              stepNumber: stepNum,
              stepName,
              status: 'failed',
              output: failReason,
              durationMs: dur,
            });
            break;
          }
          lastSummary = `Sandbox health failed; manual approval received. ${hr.detail}`;
        } else if (!hr.ok) {
          failed = true;
          failReason = hr.detail;
          const dur = Date.now() - t0;
          try {
            await env.DB.prepare(
              `INSERT INTO workflow_steps (id, run_id, step_number, step_name, step_type, status, started_at, completed_at, duration_ms, output_summary, error_message, metadata)
               VALUES (?,?,?,?,?,?,?,?,?,?,?,?)`
            ).bind(
              stepId,
              workflowRunId,
              stepNum,
              stepName,
              stepType,
              'failed',
              Math.floor(t0 / 1000),
              Math.floor(Date.now() / 1000),
              dur,
              'health check failed',
              failReason,
              '{}'
            ).run();
          } catch (_) { }
          await broadcastAgentWorkflowEvent(env, workflowRunId, {
            type: 'workflow_step',
            runId: workflowRunId,
            stepNumber: stepNum,
            stepName,
            status: 'failed',
            output: failReason,
            durationMs: dur,
          });
          break;
        } else {
          lastSummary = hr.detail;
        }
        await agentWorkflowRecordStepSuccess(env, workflowRunId, stepNum, stepName, stepType, t0, lastSummary);
        stepsCompleted += 1;
        continue;
      }
      if (stepType === 'github_diff_review') {
        const dr = await runWorkflowGithubDiffReviewStep(env, triggerUserId, step);
        lastSummary = dr.summary;
        await agentWorkflowRecordStepSuccess(env, workflowRunId, stepNum, stepName, stepType, t0, lastSummary);
        stepsCompleted += 1;
        continue;
      }

      if (stepType === 'd1_query') {
        const sqlRaw = String(step.sql || step.query || '').trim();
        if (!sqlRaw) {
          failed = true;
          failReason = 'd1_query: sql required';
          break;
        }
        if (!/^select\s/i.test(sqlRaw)) {
          failed = true;
          failReason = 'd1_query: only SELECT is allowed';
          break;
        }
        let dqRows = null;
        try {
          const dq = await env.DB.prepare(sqlRaw).all();
          dqRows = dq.results || [];
        } catch (dqErr) {
          failed = true;
          failReason = String(dqErr?.message || dqErr);
          const dur = Date.now() - t0;
          try {
            await env.DB.prepare(
              `INSERT INTO workflow_steps (id, run_id, step_number, step_name, step_type, status, started_at, completed_at, duration_ms, output_summary, error_message, metadata)
               VALUES (?,?,?,?,?,?,?,?,?,?,?,?)`
            ).bind(
              stepId,
              workflowRunId,
              stepNum,
              stepName,
              stepType,
              'failed',
              Math.floor(t0 / 1000),
              Math.floor(Date.now() / 1000),
              dur,
              'd1_query failed',
              failReason.slice(0, 2000),
              '{}'
            ).run();
          } catch (_) { }
          await broadcastAgentWorkflowEvent(env, workflowRunId, {
            type: 'workflow_step',
            runId: workflowRunId,
            stepNumber: stepNum,
            stepName,
            status: 'failed',
            output: failReason,
            durationMs: dur,
          });
          break;
        }
        const first = dqRows[0];
        lastSummary = `d1_query ok: ${dqRows.length} row(s) ${first != null ? JSON.stringify(first).slice(0, 400) : ''}`;
        await agentWorkflowRecordStepSuccess(env, workflowRunId, stepNum, stepName, stepType, t0, lastSummary);
        stepsCompleted += 1;
        continue;
      }

      if (stepType === 'terminal') {
        const cmd = String(step.command || '').trim();
        if (!cmd) {
          failed = true;
          failReason = 'terminal: command required';
          break;
        }
        const tr = await runTerminalCommandViaHttpExec(env, cmd);
        if (!tr.ok) {
          failed = true;
          failReason = 'terminal: http-exec unavailable or non-OK (check PTY / TERMINAL_EXEC_URL and tokens)';
          const dur = Date.now() - t0;
          try {
            await env.DB.prepare(
              `INSERT INTO workflow_steps (id, run_id, step_number, step_name, step_type, status, started_at, completed_at, duration_ms, output_summary, error_message, metadata)
               VALUES (?,?,?,?,?,?,?,?,?,?,?,?)`
            ).bind(
              stepId,
              workflowRunId,
              stepNum,
              stepName,
              stepType,
              'failed',
              Math.floor(t0 / 1000),
              Math.floor(Date.now() / 1000),
              dur,
              'terminal exec failed',
              failReason.slice(0, 2000),
              '{}'
            ).run();
          } catch (_) { }
          await broadcastAgentWorkflowEvent(env, workflowRunId, {
            type: 'workflow_step',
            runId: workflowRunId,
            stepNumber: stepNum,
            stepName,
            status: 'failed',
            output: failReason,
            durationMs: dur,
          });
          break;
        }
        if (tr.exitCode != null && tr.exitCode !== 0) {
          failed = true;
          failReason = `terminal: exit ${tr.exitCode} — ${(tr.text || '').slice(0, 800)}`;
          const dur = Date.now() - t0;
          try {
            await env.DB.prepare(
              `INSERT INTO workflow_steps (id, run_id, step_number, step_name, step_type, status, started_at, completed_at, duration_ms, output_summary, error_message, metadata)
               VALUES (?,?,?,?,?,?,?,?,?,?,?,?)`
            ).bind(
              stepId,
              workflowRunId,
              stepNum,
              stepName,
              stepType,
              'failed',
              Math.floor(t0 / 1000),
              Math.floor(Date.now() / 1000),
              dur,
              `exit ${tr.exitCode}`,
              failReason.slice(0, 2000),
              '{}'
            ).run();
          } catch (_) { }
          await broadcastAgentWorkflowEvent(env, workflowRunId, {
            type: 'workflow_step',
            runId: workflowRunId,
            stepNumber: stepNum,
            stepName,
            status: 'failed',
            output: failReason,
            durationMs: dur,
          });
          break;
        }
        lastSummary = `terminal ok: ${(tr.text || '').slice(0, 2000)}`;
        await agentWorkflowRecordStepSuccess(env, workflowRunId, stepNum, stepName, stepType, t0, lastSummary);
        stepsCompleted += 1;
        continue;
      }

      if (requiresApproval) {
        const proposalId = 'prop_' + [...crypto.getRandomValues(new Uint8Array(8))].map((b) => b.toString(16).padStart(2, '0')).join('');
        const now = Math.floor(Date.now() / 1000);
        const cmdText = String(step.command_text || step.params?.command || step.params?.query || `workflow:${workflowName}:${stepName}`).slice(0, 50000);
        try {
          await env.DB.prepare(
            `INSERT INTO agent_command_proposals (
              id, tenant_id, agent_session_id, proposed_by, command_source, command_name, command_text, filled_template, rationale, risk_level, status, created_at, updated_at, tool
            ) VALUES (?,?,?,?, 'agent_generated', ?, ?, ?, ?, 'medium', 'pending', ?, ?, 'workflow_approval')`
          ).bind(
            proposalId,
            tenantId,
            workflowRunId,
            'agent-sam',
            `workflow_${workflowName}`,
            cmdText,
            cmdText,
            stepName,
            now,
            now
          ).run();
        } catch (insErr) {
          console.warn('[executeAgentWorkflowSteps] proposal insert', insErr?.message ?? insErr);
          failed = true;
          failReason = String(insErr?.message || insErr);
          break;
        }
        notifySam(
          env,
          {
            subject: `Workflow approval: ${workflowName} step ${stepNum}`,
            body: `Run: ${workflowRunId}\nStep: ${stepName}\nProposal: ${proposalId}\n\nApprove: https://inneranimalmedia.com/dashboard/overview?proposal=${proposalId}`,
            category: 'workflow',
          },
          ctx
        );

        const resolution = await waitForAgentProposalResolution(env, proposalId);
        if (resolution === 'denied') {
          failed = true;
          failReason = 'approval denied';
          const dur = Date.now() - t0;
          try {
            await env.DB.prepare(
              `INSERT INTO workflow_steps (id, run_id, step_number, step_name, step_type, status, started_at, completed_at, duration_ms, output_summary, error_message, metadata)
               VALUES (?,?,?,?,?,?,?,?,?,?,?,?)`
            ).bind(
              stepId,
              workflowRunId,
              stepNum,
              stepName,
              String(step.step_type || 'approval'),
              'failed',
              Math.floor(t0 / 1000),
              Math.floor(Date.now() / 1000),
              dur,
              'denied',
              failReason,
              JSON.stringify({ proposal_id: proposalId })
            ).run();
          } catch (_) { }
          await broadcastAgentWorkflowEvent(env, workflowRunId, {
            type: 'workflow_step',
            runId: workflowRunId,
            stepNumber: stepNum,
            stepName,
            status: 'failed',
            output: 'denied',
            durationMs: dur,
          });
          break;
        }
        if (resolution === 'timeout') {
          failed = true;
          failReason = 'approval timeout';
          const dur = Date.now() - t0;
          try {
            await env.DB.prepare(
              `INSERT INTO workflow_steps (id, run_id, step_number, step_name, step_type, status, started_at, completed_at, duration_ms, output_summary, error_message, metadata)
               VALUES (?,?,?,?,?,?,?,?,?,?,?,?)`
            ).bind(
              stepId,
              workflowRunId,
              stepNum,
              stepName,
              String(step.step_type || 'approval'),
              'failed',
              Math.floor(t0 / 1000),
              Math.floor(Date.now() / 1000),
              dur,
              'timeout',
              failReason,
              JSON.stringify({ proposal_id: proposalId })
            ).run();
          } catch (_) { }
          await broadcastAgentWorkflowEvent(env, workflowRunId, {
            type: 'workflow_step',
            runId: workflowRunId,
            stepNumber: stepNum,
            stepName,
            status: 'failed',
            output: 'timeout',
            durationMs: dur,
          });
          break;
        }
      }

      const dur = Date.now() - t0;
      stepsCompleted += 1;
      lastSummary = `${stepName} ok`;
      try {
        await env.DB.prepare(
          `INSERT INTO workflow_steps (id, run_id, step_number, step_name, step_type, status, started_at, completed_at, duration_ms, output_summary, metadata)
           VALUES (?,?,?,?,?,?,?,?,?,?,?)`
        ).bind(
          stepId,
          workflowRunId,
          stepNum,
          stepName,
          String(step.step_type || 'execution'),
          'success',
          Math.floor(t0 / 1000),
          Math.floor(Date.now() / 1000),
          dur,
          lastSummary,
          '{}'
        ).run();
      } catch (dbErr) {
        console.warn('[executeAgentWorkflowSteps] workflow_steps insert', dbErr?.message ?? dbErr);
      }
      await broadcastAgentWorkflowEvent(env, workflowRunId, {
        type: 'workflow_step',
        runId: workflowRunId,
        stepNumber: stepNum,
        stepName,
        status: 'success',
        output: lastSummary,
        durationMs: dur,
      });
    } catch (stepErr) {
      failed = true;
      failReason = String(stepErr?.message || stepErr);
      break;
    }
  }

  const totalDur = Date.now() - startedWall;
  const finalStatus = failed ? 'failed' : 'success';
  try {
    await env.DB.prepare(
      `UPDATE workflow_runs SET status = ?, steps_completed = ?, output_summary = ?, duration_ms = ?, completed_at = datetime('now'), updated_at = datetime('now'), error_message = ?
       WHERE id = ?`
    ).bind(
      finalStatus,
      stepsCompleted,
      lastSummary || (failed ? failReason : 'completed'),
      totalDur,
      failed ? failReason : null,
      workflowRunId
    ).run();
  } catch (e) {
    console.warn('[executeAgentWorkflowSteps] final update', e?.message ?? e);
  }

  if (!failed && !WORKFLOW_SILENT_SUCCESS_NOTIFY.has(workflowName)) {
    notifySam(
      env,
      {
        subject: `Workflow ${workflowName} completed`,
        body: `Run: ${workflowRunId}\nSteps: ${stepsCompleted}/${steps.length}\nDuration: ${totalDur} ms`,
        category: 'workflow',
      },
      ctx
    );
  }
}

/** Delegate MCP tool execution for workflow steps (skips approval; telemetry recorded per step by executeWorkflowSteps). */
async function dispatchMcpTool(env, tool_name, input_template, session_id) {
  const out = await invokeMcpToolFromChat(
    env,
    tool_name,
    input_template && typeof input_template === 'object' ? input_template : {},
    session_id || '',
    { skipApprovalCheck: true, suppressTelemetry: true }
  );
  if (out.error) throw new Error(out.error);
  return out.result;
}

async function executeWorkflowSteps(env, workflow, run_id, session_id) {
  const MCP_WF_TENANT = tenantIdFromEnv(env) || 'global';
  let lastError = null;
  try {
    let steps = [];
    try {
      steps = typeof workflow.steps_json === 'string' ? JSON.parse(workflow.steps_json || '[]') : (workflow.steps_json || []);
    } catch (parseErr) {
      lastError = String(parseErr?.message || parseErr);
      await env.DB.prepare(
        `UPDATE mcp_workflow_runs SET status = 'failed', error_message = ?, step_results_json = '[]',
         cost_usd = 0, duration_ms = 0, completed_at = unixepoch() WHERE id = ?`
      ).bind(lastError, run_id).run();
      return;
    }
    if (!Array.isArray(steps)) steps = [];
    const stepResults = [];
    let totalCost = 0;
    let failed = false;
    const startMs = Date.now();
    const stepOutputs = []; // accumulate step results for injection

    for (const step of steps) {
      const tool_name = step.tool_name || step.tool;
      if (!tool_name) {
        failed = true;
        lastError = 'step missing tool_name';
        break;
      }
      let input_template =
        (step.input_template && typeof step.input_template === 'object' ? step.input_template : null) ||
        (step.params && typeof step.params === 'object' ? step.params : {});
      // Inject accumulated step outputs if requested
      if (input_template.inject_step_results === true && stepOutputs.length > 0) {
        input_template = { ...input_template, step_results: JSON.stringify(stepOutputs).slice(0, 8000) };
      }
      const retry_max = Math.max(1, Number(step.retry_max) || 1);
      let attempt = 0;
      let stepStatus = 'failed';
      let output = null;
      let errorMsg = null;
      let dispatchResult = null;

      while (attempt < retry_max) {
        attempt++;
        try {
          dispatchResult = await dispatchMcpTool(env, tool_name, input_template, session_id);
          output = typeof dispatchResult === 'string'
            ? dispatchResult
            : JSON.stringify(dispatchResult ?? {});
          if (!output || output === 'null' || output === '{}') {
            output = '(no output)';
          }
          stepStatus = 'completed';
          break;
        } catch (err) {
          errorMsg = String(err?.message || err);
          lastError = errorMsg;
        }
      }

      const tcId = crypto.randomUUID();
      const callStatus = stepStatus === 'completed' ? 'completed' : 'failed';
      const outSlice = output != null ? String(output).slice(0, 50000) : null;
      const stepNow = new Date().toISOString().slice(0, 19).replace('T', ' ');
      try {
        await env.DB.prepare(
          `INSERT INTO mcp_tool_calls
             (id, tenant_id, session_id, tool_name, tool_category, input_schema,
              output, status, invoked_by, invoked_at, completed_at, created_at, updated_at, error_message)
           VALUES (?, ?, ?, ?, ?, ?, ?, ?, 'workflow_runner', ?, ?, ?, ?, ?)`
        ).bind(
          tcId,
          MCP_WF_TENANT,
          session_id ?? null,
          tool_name,
          step.tool_category != null ? String(step.tool_category) : 'unknown',
          JSON.stringify(input_template),
          outSlice,
          callStatus,
          stepNow,
          stepNow,
          stepNow,
          stepNow,
          errorMsg ? String(errorMsg).slice(0, 8000) : null
        ).run();
        fireForgetAgentToolChainRow(env, {
          toolName: tool_name,
          agentSessionId: session_id ?? null,
          error: stepStatus === 'completed' ? null : errorMsg,
          costUsd: 0,
          mcpToolCallId: tcId,
          durationMs: 0,
          terminalSessionId: null,
        });
      } catch (dbErr) {
        console.warn('[executeWorkflowSteps] mcp_tool_calls insert', dbErr?.message ?? dbErr);
      }

      stepResults.push({ tool_name, status: callStatus, tool_call_id: tcId });
      if (stepStatus === 'completed' && output && output !== '(no output)') {
        stepOutputs.push({ step: step.name || tool_name, output: output.slice(0, 1000) });
      }

      if (callStatus === 'failed') {
        failed = true;
        break;
      }
    }

    const duration = Date.now() - startMs;
    const finalStatus = failed ? 'failed' : 'success';

    await env.DB.prepare(
      `UPDATE mcp_workflow_runs SET
         status = ?, step_results_json = ?, cost_usd = ?,
         duration_ms = ?, completed_at = unixepoch(), error_message = ?
       WHERE id = ?`
    ).bind(
      finalStatus,
      JSON.stringify(stepResults),
      totalCost,
      duration,
      failed ? (lastError || 'Workflow step failed') : null,
      run_id
    ).run();

    if (!failed) {
      await env.DB.prepare(
        `UPDATE mcp_workflows SET success_count = success_count + 1,
         updated_at = unixepoch() WHERE id = ? AND tenant_id = ?`
      ).bind(workflow.id, MCP_WF_TENANT).run();
    }
  } catch (err) {
    const msg = String(err?.message || err);
    try {
      await env.DB.prepare(
        `UPDATE mcp_workflow_runs SET status = 'failed', error_message = ?,
         completed_at = unixepoch(), duration_ms = 0 WHERE id = ?`
      ).bind(msg, run_id).run();
    } catch (_) { }
  }
}

/** Run Playwright/browser tools internally (MCP invoke). Used for UI validation, screenshots, and live page content. */
async function runInternalPlaywrightTool(env, toolName, params) {
  const { launch } = await import('@cloudflare/playwright');
  const url = (params.url || params.URL || '').trim() || 'https://example.com';
  const fullUrl = url.startsWith('http') ? url : 'https://' + url;
  const browser = await launch(env.MYBROWSER);
  try {
    const page = await browser.newPage();
    await page.setViewportSize({ width: params.width || 1280, height: params.height || 800 });
    await page.goto(fullUrl, { waitUntil: params.waitUntil || 'domcontentloaded', timeout: params.timeout || 20000 });
    if (toolName === 'browser_navigate') {
      // Broadcast ui.panel.open to draw room so AgentDashboard opens browser panel
      try {
        if (env.IAM_COLLAB) {
          const doId = env.IAM_COLLAB.idFromName('draw');
          await env.IAM_COLLAB.get(doId).fetch(new Request('https://internal/broadcast', {
            method: 'POST',
            body: JSON.stringify({ type: 'ui.panel.open', payload: { panel_type: 'browser', url: fullUrl } }),
            headers: { 'Content-Type': 'application/json' }
          }));
        }
      } catch (_) { }
      return { ok: true, url: fullUrl };
    }
    if (toolName === 'browser_content') {
      const html = await page.content();
      return { ok: true, url: fullUrl, html: html.slice(0, 500000) };
    }
    if (toolName === 'playwright_screenshot' || toolName === 'browser_screenshot') {
      const buf = await page.screenshot({ type: 'png', fullPage: params.fullPage === true });
      const { screenshot_url, job_id } = await putAgentBrowserScreenshotToR2(env, buf, 'image/png');
      return { ok: true, screenshot_url, job_id };
    }
    return { ok: false, error: 'Unknown tool' };
  } finally {
    await browser.close();
  }
}

/** Resend REST builtins (D1: resend_send_email, resend_list_domains, resend_send_broadcast, resend_create_api_key). */
async function runResendBuiltinTool(env, toolName, params) {
  const key = env.RESEND_API_KEY;
  if (!key) return { error: 'RESEND_API_KEY not configured' };
  const p = params || {};
  const auth = { Authorization: `Bearer ${key}`, 'Content-Type': 'application/json' };

  if (toolName === 'resend_list_domains') {
    const res = await fetch('https://api.resend.com/domains', { headers: { Authorization: `Bearer ${key}` } });
    const data = await res.json().catch(() => ({}));
    if (!res.ok) return { error: data?.message || JSON.stringify(data).slice(0, 400) || `Resend ${res.status}` };
    return { ok: true, data };
  }

  if (toolName === 'resend_create_api_key') {
    const name = String(p.name || '').trim();
    if (!name) return { error: 'name required (max 50 chars)' };
    const body = {
      name: name.slice(0, 50),
      permission: p.permission === 'sending_access' ? 'sending_access' : 'full_access',
    };
    if (body.permission === 'sending_access' && p.domain_id) body.domain_id = String(p.domain_id).trim();
    const res = await fetch('https://api.resend.com/api-keys', { method: 'POST', headers: auth, body: JSON.stringify(body) });
    const data = await res.json().catch(() => ({}));
    if (!res.ok) return { error: data?.message || JSON.stringify(data).slice(0, 400) || `Resend ${res.status}` };
    return { ok: true, id: data.id, token: data.token, warning: 'Store token securely; shown once.' };
  }

  if (toolName === 'resend_send_broadcast') {
    const broadcastId = String(p.broadcast_id || p.id || '').trim();
    if (!broadcastId) return { error: 'broadcast_id required' };
    const payload = {};
    if (p.scheduled_at != null && String(p.scheduled_at).trim()) payload.scheduled_at = String(p.scheduled_at).trim();
    const res = await fetch(`https://api.resend.com/broadcasts/${encodeURIComponent(broadcastId)}/send`, {
      method: 'POST',
      headers: auth,
      body: JSON.stringify(payload),
    });
    const data = await res.json().catch(() => ({}));
    if (!res.ok) return { error: data?.message || JSON.stringify(data).slice(0, 400) || `Resend ${res.status}` };
    return { ok: true, data };
  }

  if (toolName === 'resend_send_email') {
    const from = String(p.from || '').trim();
    const to = p.to;
    const subject = String(p.subject || '').trim();
    if (!from || !to || !subject) return { error: 'from, to, and subject required' };
    const body = { from, to, subject };
    if (p.html != null) body.html = String(p.html);
    if (p.text != null) body.text = String(p.text);
    if (p.reply_to != null) body.reply_to = p.reply_to;
    if (p.cc != null) body.cc = p.cc;
    if (p.bcc != null) body.bcc = p.bcc;
    if (p.headers != null && typeof p.headers === 'object') body.headers = p.headers;
    const res = await fetch('https://api.resend.com/emails', { method: 'POST', headers: auth, body: JSON.stringify(body) });
    const data = await res.json().catch(() => ({}));
    if (!res.ok) return { error: data?.message || JSON.stringify(data).slice(0, 400) || `Resend ${res.status}` };
    return { ok: true, id: data.id };
  }

  return { error: `Unknown Resend tool: ${toolName}` };
}

/**
 * IAM cdt_* tools (26 in D1): Playwright-first on MYBROWSER. IAM names mirror Cursor-style browser MCP, not raw CDP method names.
 * Stateless: one launch per invocation; pass url for DOM/network tools. Multi-tab tools only report the single active page.
 * Raw CDP (Tracing/Performance) is attempted via context.newCDPSession when the runtime supports it.
 */
async function runCdpBuiltinTool(env, toolName, params) {
  if (!env.MYBROWSER) return { error: 'MYBROWSER not configured' };
  const p = params || {};
  const { launch } = await import('@cloudflare/playwright');

  function normalizeUrl(raw) {
    const u = String(raw || '').trim();
    if (!u) return '';
    return u.startsWith('http') ? u : `https://${u}`;
  }

  async function withPage(fn) {
    const browser = await launch(env.MYBROWSER);
    try {
      const page = await browser.newPage();
      await page.setViewportSize({
        width: Math.min(1920, Math.max(320, Number(p.width) || 1280)),
        height: Math.min(2000, Math.max(240, Number(p.height) || 800)),
      });
      const url = normalizeUrl(p.url);
      if (url) {
        await page.goto(url, {
          waitUntil: p.waitUntil || 'domcontentloaded',
          timeout: Math.min(120000, Math.max(5000, Number(p.timeout) || 25000)),
        });
      }
      return await fn(browser, page);
    } finally {
      await browser.close();
    }
  }

  try {
    switch (toolName) {
      case 'cdt_navigate_page': {
        const url = normalizeUrl(p.url);
        if (!url) return { error: 'url required' };
        return await withPage(async (_b, page) => ({ ok: true, url: page.url() }));
      }
      case 'cdt_list_pages':
        return await withPage(async (_b, page) => ({ pages: [{ index: 0, url: page.url() }] }));
      case 'cdt_select_page': {
        const idx = Number(p.page_index ?? p.index ?? 0);
        if (idx !== 0) return { error: 'Stateless worker: only page_index 0 is supported (single page per call)' };
        return await withPage(async (_b, page) => ({ ok: true, selected_index: 0, url: page.url() }));
      }
      case 'cdt_new_page':
        return {
          ok: true,
          note: 'Stateless mode: each cdt_* call uses a fresh browser. Open a URL with cdt_navigate_page or pass url on other tools instead of multi-tab new_page.',
        };
      case 'cdt_close_page':
        return { ok: true, note: 'Browser session ends when the tool returns; no explicit close needed.' };

      case 'cdt_click':
      case 'cdt_fill':
      case 'cdt_hover':
      case 'cdt_press_key':
      case 'cdt_wait_for':
      case 'cdt_evaluate_script':
      case 'cdt_handle_dialog':
      case 'cdt_upload_file':
      case 'cdt_drag':
      case 'cdt_fill_form':
      case 'cdt_emulate':
      case 'cdt_resize_page':
      case 'cdt_take_screenshot':
      case 'cdt_take_snapshot':
      case 'cdt_list_console_messages':
      case 'cdt_get_console_message':
      case 'cdt_list_network_requests':
      case 'cdt_get_network_request':
      case 'cdt_performance_stop_trace':
      case 'cdt_performance_analyze_insight': {
        const url = normalizeUrl(p.url);
        if (!url && toolName !== 'cdt_resize_page' && toolName !== 'cdt_emulate') {
          return { error: 'url required for this tool (stateless navigation)' };
        }
        const browser = await launch(env.MYBROWSER);
        try {
          let page;
          try {
            const context = await browser.newContext(
              p.user_agent || p.userAgent
                ? { userAgent: String(p.user_agent || p.userAgent) }
                : {}
            );
            page = await context.newPage();
          } catch (_) {
            page = await browser.newPage();
          }
          await page.setViewportSize({
            width: Math.min(1920, Math.max(320, Number(p.width) || 1280)),
            height: Math.min(2000, Math.max(240, Number(p.height) || 800)),
          });
          if (toolName === 'cdt_resize_page') {
            await page.setViewportSize({
              width: Math.min(1920, Math.max(320, Number(p.width) || 1280)),
              height: Math.min(2000, Math.max(240, Number(p.height) || 800)),
            });
            if (url) await page.goto(url, { waitUntil: 'domcontentloaded', timeout: 25000 });
            return { ok: true, width: Number(p.width) || 1280, height: Number(p.height) || 800, url: page.url() };
          }
          if (toolName === 'cdt_emulate') {
            if (url) await page.goto(url, { waitUntil: 'domcontentloaded', timeout: 25000 });
            return {
              ok: true,
              url: page.url(),
              note: 'Set user_agent / width / height on this tool; preset device profiles are not applied in Worker (pass user_agent + viewport explicitly).',
            };
          }

          const requests = [];
          const responses = new Map();
          page.on('request', (req) => {
            requests.push({
              url: req.url(),
              method: req.method(),
              resourceType: req.resourceType(),
              id: requests.length,
            });
          });
          page.on('response', async (res) => {
            try {
              const req = res.request();
              const idx = requests.findIndex((r) => r.url === req.url() && r.method === req.method());
              if (idx >= 0) {
                responses.set(idx, {
                  status: res.status(),
                  statusText: res.statusText(),
                  headers: res.headers(),
                });
              }
            } catch (_) { }
          });
          const consoles = [];
          page.on('console', (msg) => {
            consoles.push({ type: msg.type(), text: msg.text() });
          });

          if (toolName === 'cdt_handle_dialog') {
            page.once('dialog', async (dialog) => {
              const accept = p.accept !== false;
              if (accept) {
                if (p.promptText != null) await dialog.accept(String(p.promptText));
                else await dialog.accept();
              } else {
                await dialog.dismiss();
              }
            });
          }

          if (url) {
            await page.goto(url, {
              waitUntil: p.waitUntil || 'domcontentloaded',
              timeout: Math.min(120000, Math.max(5000, Number(p.timeout) || 25000)),
            });
          }

          const selector = String(p.selector || p.element || '').trim();

          switch (toolName) {
            case 'cdt_click':
              if (!selector) return { error: 'selector required' };
              await page.click(selector, { timeout: Number(p.timeout) || 15000 });
              return { ok: true, url: page.url() };
            case 'cdt_fill':
              if (!selector) return { error: 'selector required' };
              await page.fill(selector, String(p.value ?? ''), { timeout: Number(p.timeout) || 15000 });
              return { ok: true };
            case 'cdt_fill_form': {
              const fields = Array.isArray(p.fields) ? p.fields : [];
              if (!fields.length) return { error: 'fields array required [{selector,value}]' };
              for (const f of fields) {
                if (f?.selector) await page.fill(String(f.selector), String(f.value ?? ''));
              }
              return { ok: true, count: fields.length };
            }
            case 'cdt_hover':
              if (!selector) return { error: 'selector required' };
              await page.hover(selector, { timeout: Number(p.timeout) || 15000 });
              return { ok: true };
            case 'cdt_press_key':
              await page.keyboard.press(String(p.key || p.text || 'Enter'));
              return { ok: true };
            case 'cdt_handle_dialog':
              return {
                ok: true,
                url: page.url(),
                note: 'Dialog listener was registered before navigation; dialogs during load were accepted/dismissed per accept/promptText params.',
              };
            case 'cdt_drag': {
              const src = String(p.source_selector || p.from_selector || '').trim();
              const tgt = String(p.target_selector || p.to_selector || '').trim();
              if (!src || !tgt) return { error: 'source_selector and target_selector required' };
              await page.locator(src).dragTo(page.locator(tgt));
              return { ok: true };
            }
            case 'cdt_wait_for': {
              const state = String(p.state || 'visible');
              const tw = Number(p.timeout) || 30000;
              if (p.text) await page.getByText(String(p.text), { exact: p.exact === true }).first().waitFor({ timeout: tw });
              else if (selector) await page.waitForSelector(selector, { state, timeout: tw });
              else if (p.time_ms) {
                const ms = Math.min(60000, Math.max(0, Number(p.time_ms) || 0));
                await new Promise((r) => setTimeout(r, ms));
              } else return { error: 'Provide selector, text, or time_ms' };
              return { ok: true };
            }
            case 'cdt_evaluate_script': {
              const expr = p.expression != null ? String(p.expression) : p.script != null ? String(p.script) : '';
              if (!expr) return { error: 'expression or script required' };
              const r = await page.evaluate((code) => {
                try {
                  // eslint-disable-next-line no-eval
                  return (0, eval)(code);
                } catch (e) {
                  return { __eval_error: String(e && e.message ? e.message : e) };
                }
              }, expr);
              return { ok: true, result: r };
            }
            case 'cdt_upload_file': {
              if (!selector) return { error: 'selector required' };
              const b64 = p.file_base64 || p.content_base64;
              const name = String(p.filename || 'upload.bin');
              if (b64) {
                const bin = Uint8Array.from(atob(String(b64).replace(/\s/g, '')), (c) => c.charCodeAt(0));
                await page.setInputFiles(selector, { name, mimeType: p.mimeType || 'application/octet-stream', buffer: bin });
              } else if (p.file_path) {
                return { error: 'file_path not supported in Worker; use file_base64' };
              } else {
                return { error: 'file_base64 required' };
              }
              return { ok: true };
            }
            case 'cdt_take_screenshot': {
              const buf = await page.screenshot({
                type: p.type === 'jpeg' ? 'jpeg' : 'png',
                fullPage: p.fullPage === true,
              });
              const { screenshot_url, job_id } = await putAgentBrowserScreenshotToR2(env, buf, 'image/png');
              return { ok: true, screenshot_url, job_id, url: page.url() };
            }
            case 'cdt_take_snapshot': {
              let snap = null;
              try {
                snap = await page.accessibility.snapshot({ interestingOnly: p.interestingOnly !== false });
              } catch (_) {
                snap = { error: 'accessibility.snapshot unavailable' };
              }
              return { ok: true, snapshot: snap, url: page.url() };
            }
            case 'cdt_list_console_messages':
              return { ok: true, messages: consoles.slice(-Math.min(200, Number(p.limit) || 50)) };
            case 'cdt_get_console_message': {
              const i = Number(p.index ?? p.message_index ?? 0);
              const m = consoles[i];
              if (!m) return { error: `No console message at index ${i}` };
              return { ok: true, message: m };
            }
            case 'cdt_list_network_requests': {
              const lim = Math.min(500, Number(p.limit) || 100);
              const out = requests.slice(0, lim).map((r, i) => ({ ...r, response: responses.get(i) || null }));
              return { ok: true, requests: out };
            }
            case 'cdt_get_network_request': {
              const i = Number(p.index ?? p.request_index ?? 0);
              const r = requests[i];
              if (!r) return { error: `No request at index ${i}` };
              return { ok: true, request: r, response: responses.get(i) || null };
            }
            case 'cdt_performance_stop_trace': {
              const metrics = await page.evaluate(() => {
                const nav = performance.getEntriesByType('navigation')[0];
                const paints = performance.getEntriesByType('paint');
                return {
                  domContentLoaded: nav?.domContentLoadedEventEnd,
                  loadEventEnd: nav?.loadEventEnd,
                  domInteractive: nav?.domInteractive,
                  paints: paints?.map((x) => ({ name: x.name, startTime: x.startTime })) || [],
                };
              });
              return {
                ok: true,
                note: 'Stateless: metrics cover this navigation only. For full traces use local Playwright or persistent browser sessions.',
                requestCount: requests.length,
                metrics,
              };
            }
            case 'cdt_performance_analyze_insight': {
              const insight = String(p.insight || 'navigation').toLowerCase();
              const data = await page.evaluate(() => {
                const nav = performance.getEntriesByType('navigation')[0];
                return nav
                  ? {
                    ttfb: nav.responseStart,
                    domInteractive: nav.domInteractive,
                    loadEventEnd: nav.loadEventEnd,
                  }
                  : {};
              });
              return { ok: true, insight, data };
            }
            default:
              return { error: `Unhandled cdt branch: ${toolName}` };
          }
        } finally {
          await browser.close();
        }
      }

      case 'cdt_performance_start_trace': {
        const browser = await launch(env.MYBROWSER);
        try {
          const page = await browser.newPage();
          let cdpNote = null;
          try {
            const ctx = page.context();
            if (typeof ctx.newCDPSession === 'function') {
              const session = await ctx.newCDPSession(page);
              await session.send('Tracing.start', {
                transferMode: 'ReturnAsStream',
                traceConfig: { recordMode: 'recordAsMuchAsPossible' },
              });
              cdpNote = 'CDP Tracing.start issued; stop_trace is not persisted across Worker invocations — use cdt_performance_stop_trace with url in the same multi-step client flow, or trace locally.';
            }
          } catch (e) {
            cdpNote = `CDP unavailable: ${e?.message || e}`;
          }
          return {
            ok: true,
            note: cdpNote || 'No CDP session API; use cdt_performance_stop_trace with url for navigation metrics.',
          };
        } finally {
          await browser.close();
        }
      }

      default:
        return { error: `Unknown cdt tool: ${toolName}` };
    }
  } catch (e) {
    return { error: String(e?.message || e) };
  }
}

async function uploadImgxToDashboard(env, bytes, contentType, baseName, logCtx = null) {
  if (!env.DASHBOARD || !bytes) return { ok: false, error: 'DASHBOARD bucket not configured' };
  const safeBase = String(baseName || 'imgx').replace(/[^a-zA-Z0-9._-]/g, '-').slice(0, 80) || 'imgx';
  const id = crypto.randomUUID();
  const ext = contentType && contentType.includes('webp') ? 'webp' : contentType && contentType.includes('jpeg') ? 'jpg' : 'png';
  const key = `generated/imgx/${safeBase}-${id}.${ext}`;
  await env.DASHBOARD.put(key, bytes, { httpMetadata: { contentType: contentType || 'image/png' } });
  if (logCtx) {
    const blen = bytes.byteLength ?? bytes.length ?? 0;
    await insertAiGenerationLog(env, {
      generationType: logCtx.generationType || 'image_asset',
      prompt: logCtx.prompt ?? null,
      model: logCtx.model ?? null,
      responseText: logCtx.responseText ?? `DASHBOARD:${key}`,
      tenantId:
        (logCtx.tenantId != null && String(logCtx.tenantId).trim()) ||
        (env.TENANT_ID ? String(env.TENANT_ID).trim() : null),
      createdBy: logCtx.createdBy || 'worker',
      metadataJson: {
        r2_key: key,
        bucket: 'DASHBOARD',
        byte_length: blen,
        content_type: contentType || 'image/png',
        ...(logCtx.metadata || {}),
      },
      sourceKind: 'worker',
      workspaceId: logCtx.workspaceId ?? null,
      relatedIdsJson: logCtx.relatedIdsJson ?? null,
    });
  }
  return { ok: true, key, url: `https://pub-b845a8f899834f0faf95dc83eda3c505.r2.dev/${key}` };
}

function listImgxProviders(env) {
  const openaiOk = !!env.OPENAI_API_KEY;
  const workersAiOk = !!env.AI;
  return [
    {
      id: 'openai',
      available: openaiOk,
      models: ['dall-e-3'],
      supports_generate: true,
      supports_edit: true,
    },
    {
      id: 'gemini',
      available: workersAiOk,
      models: ['@cf/stabilityai/stable-diffusion-xl-base-1.0'],
      supports_generate: true,
      supports_edit: false,
    },
  ];
}

async function runImgxBuiltinTool(env, toolName, params, ctx = {}) {
  if (toolName === 'imgx_list_providers') {
    return { providers: listImgxProviders(env) };
  }

  const hasOpenai = !!env.OPENAI_API_KEY;
  let provider = String(params.provider || '').trim().toLowerCase();
  if (!provider) {
    provider = hasOpenai ? 'openai' : (env.AI ? 'cf' : '');
  }
  if (!provider) {
    return { error: 'No provider configured. Set OPENAI_API_KEY or use Workers AI (AI binding).' };
  }

  const prompt = String(params.prompt || '').trim();
  if (!prompt) return { error: 'prompt required' };
  const filename = String(params.filename || 'imgx').trim() || 'imgx';
  const size = String(params.size || '1024x1024').trim() || '1024x1024';

  const workersAiProvider =
    provider === 'gemini' || provider === 'google' || provider === 'imagen' || provider === 'cf';
  if (toolName === 'imgx_edit_image' && workersAiProvider) {
    return { error: 'imgx_edit_image supports provider=openai only. Use imgx_generate_image with provider=gemini, google, imagen, or cf for Workers AI text-to-image.' };
  }

  if (workersAiProvider) {
    try {
      if (toolName !== 'imgx_generate_image') {
        return { error: `Unsupported IMGX tool for provider=${provider}: ${toolName}` };
      }
      if (!env.AI) return { error: 'Workers AI binding (AI) not configured' };
      const result = await env.AI.run(
        '@cf/stabilityai/stable-diffusion-xl-base-1.0',
        { prompt: String(params.prompt || '').trim() },
      );
      let imageData = null;
      if (result instanceof ReadableStream) {
        imageData = await new Response(result).arrayBuffer();
      } else if (result && typeof result === 'object' && result.image != null) {
        const img = result.image;
        if (img instanceof ArrayBuffer) imageData = img;
        else if (img instanceof Uint8Array) {
          imageData = img.buffer.slice(img.byteOffset, img.byteOffset + img.byteLength);
        }
      } else if (result instanceof Uint8Array) {
        imageData = result.buffer.slice(result.byteOffset, result.byteOffset + result.byteLength);
      } else if (result instanceof ArrayBuffer) {
        imageData = result;
      }
      if (!imageData || imageData.byteLength === 0) {
        return { error: 'Workers AI image generation failed' };
      }
      const key = 'generated/imgx/imgx-' + crypto.randomUUID() + '.png';
      const bucket = env.DOCS_BUCKET || env.DASHBOARD;
      if (!bucket) return { error: 'No R2 bucket for image storage' };
      await bucket.put(key, imageData, { httpMetadata: { contentType: 'image/png' } });
      const image_url = 'https://docs.inneranimalmedia.com/' + key;
      await insertAiGenerationLog(env, {
        generationType: 'imgx_workers_ai_generate',
        prompt,
        model: '@cf/stabilityai/stable-diffusion-xl-base-1.0',
        responseText: image_url,
        metadataJson: {
          r2_key: key,
          bucket: env.DOCS_BUCKET ? 'DOCS_BUCKET' : 'DASHBOARD',
          tool: 'imgx_generate_image',
          provider: 'cloudflare',
          byte_length: imageData.byteLength ?? imageData.length ?? 0,
        },
      });
      try {
        let rates = ctx.modelRates;
        if (!rates && env.DB) {
          try {
            rates = await loadAiModelRatesMap(env);
          } catch (_) {
            rates = {};
          }
        }
        let wIn = 0;
        let wOut = 0;
        if (result && typeof result === 'object' && result.usage) {
          wIn = Math.floor(Number(result.usage.prompt_tokens) || 0);
          wOut = Math.floor(Number(result.usage.completion_tokens) || 0);
        }
        await writeTelemetry(
          env,
          {
            sessionId: ctx.conversationId || null,
            tenantId: resolveTelemetryTenantId(env, ctx.tenantId),
            provider: 'workers_ai',
            model: '@cf/stabilityai/stable-diffusion-xl-base-1.0',
            inputTokens: wIn,
            outputTokens: wOut,
            success: true,
            toolCallCount: 1,
            toolNamesUsed: [toolName],
          },
          rates || {}
        );
      } catch (_) { }
      return {
        ok: true,
        image_url,
        key,
        model: 'stable-diffusion-xl-base-1.0',
        provider: 'cloudflare',
      };
    } catch (e) {
      return { error: String(e.message || e) };
    }
  }

  if (provider !== 'openai') {
    return { error: `Unsupported provider "${provider}". Use openai or gemini/google/imagen/cf (Workers AI, generate only).` };
  }
  if (!hasOpenai) return { error: 'OPENAI_API_KEY not configured' };

  if (toolName === 'imgx_generate_image') {
    const model = String(params.model || 'dall-e-3');
    const payload = {
      model: model,
      prompt: prompt,
      size: ['1024x1024', '1024x1792', '1792x1024'].includes(size) ? size : '1024x1024',
    };
    const res = await fetch('https://api.openai.com/v1/images/generations', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${env.OPENAI_API_KEY}`,
      },
      body: JSON.stringify(payload),
      signal: AbortSignal.timeout(30000),
    });
    const data = await res.json().catch(() => ({}));
    if (!res.ok) return { error: data?.error?.message || 'OpenAI image generation failed' };
    const imageUrl = typeof data?.data?.[0]?.url === 'string' ? data.data[0].url.trim() : '';
    let bytes = null;
    if (imageUrl) {
      try {
        const imgRes = await fetch(imageUrl, { signal: AbortSignal.timeout(60000) });
        if (imgRes.ok) {
          const ab = await imgRes.arrayBuffer();
          bytes = new Uint8Array(ab);
        }
      } catch (_) { }
    }
    if (!bytes || !bytes.length) {
      const b64 = data?.data?.[0]?.b64_json;
      if (b64 && typeof b64 === 'string') {
        try {
          bytes = Uint8Array.from(atob(b64), c => c.charCodeAt(0));
        } catch (_) {
          bytes = null;
        }
      }
    }
    if (!bytes || !bytes.length) return { error: 'No image data returned by provider' };
    const stored = await uploadImgxToDashboard(env, bytes, 'image/png', filename, {
      generationType: 'imgx_openai_generate',
      prompt,
      model: String(params.model || 'dall-e-3'),
      metadata: { tool: 'imgx_generate_image', provider: 'openai' },
    });
    if (!stored.ok) return { error: stored.error || 'Image storage failed' };
    try {
      let rates = ctx.modelRates;
      if (!rates && env.DB) {
        try {
          rates = await loadAiModelRatesMap(env);
        } catch (_) {
          rates = {};
        }
      }
      const mdl = String(params.model || 'dall-e-3');
      await writeTelemetry(
        env,
        {
          sessionId: ctx.conversationId || null,
          tenantId: resolveTelemetryTenantId(env, ctx.tenantId),
          provider: 'openai',
          model: mdl,
          inputTokens: 0,
          outputTokens: 0,
          success: true,
          toolCallCount: 1,
          toolNamesUsed: [toolName],
        },
        rates || {}
      );
    } catch (_) { }
    return { ok: true, provider: 'openai', model: String(params.model || 'dall-e-3'), image_url: stored.url, key: stored.key };
  }

  if (toolName === 'imgx_edit_image') {
    const inputUrl = String(params.input_url || '').trim();
    if (!inputUrl) return { error: 'input_url required for imgx_edit_image' };
    const source = await fetch(inputUrl);
    if (!source.ok) return { error: `Failed to fetch input_url (${source.status})` };
    const sourceBytes = await source.arrayBuffer();
    const sourceType = source.headers.get('content-type') || 'image/png';
    const fd = new FormData();
    fd.append('model', String(params.model || 'dall-e-3'));
    fd.append('prompt', prompt);
    fd.append('size', size);
    fd.append('response_format', 'b64_json');
    fd.append('image', new Blob([sourceBytes], { type: sourceType }), 'input.png');
    const res = await fetch('https://api.openai.com/v1/images/edits', {
      method: 'POST',
      headers: { 'Authorization': `Bearer ${env.OPENAI_API_KEY}` },
      body: fd,
      signal: AbortSignal.timeout(30000),
    });
    const data = await res.json().catch(() => ({}));
    if (!res.ok) return { error: data?.error?.message || 'OpenAI image edit failed' };
    let b64 = data?.data?.[0]?.b64_json;
    let bytes = null;
    if (b64) {
      try {
        bytes = Uint8Array.from(atob(b64), c => c.charCodeAt(0));
      } catch (_) {
        bytes = null;
      }
    }
    const editUrl = typeof data?.data?.[0]?.url === 'string' ? data.data[0].url.trim() : '';
    if ((!bytes || !bytes.length) && editUrl) {
      try {
        const imgRes = await fetch(editUrl, { signal: AbortSignal.timeout(60000) });
        if (imgRes.ok) {
          const ab = await imgRes.arrayBuffer();
          bytes = new Uint8Array(ab);
        }
      } catch (_) { }
    }
    if (!bytes || !bytes.length) return { error: 'No edited image data returned by provider' };
    const stored = await uploadImgxToDashboard(env, bytes, 'image/png', filename + '-edit', {
      generationType: 'imgx_openai_edit',
      prompt,
      model: String(params.model || 'dall-e-3'),
      metadata: { tool: 'imgx_edit_image', provider: 'openai' },
    });
    if (!stored.ok) return { error: stored.error || 'Image storage failed' };
    return { ok: true, provider: 'openai', model: String(params.model || 'dall-e-3'), image_url: stored.url, key: stored.key };
  }

  return { error: `Unsupported IMGX tool: ${toolName}` };
}

function cloudconvertCollectTasksFromJob(data) {
  const tasks = data?.tasks;
  if (Array.isArray(tasks)) return tasks;
  if (tasks && typeof tasks === 'object') return Object.values(tasks);
  return [];
}

function cloudconvertExtractExportFromJob(data) {
  for (const t of cloudconvertCollectTasksFromJob(data)) {
    if (String(t?.operation) !== 'export/url') continue;
    if (t.status && t.status !== 'finished') continue;
    const files = t.result?.files || t.result?.form?.files;
    const arr = Array.isArray(files) ? files : [];
    const first = arr[0];
    if (first?.url) return { url: first.url, filename: first.filename ?? null };
  }
  return { url: null, filename: null };
}

async function runCloudConvertBuiltinTool(env, toolName, params) {
  const apiKey = env.CLOUDCONVERT_API_KEY;
  if (!apiKey) return { error: 'CLOUDCONVERT_API_KEY not configured' };

  if (toolName === 'cloudconvert_get_job') {
    const jobId = String(params.job_id ?? params.id ?? '').trim();
    if (!jobId) return { error: 'job_id required' };
    const res = await fetch(`https://api.cloudconvert.com/v2/jobs/${encodeURIComponent(jobId)}`, {
      headers: { Authorization: `Bearer ${apiKey}` },
    });
    const body = await res.json().catch(() => ({}));
    if (!res.ok) {
      return { error: body?.message || body?.errors?.[0]?.message || `CloudConvert ${res.status}` };
    }
    const data = body.data ?? body;
    const { url: output_url, filename: output_filename } = cloudconvertExtractExportFromJob(data);
    return {
      status: data.status,
      output_url,
      output_filename,
      finished_at: data.finished_at ?? data.ended_at ?? null,
    };
  }

  if (toolName !== 'cloudconvert_create_job') return { error: `Unknown CloudConvert tool: ${toolName}` };

  const input_url = String(params.input_url ?? '').trim();
  const input_format = String(params.input_format ?? '').trim();
  const output_format = String(params.output_format ?? '').trim();
  if (!input_url || !input_format || !output_format) {
    return { error: 'input_url, input_format, and output_format are required' };
  }
  const tasks = {
    import: { operation: 'import/url', url: input_url },
    convert: { operation: 'convert', input: 'import', input_format, output_format },
    export: { operation: 'export/url', input: 'convert' },
  };
  const createRes = await fetch('https://api.cloudconvert.com/v2/jobs', {
    method: 'POST',
    headers: { Authorization: `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ tasks }),
  });
  const createBody = await createRes.json().catch(() => ({}));
  if (!createRes.ok) {
    return { error: createBody?.message || createBody?.errors?.[0]?.message || `CloudConvert create ${createRes.status}` };
  }
  const data = createBody.data ?? createBody;
  const job_id = data.id;
  const status = data.status;
  const created_at = data.created_at ?? data.inserted_at ?? null;

  const output_r2_key = params.output_r2_key != null ? String(params.output_r2_key).trim() : '';
  if (!output_r2_key) {
    return { job_id, status, created_at };
  }
  if (!env.DASHBOARD) {
    return { job_id, status, created_at, r2_error: 'DASHBOARD bucket not configured' };
  }

  const maxWaitSec = Math.min(300, Math.max(30, Number(params.poll_timeout_sec) || 120));
  const deadline = Date.now() + maxWaitSec * 1000;
  let last = data;
  while (Date.now() < deadline) {
    await new Promise((r) => setTimeout(r, 2000));
    const pollRes = await fetch(`https://api.cloudconvert.com/v2/jobs/${encodeURIComponent(job_id)}`, {
      headers: { Authorization: `Bearer ${apiKey}` },
    });
    const pollBody = await pollRes.json().catch(() => ({}));
    last = pollBody.data ?? pollBody;
    const st = last.status;
    if (st === 'finished' || st === 'error' || st === 'failed') break;
  }
  const { url: outUrl } = cloudconvertExtractExportFromJob(last);
  if (!outUrl) {
    return { job_id, status: last.status, created_at, r2_upload: 'skipped', reason: 'export URL not ready' };
  }
  const fileRes = await fetch(outUrl);
  if (!fileRes.ok) return { error: `Failed to download export (${fileRes.status})` };
  const buf = await fileRes.arrayBuffer();
  const ct = fileRes.headers.get('content-type') || 'application/octet-stream';
  await env.DASHBOARD.put(output_r2_key, buf, { httpMetadata: { contentType: ct } });
  await insertAiGenerationLog(env, {
    generationType: 'cloudconvert_file_export',
    model: `cloudconvert:${String(params.output_format || '').trim() || 'unknown'}`,
    responseText: output_r2_key,
    metadataJson: {
      tool: 'cloudconvert_create_job',
      job_id,
      output_r2_key,
      content_type: ct,
      byte_length: buf.byteLength,
    },
  });
  return { job_id, status: last.status, created_at, output_r2_key };
}

async function runMeshyBuiltinTool(env, toolName, params) {
  const apiKey = env.MESHYAI_API_KEY;
  if (!apiKey) return { error: 'MESHYAI_API_KEY not configured' };

  if (toolName === 'meshyai_text_to_3d') {
    const prompt = String(params.prompt ?? '').trim();
    if (!prompt) return { error: 'prompt required' };
    const res = await fetch('https://api.meshy.ai/v2/text-to-3d', {
      method: 'POST',
      headers: { Authorization: `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        mode: 'preview',
        prompt,
        art_style: params.art_style || 'realistic',
        negative_prompt: params.negative_prompt || '',
        topology: 'quad',
        target_polycount: 30000,
      }),
    });
    const body = await res.json().catch(() => ({}));
    if (!res.ok) return { error: body?.message || body?.error || JSON.stringify(body).slice(0, 200) || `Meshy ${res.status}` };
    const task_id = body.result ?? body.task_id ?? body.id ?? body.data?.task_id ?? body.data?.id;
    return { task_id };
  }

  if (toolName === 'meshyai_image_to_3d') {
    const image_url = String(params.image_url ?? '').trim();
    if (!image_url) return { error: 'image_url required' };
    const res = await fetch('https://api.meshy.ai/v2/image-to-3d', {
      method: 'POST',
      headers: { Authorization: `Bearer ${apiKey}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        image_url,
        output_format: params.output_format || 'glb',
        topology: params.topology || 'quad',
      }),
    });
    const body = await res.json().catch(() => ({}));
    if (!res.ok) return { error: body?.message || body?.error || JSON.stringify(body).slice(0, 200) || `Meshy ${res.status}` };
    const task_id = body.result ?? body.task_id ?? body.id ?? body.data?.task_id ?? body.data?.id;
    return { task_id };
  }

  if (toolName === 'meshyai_get_task') {
    const task_id = String(params.task_id ?? params.id ?? '').trim();
    if (!task_id) return { error: 'task_id required' };
    let res = await fetch(`https://api.meshy.ai/v2/text-to-3d/${encodeURIComponent(task_id)}`, {
      headers: { Authorization: `Bearer ${apiKey}` },
    });
    if (res.status === 404) {
      res = await fetch(`https://api.meshy.ai/v2/image-to-3d/${encodeURIComponent(task_id)}`, {
        headers: { Authorization: `Bearer ${apiKey}` },
      });
    }
    const body = await res.json().catch(() => ({}));
    if (!res.ok) return { error: body?.message || body?.error || `Meshy get ${res.status}` };
    const d = body.result && typeof body.result === 'object' ? body.result : body;
    const status = d.status ?? d.task_status ?? body.status;
    const progress = d.progress ?? d.progress_percent ?? body.progress;
    const model_urls = d.model_urls ?? d.modelUrls ?? {};
    const out = { status, progress, model_urls };
    const r2_key = params.r2_key != null ? String(params.r2_key).trim() : '';
    const stNorm = String(status || '').toUpperCase();
    if (stNorm === 'SUCCEEDED' && r2_key && env.AUTORAG_BUCKET) {
      const glbUrl = model_urls && typeof model_urls === 'object' ? (model_urls.glb || model_urls.GLB) : null;
      if (glbUrl) {
        const f = await fetch(glbUrl);
        if (f.ok) {
          const buf = await f.arrayBuffer();
          const meshyKey = r2_key.startsWith('meshy/') ? r2_key : `meshy/${r2_key}`;
          await env.AUTORAG_BUCKET.put(meshyKey, buf, { httpMetadata: { contentType: 'model/gltf-binary' } });
          out.r2_key = meshyKey;
          await insertAiGenerationLog(env, {
            generationType: 'meshy_3d_glb_export',
            model: 'meshy_api',
            responseText: meshyKey,
            metadataJson: {
              tool: 'meshyai_get_task',
              task_id,
              r2_key: meshyKey,
              glb_url: glbUrl,
              byte_length: buf.byteLength,
              bucket: 'AUTORAG_BUCKET',
            },
            relatedIdsJson: [task_id, meshyKey],
          });
        }
      }
    }
    return out;
  }

  return { error: `Unknown Meshy tool: ${toolName}` };
}

async function handleMeshyLatestGet(env) {
  if (!env.AUTORAG_BUCKET) return jsonResponse({ url: null, filename: null, error: 'AUTORAG_BUCKET not configured' }, 503);
  try {
    const list = await env.AUTORAG_BUCKET.list({ prefix: 'meshy/', limit: 100 });
    const objects = (list.objects || []).slice().sort((a, b) => new Date(b.uploaded).getTime() - new Date(a.uploaded).getTime());
    if (!objects.length) return jsonResponse({ url: null, filename: null });
    const latest = objects[0];
    const obj = await env.AUTORAG_BUCKET.get(latest.key);
    if (!obj) return jsonResponse({ url: null, filename: null });
    const arrayBuffer = await obj.arrayBuffer();
    const bytes = new Uint8Array(arrayBuffer);
    let binary = '';
    const chunk = 0x8000;
    for (let i = 0; i < bytes.length; i += chunk) {
      binary += String.fromCharCode.apply(null, bytes.subarray(i, i + chunk));
    }
    const b64 = btoa(binary);
    return jsonResponse({
      url: `data:model/gltf-binary;base64,${b64}`,
      filename: latest.key.split('/').pop(),
      key: latest.key,
    });
  } catch (e) {
    return jsonResponse({ url: null, error: e?.message ?? String(e) });
  }
}

/** Per-intent default max tool iterations when D1 `agentsam_ai.model_policy_json.max_tool_loop` is unset. */
const INTENT_LOOP_MAX_BY_INTENT = {
  mixed: 5,
  question: 3,
  deployment: 15,
  problem_solving: 20,
  write_migration: 8,
  generate_ui: 12,
  intent_build: 20,
  analyze_r2: 8,
  shell: 15,
};
const INTENT_LOOP_MAX_DEFAULT = 10;

/**
 * Max Anthropic tool loop iterations: caller opts > per-agent D1 > per-intent map > global default.
 * @param {{ maxToolLoop?: number, _intent?: string }} opts
 * @param {Record<string, unknown>|null} modelPolicyJson
 * @param {string} intentKey
 */
function resolveMaxToolLoop(opts, modelPolicyJson, intentKey) {
  if (opts && typeof opts.maxToolLoop === 'number' && Number.isFinite(opts.maxToolLoop) && opts.maxToolLoop > 0) {
    return Math.min(100, Math.max(1, Math.floor(opts.maxToolLoop)));
  }
  if (modelPolicyJson && typeof modelPolicyJson === 'object' && !Array.isArray(modelPolicyJson)) {
    const v = modelPolicyJson.max_tool_loop;
    if (typeof v === 'number' && Number.isFinite(v) && v > 0) {
      return Math.min(100, Math.max(1, Math.floor(v)));
    }
  }
  const fromIntent = INTENT_LOOP_MAX_BY_INTENT[intentKey];
  if (typeof fromIntent === 'number' && fromIntent > 0) {
    return Math.min(100, Math.max(1, fromIntent));
  }
  return INTENT_LOOP_MAX_DEFAULT;
}

function enqueueAgentChatDoPersist(env, ctx, conversationId, modelKey, assistantContent, inputTokens, outputTokens) {
  if (!ctx || typeof ctx.waitUntil !== 'function' || !env.AGENT_SESSION || !conversationId) return;
  const _doPersistId = env.AGENT_SESSION.idFromName(String(conversationId));
  const _doPersist = env.AGENT_SESSION.get(_doPersistId);
  const _modelKeyPersist = modelKey || '';
  ctx.waitUntil(
    _doPersist.fetch(new Request('https://do/message', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        role: 'assistant',
        content: assistantContent || '',
        model_used: _modelKeyPersist,
        input_tokens: inputTokens,
        output_tokens: outputTokens,
        rag_chunks_injected: 0,
        top_rag_score: 0,
      }),
    })).catch((e) => console.warn('[chatWithToolsAnthropic] DO message persist', e?.message ?? e)),
  );
}

/**
 * One aggregate agent_telemetry row per completed chat turn (after tool loop / stream done).
 * Does not replace per-iteration writeTelemetry (metric_name llm_turn); this row uses metric_name llm_call.
 * cost_breakdown_json / workspace_id / agent_id live in metadata_json (no extra D1 columns in baseline schema).
 */
/**
 * Inserts metric_name llm_call into agent_telemetry. Prefer ctx.waitUntil so the write survives
 * after the HTTP response finishes; if waitUntil is missing, returns a Promise callers should await
 * when they are already in an async continuation (e.g. SSE tool-loop .then).
 */
function enqueueAgentTelemetryFinalLlmCall(env, ctx, {
  conversationId,
  provider,
  modelKey,
  modelRow,
  routingOpts,
  inputTokens,
  outputTokens,
  cacheReadTokens = 0,
  cacheWriteTokens = 0,
  agentId,
  agentRunId,
}) {
  if (!env?.DB) return undefined;
  const tenantId = tenantIdFromEnv(env) || 'unknown';
  const workspaceId = tenantIdFromEnv(env) || null;

  const run = async () => {
    try {
      let ratesMap = routingOpts && routingOpts.modelRates ? { ...routingOpts.modelRates } : {};
      const mk = String(modelKey || '');
      if (!ratesMap[mk] && modelRow) ratesMap[mk] = modelRow;
      if (!ratesMap[mk] && env.DB) {
        try {
          const loaded = await loadAiModelRatesMap(env);
          ratesMap = { ...loaded, ...ratesMap };
        } catch (_) { }
      }
      const row = ratesMap[mk] || modelRow;
      const tin = Math.floor(Number(inputTokens) || 0);
      const tout = Math.floor(Number(outputTokens) || 0);
      const crd = Math.floor(Number(cacheReadTokens) || 0);
      const cwd = Math.floor(Number(cacheWriteTokens) || 0);
      const computedCostUsd = computeUsdFromModelRatesRow(mk, row, tin, tout, crd, cwd);
      const costBreakdown = { input: tin, output: tout, cache_read: crd, cache_write: cwd };
      const metaObj = {
        kind: 'llm_call_final',
        cost_breakdown: costBreakdown,
        cost_breakdown_json: JSON.stringify(costBreakdown),
        agent_id: agentId ?? null,
        workspace_id: workspaceId,
        agent_run_id: agentRunId ?? null,
        routing_decision_id: routingOpts?.routingDecisionId ?? null,
      };
      const totIn = tin + crd + cwd;
      const id = crypto.randomUUID();
      const ts = Math.floor(Date.now() / 1000);
      // agent_telemetry: 20 columns = 18 ? + unixepoch(created_at) + unixepoch(updated_at); .bind must supply 18 values.
      await env.DB.prepare(
        `INSERT INTO agent_telemetry (
          id, tenant_id, session_id, metric_type, metric_name, metric_value, timestamp, metadata_json,
          model_used, provider, input_tokens, output_tokens,
          cache_read_input_tokens, cache_creation_input_tokens,
          computed_cost_usd, total_input_tokens,
          event_type, severity, created_at, updated_at
        ) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,unixepoch(),unixepoch())`
      ).bind(
        id,
        tenantId,
        conversationId != null ? String(conversationId) : null,
        'usage_count',
        'llm_call',
        1,
        ts,
        JSON.stringify(metaObj),
        mk,
        String(provider || 'unknown'),
        tin,
        tout,
        crd,
        cwd,
        Number.isFinite(Number(computedCostUsd)) ? Number(computedCostUsd) : 0,
        totIn,
        'chat',
        'info',
      ).run();
    } catch (e) {
      console.warn('[enqueueAgentTelemetryFinalLlmCall]', e?.message ?? e);
    }
  };

  if (ctx && typeof ctx.waitUntil === 'function') {
    ctx.waitUntil(run());
    return undefined;
  }
  return run();
}

/** OpenAI chat completions with tools; runs tool_calls loop. When opts.stream is true, returns SSE stream matching Anthropic contract. */
async function chatWithToolsOpenAI(env, systemWithBlurb, apiMessages, model, conversationId, agent_id, ctx, opts = {}, preFilteredTools = null) {
  const wantStream = opts.stream === true;
  const mode = opts.mode || 'agent';

  let resolvedAllowedToolGlobs = opts.allowed_tool_globs;
  if (
    (resolvedAllowedToolGlobs == null || String(resolvedAllowedToolGlobs).trim() === '') &&
    opts.oauthUserId
  ) {
    const sk =
      opts.subagent_id != null && String(opts.subagent_id).trim() !== ''
        ? String(opts.subagent_id).trim()
        : opts.agent_id != null && String(opts.agent_id).trim() !== ''
          ? String(opts.agent_id).trim()
          : '';
    if (sk) {
      const loaded = await loadSubagentAllowedToolGlobs(env, opts.oauthUserId, sk);
      if (loaded != null) resolvedAllowedToolGlobs = loaded;
    }
  }

  let tools = [];
  try {
    if (preFilteredTools && Array.isArray(preFilteredTools) && preFilteredTools.length > 0) {
      tools = preFilteredTools.map((t) => {
        let rawSchema = t.input_schema || {};
        if (typeof rawSchema === 'string') {
          try {
            rawSchema = JSON.parse(rawSchema);
          } catch (_) {
            rawSchema = {};
          }
        }
        let input_schema;
        if (rawSchema && rawSchema.type === 'object' && rawSchema.properties) {
          input_schema = rawSchema;
        } else {
          input_schema = { type: 'object', properties: {}, required: [] };
        }
        return { name: t.name || t.tool_name, description: (t.description || t.name || '').slice(0, 500), input_schema };
      });
    } else {
      const r = await env.DB.prepare(
        `SELECT tool_name, description, input_schema, tool_category FROM mcp_registered_tools WHERE enabled = 1
         AND (modes_json LIKE '%"' || ? || '"%')
         AND is_degraded = 0
         ORDER BY tool_name`
      )
        .bind(mode)
        .all();
      const filtered = filterToolRowsByPanel(agent_id, r.results || []);
      const modeFiltered = filterToolsByMode(mode, filtered.map((t) => ({ name: t.tool_name, ...t })));
      const modeFilteredNames = new Set(modeFiltered.map((t) => t.tool_name || t.name));
      const filteredByMode = filtered.filter((t) => modeFilteredNames.has(t.tool_name));
      tools = filteredByMode.map((t) => {
        let rawSchema = {};
        try {
          rawSchema = typeof t.input_schema === 'string' ? JSON.parse(t.input_schema) : (t.input_schema || {});
        } catch (_) { }
        let input_schema;
        if (rawSchema && rawSchema.type === 'object' && rawSchema.properties) {
          input_schema = rawSchema;
        } else {
          const properties = {};
          const required = [];
          for (const [key, val] of Object.entries(rawSchema)) {
            if (key === 'type' || key === 'properties' || key === 'required') continue;
            properties[key] = {
              type: (val && val.type) || 'string',
              ...(val && val.items && { items: val.items }),
              ...(val && val.description && { description: val.description }),
              ...(val && val.enum && { enum: val.enum }),
            };
            if (val && val.required) required.push(key);
          }
          input_schema = { type: 'object', properties: Object.keys(properties).length ? properties : {}, required };
        }
        return {
          name: t.tool_name,
          description: (t.description || t.tool_name).slice(0, 500),
          input_schema,
        };
      });
    }
    if (mode === 'agent') {
      const SYNTHETIC_DASHBOARD_TOOLS = [
        {
          name: 'preview_in_browser',
          description:
            'Open a URL in the dashboard browser tab. Pass url directly, or r2Key with optional bucket (default ASSETS for sandbox preview). Public ASSETS URLs use agent_configs slug r2_public_urls.',
          input_schema: {
            type: 'object',
            properties: {
              url: { type: 'string', description: 'Full https URL to open in the embedded browser' },
              r2Key: { type: 'string', description: 'R2 object key; combined with bucket to build public URL' },
              bucket: { type: 'string', description: 'Binding: ASSETS (default), DASHBOARD, DOCS_BUCKET, AUTORAG_BUCKET, agent-sam-sandbox-cicd' },
            },
          },
        },
        {
          name: 'get_r2_url',
          description: 'Return the public HTTPS URL for an R2 object (bucket binding name + key). ASSETS uses agent_configs slug r2_public_urls.',
          input_schema: {
            type: 'object',
            properties: {
              bucket: { type: 'string', description: 'Binding: ASSETS, DASHBOARD, DOCS_BUCKET, AUTORAG_BUCKET, agent-sam-sandbox-cicd (default DASHBOARD)' },
              key: { type: 'string', description: 'Object key path' },
            },
            required: ['key'],
          },
        },
      ];
      const have = new Set(tools.map((t) => t.name));
      for (const s of SYNTHETIC_DASHBOARD_TOOLS) {
        if (!have.has(s.name)) {
          tools.push(s);
          have.add(s.name);
        }
      }
    }
    if (tools.length > 0) {
      try {
        const tenantForIntent =
          (opts.routingOpts && opts.routingOpts.tenantId != null && String(opts.routingOpts.tenantId).trim()) ||
          (env.TENANT_ID ? String(env.TENANT_ID).trim() : null) ||
          null;
        const lastUserForIntent = getLastUserMessageText(apiMessages) || '';
        const intentForFilter = opts._intent || 'auto';
        tools = await filterToolsByIntent(env, tenantForIntent, intentForFilter, lastUserForIntent, tools);
      } catch (e) {
        console.warn('[chatWithToolsOpenAI] filterToolsByIntent', e?.message ?? e);
      }
      if (resolvedAllowedToolGlobs != null && parseMixedToolAllowList(resolvedAllowedToolGlobs).length > 0) {
        tools = filterToolsByAllowPatterns(tools, resolvedAllowedToolGlobs);
      }
    }
  } catch (e) {
    console.error('[chatWithToolsOpenAI] tool load failed:', e?.message ?? e);
  }
  if (tools.length === 0 && !preFilteredTools) return null;

  const intentForLoop = opts._intent || 'mixed';
  let modelPolicyJson = null;
  if (env.DB && agent_id) {
    try {
      const ar = await env.DB.prepare('SELECT model_policy_json FROM agentsam_ai WHERE id = ? LIMIT 1').bind(agent_id).first();
      if (ar?.model_policy_json != null) {
        const raw = ar.model_policy_json;
        modelPolicyJson = typeof raw === 'string' ? JSON.parse(raw) : raw;
      }
    } catch (e) {
      console.warn('[chatWithToolsOpenAI] agentsam_ai.model_policy_json', e?.message ?? e);
    }
  }
  const maxToolLoopResolved = resolveMaxToolLoop(opts, modelPolicyJson, intentForLoop);
  const hasWorkspaceTools = tools.some((t) => t && /^workspace_/.test(t.name));
  const systemWithWorkspaceHint = hasWorkspaceTools
    ? `${systemWithBlurb}\n\n## Workspace (PTY host repo)\nUse workspace_read_file to read any file by path when the user references a file not already in context. Use workspace_list_files to explore the repo. Use workspace_search to find symbol definitions, usages, or patterns across the codebase.`
    : systemWithBlurb;

  const openaiTools = tools.map((t) => ({
    type: 'function',
    function: {
      name: t.name,
      description: t.description,
      parameters: t.input_schema,
    },
  }));

  const mapUserContent = (m) => m.content;
  const baseUserMsgs = apiMessages.map((m) => ({ role: m.role, content: mapUserContent(m) }));
  let messages = [{ role: 'system', content: systemWithWorkspaceHint }, ...baseUserMsgs];

  const TOOL_DISPLAY = {
    terminal_execute: 'terminal',
    workspace_read_file: 'filesystem',
    workspace_list_files: 'filesystem',
    workspace_search: 'filesystem',
    d1_query: 'D1 database',
    d1_write: 'D1 database',
    r2_read: 'file',
    r2_write: 'file',
    preview_in_browser: 'browser',
    get_r2_url: 'file',
    agentsam_run_agent: 'agentsam_run_agent',
    agentsam_get_agent: 'agentsam_get_agent',
    agentsam_list_agents: 'agentsam_list_agents',
    github_fetch: 'GitHub',
    web_search: 'web',
    deploy_worker: 'deploy',
    excalidraw_open: 'excalidraw',
    excalidraw_add_elements: 'excalidraw',
    excalidraw_load_library: 'excalidraw',
    excalidraw_export: 'excalidraw',
    excalidraw_clear: 'excalidraw',
  };

  let iter = 0;
  let lastContent = '';
  let lastUsage = { input_tokens: 0, output_tokens: 0, cache_read_input_tokens: 0, cache_write_input_tokens: 0 };
  const allToolCalls = [];
  const pendingStateEvents = [];
  const encoder = new TextEncoder();
  const enqueue = (controller, obj) => {
    controller.enqueue(encoder.encode('data: ' + JSON.stringify(obj) + '\n\n'));
  };
  const flushPendingToolStates = (controller) => {
    for (const evt of pendingStateEvents) enqueue(controller, evt);
    pendingStateEvents.length = 0;
  };

  let _streamWriter = null;
  let _streamEnc = null;
  let _streamResponse = null;
  if (wantStream) {
    const { readable, writable } = new TransformStream();
    _streamEnc = new TextEncoder();
    _streamWriter = writable.getWriter();
    opts.streamWriter = _streamWriter;
    opts.streamEnc = _streamEnc;
    _streamResponse = new Response(readable, { headers: { 'Content-Type': 'text/event-stream', 'Cache-Control': 'no-cache' } });
  }

  const _runLoop = async () => {
    while (iter < maxToolLoopResolved) {
      iter++;
      const res = await fetch('https://api.openai.com/v1/chat/completions', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${env.OPENAI_API_KEY}`,
        },
        body: JSON.stringify({
          model: model.model_key,
          ...(model.model_key.startsWith("gpt-5") || model.model_key.startsWith("o") ? { max_completion_tokens: 8192 } : { max_tokens: 8192 }),
          messages,
          tools: openaiTools,
          tool_choice: 'auto',
        }),
      });
      if (!res.ok) {
        const err = await res.json().catch(() => ({}));
        const errMsg = err.error?.message || err.message || res.statusText;
        if (wantStream && _streamWriter) {
          try {
            await _streamWriter.write(_streamEnc.encode(`data: ${JSON.stringify({ type: 'error', error: errMsg })}\n\n`));
          } catch (_) { }
          return new Response(null, { status: 200 });
        }
        return jsonResponse({ error: errMsg, stream: false }, res.status);
      }
      const data = await res.json();
      const choice = data.choices?.[0];
      const assistantMsg = choice?.message;
      const toolCalls = assistantMsg?.tool_calls || [];
      const u = data.usage || {};
      const ptd = u.prompt_tokens_details;
      const cachedTok = ptd && typeof ptd === 'object' && typeof ptd.cached_tokens === 'number' ? ptd.cached_tokens : 0;
      lastUsage = {
        input_tokens: u.prompt_tokens ?? 0,
        output_tokens: u.completion_tokens ?? 0,
        cache_read_input_tokens: cachedTok,
        cache_write_input_tokens: 0,
      };
      if (env.DB) {
        try {
          let openaiRates = opts.modelRates;
          if (!openaiRates) {
            try {
              openaiRates = await loadAiModelRatesMap(env);
            } catch (_) {
              openaiRates = {};
            }
          }
          await writeTelemetry(
            env,
            {
              sessionId: conversationId,
              tenantId: resolveTelemetryTenantId(env, opts.routingOpts?.tenantId),
              provider: 'openai',
              model: model.model_key,
              inputTokens: lastUsage.input_tokens,
              outputTokens: lastUsage.output_tokens,
              cacheReadTokens: lastUsage.cache_read_input_tokens,
              cacheWriteTokens: 0,
              success: true,
              routingDecisionId: opts.routingOpts?.routingDecisionId,
              agentRunId: opts.agentsamAgentRunId,
            },
            openaiRates,
          );
        } catch (_) { }
      }

      const textContent = typeof assistantMsg?.content === 'string' ? assistantMsg.content : '';
      lastContent = textContent || lastContent;
      if (wantStream && _streamWriter && textContent) {
        try {
          await _streamWriter.write(_streamEnc.encode('data: ' + JSON.stringify({ type: 'text', text: textContent }) + '\n\n'));
        } catch (_) { }
      }

      if (mode === 'ask' && toolCalls.length > 0) {
        const actionTc = toolCalls.find((tc) => tc.function && isActionTool(tc.function.name));
        if (actionTc) {
          const name = actionTc.function.name;
          let params = {};
          try {
            const fa = actionTc.function.arguments;
            if (fa != null && String(fa).trim() !== '') params = JSON.parse(fa);
          } catch (_) { }
          const toolDesc = (tools.find((t) => t.name === name) || {}).description || name;
          const preview = toolApprovalPreview(name, params);
          if (wantStream) {
            const streamBody = new ReadableStream({
              start(controller) {
                flushPendingToolStates(controller);
                enqueue(controller, { type: 'text', text: lastContent });
                emitCodeBlocksFromText(lastContent, (obj) => enqueue(controller, obj));
                enqueue(controller, {
                  type: 'tool_approval_request',
                  tool: {
                    name,
                    description: toolDesc,
                    parameters: params,
                    preview,
                  },
                });
                enqueue(controller, { type: 'done', usage: lastUsage });
                controller.close();
              },
            });
            return new Response(streamBody, { headers: { 'Content-Type': 'text/event-stream' } });
          }
          return jsonResponse({
            tool_approval_request: true,
            text: lastContent,
            tool: { name, description: toolDesc, parameters: params, preview },
            conversation_id: conversationId,
          });
        }
      }

      if (toolCalls.length === 0) {
        const inputTokens = lastUsage.input_tokens;
        const outputTokens = lastUsage.output_tokens;
        const costUsd = calculateCost(model, inputTokens, outputTokens);
        if (wantStream) {
          try {
            for (const evt of pendingStateEvents) {
              await _streamWriter.write(_streamEnc.encode('data: ' + JSON.stringify(evt) + '\n\n'));
            }
            pendingStateEvents.length = 0;
            emitCodeBlocksFromText(lastContent, (obj) => {
              _streamWriter.write(_streamEnc.encode('data: ' + JSON.stringify(obj) + '\n\n')).catch(() => { });
            });
          } catch (_) { }
          return undefined;
        }
        await streamDoneDbWrites(
          env,
          conversationId,
          model,
          lastContent,
          inputTokens,
          outputTokens,
          costUsd,
          agent_id,
          ctx,
          getLastUserMessageText(messages),
          opts.agentsamAgentRunId || null,
          opts.routingOpts || null,
          0,
          lastUsage.cache_read_input_tokens,
          true,
          opts.persistConversationUserId ?? null,
        );
        await logAssistantCodeArtifactIfPresent(env, {
          fullText: lastContent,
          modelKey: model.model_key,
          conversationId,
          provider: 'openai',
          inputTokens,
          outputTokens,
          computedCostUsd: costUsd,
        });
        enqueueAgentChatDoPersist(env, ctx, conversationId, model.model_key, lastContent, inputTokens, outputTokens);
        await enqueueAgentTelemetryFinalLlmCall(env, ctx, {
          conversationId,
          provider: 'openai',
          modelKey: model.model_key,
          modelRow: model,
          routingOpts: opts.routingOpts || null,
          inputTokens,
          outputTokens,
          cacheReadTokens: lastUsage.cache_read_input_tokens || 0,
          cacheWriteTokens: 0,
          agentId: agent_id,
          agentRunId: opts.agentsamAgentRunId ?? null,
        });
        return jsonResponse({
          content: [{ type: 'text', text: lastContent }],
          message: { content: lastContent, role: 'assistant', tool_calls: allToolCalls.length ? allToolCalls : undefined },
          conversation_id: conversationId,
          stream: false,
          input_tokens: inputTokens,
          output_tokens: outputTokens,
          cost_usd: costUsd,
        });
      }

      if (mode === 'ask') {
        const actionTc = toolCalls.find((tc) => tc.function && isActionTool(tc.function.name));
        if (actionTc) {
          const name = actionTc.function.name;
          let params = {};
          try {
            const fa = actionTc.function.arguments;
            if (fa != null && String(fa).trim() !== '') params = JSON.parse(fa);
          } catch (_) { }
          const toolDesc = (tools.find((t) => t.name === name) || {}).description || name;
          const preview = toolApprovalPreview(name, params);
          return jsonResponse({
            tool_approval_request: true,
            text: lastContent ?? '',
            tool: { name, description: toolDesc, parameters: params, preview },
            conversation_id: conversationId,
          });
        }
      }

      if (wantStream && toolCalls.some((tc) => tc.function?.name?.startsWith('excalidraw_'))) {
        pendingStateEvents.push({ type: 'open_panel', panel: 'draw' });
      }

      messages.push({
        role: 'assistant',
        content: assistantMsg.content ?? null,
        tool_calls: toolCalls,
      });

      for (const tc of toolCalls) {
        const name = tc.function?.name;
        let input = {};
        try {
          const fa = tc.function?.arguments;
          if (fa != null && String(fa).trim() !== '') input = JSON.parse(fa);
        } catch (_) { }
        if (wantStream) {
          const toolLabel = TOOL_DISPLAY[name] ?? name;
          if (opts.streamWriter && opts.streamEnc) {
            try {
              await opts.streamWriter.write(opts.streamEnc.encode('data: ' + JSON.stringify({ type: 'tool_start', tool: name, label: toolLabel }) + '\n\n'));
            } catch (_) { }
          }
          pendingStateEvents.push({ type: 'state', state: 'TOOL_CALL', context: { tool: toolLabel } });
        }
        const out = await invokeMcpToolFromChat(env, name, input, conversationId, {
          executionCtx: ctx,
          oauthUserId: opts.oauthUserId,
          tenantId: opts.routingOpts?.tenantId,
        });
        if (wantStream) {
          pendingStateEvents.push({ type: 'state', state: 'THINKING', context: {} });
        }
        const resultText = out.error ? JSON.stringify({ error: out.error }) : (typeof out.result === 'string' ? out.result : JSON.stringify(out.result || {}));
        if (wantStream && !out.error) {
          try {
            const resultObj = typeof out.result === 'string' ? JSON.parse(out.result) : (out.result || {});
            const events = [];
            if (Array.isArray(resultObj.ui_events) && resultObj.ui_events.length) {
              events.push(...resultObj.ui_events);
            } else if (resultObj.ui_event) {
              events.push(resultObj.ui_event);
            }
            if (events.length) {
              pendingStateEvents.push({ type: 'tool_result', tool: name, result: JSON.stringify(resultObj) });
              for (const evt of events) {
                if (
                  opts.streamWriter &&
                  opts.streamEnc &&
                  evt &&
                  (evt.type === 'r2_file_updated' || evt.type === 'browser_navigate')
                ) {
                  await opts.streamWriter.write(opts.streamEnc.encode('data: ' + JSON.stringify(evt) + '\n\n'));
                }
              }
            }
          } catch (_) { }
        }
        messages.push({
          role: 'tool',
          tool_call_id: tc.id,
          content: resultText.slice(0, 2000),
        });
        allToolCalls.push({ id: tc.id, name, input, result: resultText.slice(0, 500) });
      }

      if (messages.length > 13) {
        const sys = messages[0];
        messages = [sys, ...messages.slice(-12)];
      }
      await new Promise((r) => setTimeout(r, 1000));
    }

    if (iter >= maxToolLoopResolved && (!lastContent || lastContent.trim().length < 10)) {
      const finalRes = await fetch('https://api.openai.com/v1/chat/completions', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${env.OPENAI_API_KEY}`,
        },
        body: JSON.stringify({
          model: model.model_key,
          max_tokens: 4096,
          messages: [
            ...messages,
            {
              role: 'user',
              content:
                'You must reply with a single concise final answer based on the conversation and tool results above. Do not use any tools.',
            },
          ],
        }),
      });
      if (finalRes.ok) {
        const finalData = await finalRes.json();
        const ft = finalData.choices?.[0]?.message?.content;
        if (typeof ft === 'string' && ft.trim()) {
          lastContent = ft.trim();
          const fu = finalData.usage || {};
          lastUsage = {
            input_tokens: (lastUsage.input_tokens || 0) + (fu.prompt_tokens ?? 0),
            output_tokens: (lastUsage.output_tokens || 0) + (fu.completion_tokens ?? 0),
            cache_read_input_tokens: lastUsage.cache_read_input_tokens,
            cache_write_input_tokens: 0,
          };
        }
      }
    }
  };

  if (wantStream) {
    _runLoop().then(async (result) => {
      try {
        if (result instanceof Response) {
          await _streamWriter.close().catch(() => { });
          return;
        }
        for (const evt of pendingStateEvents) {
          await _streamWriter.write(_streamEnc.encode('data: ' + JSON.stringify(evt) + '\n\n'));
        }
        pendingStateEvents.length = 0;
        const finalInputTokens = lastUsage.input_tokens || 0;
        const finalOutputTokens = lastUsage.output_tokens || 0;
        const finalCost = calculateCost(model, finalInputTokens, finalOutputTokens);
        await streamDoneDbWrites(
          env,
          conversationId,
          model,
          lastContent,
          finalInputTokens,
          finalOutputTokens,
          finalCost,
          agent_id,
          ctx,
          getLastUserMessageText(messages),
          opts.agentsamAgentRunId || null,
          opts.routingOpts || null,
          0,
          lastUsage.cache_read_input_tokens,
          true,
          opts.persistConversationUserId ?? null,
        );
        await logAssistantCodeArtifactIfPresent(env, {
          fullText: lastContent,
          modelKey: model.model_key,
          conversationId,
          provider: 'openai',
          inputTokens: finalInputTokens,
          outputTokens: finalOutputTokens,
          computedCostUsd: finalCost,
        });
        enqueueAgentChatDoPersist(env, ctx, conversationId, model.model_key, lastContent, finalInputTokens, finalOutputTokens);
        await enqueueAgentTelemetryFinalLlmCall(env, ctx, {
          conversationId,
          provider: 'openai',
          modelKey: model.model_key,
          modelRow: model,
          routingOpts: opts.routingOpts || null,
          inputTokens: finalInputTokens,
          outputTokens: finalOutputTokens,
          cacheReadTokens: lastUsage.cache_read_input_tokens || 0,
          cacheWriteTokens: 0,
          agentId: agent_id,
          agentRunId: opts.agentsamAgentRunId ?? null,
        });
        await _streamWriter.write(
          _streamEnc.encode(
            'data: ' +
            JSON.stringify({
              type: 'done',
              input_tokens: finalInputTokens,
              output_tokens: finalOutputTokens,
              cost_usd: finalCost,
              conversation_id: conversationId,
              model_used: model.model_key,
            }) +
            '\n\n',
          ),
        );
      } catch (e) {
        try {
          await _streamWriter.write(_streamEnc.encode('data: ' + JSON.stringify({ type: 'error', error: e?.message }) + '\n\n'));
        } catch (_) { }
      } finally {
        await _streamWriter.close().catch(() => { });
      }
    }).catch(async (e) => {
      try {
        await _streamWriter.write(_streamEnc.encode('data: ' + JSON.stringify({ type: 'error', error: e?.message }) + '\n\n'));
      } catch (_) { }
      await _streamWriter.close().catch(() => { });
    });
    return _streamResponse;
  }
  const _loopOut = await _runLoop();
  if (_loopOut instanceof Response) return _loopOut;
  const _finalIn = lastUsage.input_tokens || 0;
  const _finalOut = lastUsage.output_tokens || 0;
  const _finalText = lastContent || '(Tool loop limit reached.)';
  enqueueAgentChatDoPersist(env, ctx, conversationId, model.model_key, _finalText, _finalIn, _finalOut);
  await enqueueAgentTelemetryFinalLlmCall(env, ctx, {
    conversationId,
    provider: 'openai',
    modelKey: model.model_key,
    modelRow: model,
    routingOpts: opts.routingOpts || null,
    inputTokens: _finalIn,
    outputTokens: _finalOut,
    cacheReadTokens: lastUsage.cache_read_input_tokens || 0,
    cacheWriteTokens: 0,
    agentId: agent_id,
    agentRunId: opts.agentsamAgentRunId ?? null,
  });
  return jsonResponse({
    content: [{ type: 'text', text: _finalText }],
    message: { content: _finalText, role: 'assistant', tool_calls: allToolCalls },
    conversation_id: conversationId,
    stream: false,
  });
}

async function chatWithToolsAnthropic(env, request, provider, modelKey, systemWithBlurb, apiMessages, toolDefinitions, modelRow, agent_id, conversationId, attachedFilesFromRequest, executionCtx) {
  const wantStream = true; 
  const mode = 'agent';
  const opts = { routingOpts: { tenantId: resolveTenantIdForWorker({}, env) } }; // Minimal shim
  const preFilteredTools = toolDefinitions;
  const ctx = executionCtx;
  const model = modelRow;

  let resolvedAllowedToolGlobs = null;
  if (
    (resolvedAllowedToolGlobs == null || String(resolvedAllowedToolGlobs).trim() === '') &&
    opts.oauthUserId
  ) {
    const sk =
      opts.subagent_id != null && String(opts.subagent_id).trim() !== ''
        ? String(opts.subagent_id).trim()
        : opts.agent_id != null && String(opts.agent_id).trim() !== ''
          ? String(opts.agent_id).trim()
          : '';
    if (sk) {
      const loaded = await loadSubagentAllowedToolGlobs(env, opts.oauthUserId, sk);
      if (loaded != null) resolvedAllowedToolGlobs = loaded;
    }
  }

  let tools = [];
  try {
    // Use pre-filtered tools from router if provided — avoids reloading all 36 tools
    if (preFilteredTools && Array.isArray(preFilteredTools) && preFilteredTools.length > 0) {
      tools = preFilteredTools.map(t => {
        let rawSchema = t.input_schema || {};
        if (typeof rawSchema === 'string') { try { rawSchema = JSON.parse(rawSchema); } catch (_) { rawSchema = {}; } }
        let input_schema;
        if (rawSchema && rawSchema.type === 'object' && rawSchema.properties) {
          input_schema = rawSchema;
        } else {
          input_schema = { type: 'object', properties: {}, required: [] };
        }
        return { name: t.name || t.tool_name, description: (t.description || t.name || '').slice(0, 500), input_schema };
      });
      console.log('[chatWithToolsAnthropic] Using pre-filtered tools:', tools.length);
    } else {
      const r = await env.DB.prepare(
        `SELECT tool_name, description, input_schema, tool_category FROM mcp_registered_tools WHERE enabled = 1
       AND (modes_json LIKE '%"' || ? || '"%')
       AND is_degraded = 0
       ORDER BY tool_name`
      ).bind(mode).all();
      const filtered = filterToolRowsByPanel(agent_id, r.results || []);
      // Apply mode-based tool filter to cap tokens per LLM call
      const modeFiltered = filterToolsByMode(mode, filtered.map(t => ({ name: t.tool_name, ...t })));
      const modeFilteredNames = new Set(modeFiltered.map(t => t.tool_name || t.name));
      const filteredByMode = filtered.filter(t => modeFilteredNames.has(t.tool_name));
      tools = filteredByMode.map((t) => {
        let rawSchema = {};
        try { rawSchema = typeof t.input_schema === 'string' ? JSON.parse(t.input_schema) : (t.input_schema || {}); } catch (_) { }
        let input_schema;
        if (rawSchema && rawSchema.type === 'object' && rawSchema.properties) {
          input_schema = rawSchema;
        } else {
          const properties = {};
          const required = [];
          for (const [key, val] of Object.entries(rawSchema)) {
            if (key === 'type' || key === 'properties' || key === 'required') continue;
            properties[key] = {
              type: (val && val.type) || 'string',
              ...(val && val.items && { items: val.items }),
              ...(val && val.description && { description: val.description }),
              ...(val && val.enum && { enum: val.enum })
            };
            if (val && val.required) required.push(key);
          }
          input_schema = { type: 'object', properties: Object.keys(properties).length ? properties : {}, required };
        }
        return {
          name: t.tool_name,
          description: (t.description || t.tool_name).slice(0, 500),
          input_schema,
        };
      });
    } // end preFilteredTools else
    if (mode === 'agent') {
      const SYNTHETIC_DASHBOARD_TOOLS = [
        {
          name: 'preview_in_browser',
          description: 'Open a URL in the dashboard browser tab. Pass url directly, or r2Key with optional bucket (default ASSETS for sandbox preview). Public ASSETS URLs use agent_configs slug r2_public_urls.',
          input_schema: {
            type: 'object',
            properties: {
              url: { type: 'string', description: 'Full https URL to open in the embedded browser' },
              r2Key: { type: 'string', description: 'R2 object key; combined with bucket to build public URL' },
              bucket: { type: 'string', description: 'Binding: ASSETS (default), DASHBOARD, DOCS_BUCKET, AUTORAG_BUCKET, agent-sam-sandbox-cicd' },
            },
          },
        },
        {
          name: 'get_r2_url',
          description: 'Return the public HTTPS URL for an R2 object (bucket binding name + key). ASSETS uses agent_configs slug r2_public_urls.',
          input_schema: {
            type: 'object',
            properties: {
              bucket: { type: 'string', description: 'Binding: ASSETS, DASHBOARD, DOCS_BUCKET, AUTORAG_BUCKET, agent-sam-sandbox-cicd (default DASHBOARD)' },
              key: { type: 'string', description: 'Object key path' },
            },
            required: ['key'],
          },
        },
      ];
      const have = new Set(tools.map((t) => t.name));
      for (const s of SYNTHETIC_DASHBOARD_TOOLS) {
        if (!have.has(s.name)) {
          tools.push(s);
          have.add(s.name);
        }
      }
    }
    if (tools.length > 0) {
      try {
        const tenantForIntent =
          (opts.routingOpts && opts.routingOpts.tenantId != null && String(opts.routingOpts.tenantId).trim()) ||
          (env.TENANT_ID ? String(env.TENANT_ID).trim() : null) ||
          null;
        const lastUserForIntent = getLastUserMessageText(apiMessages) || '';
        const intentForFilter = opts._intent || 'auto';
        tools = await filterToolsByIntent(env, tenantForIntent, intentForFilter, lastUserForIntent, tools);
      } catch (e) {
        console.warn('[chatWithToolsAnthropic] filterToolsByIntent', e?.message ?? e);
      }
      if (resolvedAllowedToolGlobs != null && parseMixedToolAllowList(resolvedAllowedToolGlobs).length > 0) {
        tools = filterToolsByAllowPatterns(tools, resolvedAllowedToolGlobs);
      }
    }
  } catch (e) {
    console.error('[chatWithToolsAnthropic] tool load failed:', e?.message ?? e);
  }
  if (tools.length === 0 && !preFilteredTools) return null;
  console.log('[chatWithToolsAnthropic] Loaded tools:', tools.length);
  const intentForLoop = opts._intent || 'mixed';
  let modelPolicyJson = null;
  if (env.DB && agent_id) {
    try {
      const ar = await env.DB.prepare('SELECT model_policy_json FROM agentsam_ai WHERE id = ? LIMIT 1').bind(agent_id).first();
      if (ar?.model_policy_json != null) {
        const raw = ar.model_policy_json;
        modelPolicyJson = typeof raw === 'string' ? JSON.parse(raw) : raw;
      }
    } catch (e) {
      console.warn('[chatWithToolsAnthropic] agentsam_ai.model_policy_json', e?.message ?? e);
    }
  }
  const maxToolLoopResolved = resolveMaxToolLoop(opts, modelPolicyJson, intentForLoop);
  console.log('[chatWithToolsAnthropic] max_tool_loop', { intent: intentForLoop, agent_id, resolved: maxToolLoopResolved });
  const hasWorkspaceTools = tools.some((t) => t && /^workspace_/.test(t.name));
  const systemWithWorkspaceHint = hasWorkspaceTools
    ? `${systemWithBlurb}\n\n## Workspace (PTY host repo)\nUse workspace_read_file to read any file by path when the user references a file not already in context. Use workspace_list_files to explore the repo. Use workspace_search to find symbol definitions, usages, or patterns across the codebase.`
    : systemWithBlurb;
  const resolvedModelKey = resolveAnthropicModelKey(model.model_key);
  const allToolCalls = [];
  let messages = apiMessages.map((m) => ({ role: m.role, content: m.content }));
  let iter = 0;
  let lastContent = '';
  let lastUsage = { input_tokens: 0, output_tokens: 0, cache_creation_input_tokens: 0, cache_read_input_tokens: 0 };

  const encoder = new TextEncoder();
  const enqueue = (controller, obj) => {
    controller.enqueue(encoder.encode('data: ' + JSON.stringify(obj) + '\n\n'));
  };

  const TOOL_DISPLAY = {
    terminal_execute: 'terminal',
    workspace_read_file: 'filesystem',
    workspace_list_files: 'filesystem',
    workspace_search: 'filesystem',
    d1_query: 'D1 database',
    d1_write: 'D1 database',
    r2_read: 'file',
    r2_write: 'file',
    preview_in_browser: 'browser',
    get_r2_url: 'file',
    agentsam_run_agent: 'agentsam_run_agent',
    agentsam_get_agent: 'agentsam_get_agent',
    agentsam_list_agents: 'agentsam_list_agents',
    github_fetch: 'GitHub',
    web_search: 'web',
    deploy_worker: 'deploy',
    bash_cat: 'file',
    bash_find: 'filesystem',
    list_tools: 'tools',
    query_database: 'database',
    excalidraw_open: 'excalidraw',
    excalidraw_add_elements: 'excalidraw',
    excalidraw_load_library: 'excalidraw',
    excalidraw_export: 'excalidraw',
    excalidraw_clear: 'excalidraw',
  };
  const pendingStateEvents = [];
  const flushPendingToolStates = (controller) => {
    for (const evt of pendingStateEvents) enqueue(controller, evt);
    pendingStateEvents.length = 0;
  };

  // ── STREAMING SETUP (moved before loop so client gets response immediately) ──
  let _streamWriter = null;
  let _streamEnc = null;
  let _streamResponse = null;
  if (wantStream) {
    const { readable, writable } = new TransformStream();
    _streamEnc = new TextEncoder();
    _streamWriter = writable.getWriter();
    _streamResponse = new Response(readable, { headers: { 'Content-Type': 'text/event-stream', 'Cache-Control': 'no-cache' } });
    // Pass writer into opts so tool_start can emit immediately
    opts.streamWriter = _streamWriter;
    opts.streamEnc = _streamEnc;
  }

  // Run loop in background IIFE when streaming so response is returned immediately
  const _runLoop = async () => {
    const MAX_TOOL_ITERATIONS = 10;
    let toolIterations = 0;
    const REQUEST_WALL_START = Date.now();

    while (toolIterations < MAX_TOOL_ITERATIONS) {
      if (toolIterations++ >= MAX_TOOL_ITERATIONS) {
        if (_streamWriter) {
          await _streamWriter.write(_streamEnc.encode(`data: ${JSON.stringify({ type: 'text', text: '\n\n[Agent stopped: max tool calls reached]' })}\n\n`));
          await _streamWriter.write(_streamEnc.encode(`data: ${JSON.stringify({ type: 'done', input_tokens: 0, output_tokens: 0, cost_usd: 0 })}\n\n`));
        }
        break;
      }
      if (Date.now() - REQUEST_WALL_START > 90_000) {
        if (_streamWriter) {
          await _streamWriter.write(_streamEnc.encode(`data: ${JSON.stringify({ type: 'text', text: '\n\n[Agent stopped: 90s timeout]' })}\n\n`));
          await _streamWriter.write(_streamEnc.encode(`data: ${JSON.stringify({ type: 'done', input_tokens: 0, output_tokens: 0, cost_usd: 0 })}\n\n`));
        }
        break;
      }
      iter++;
      // Adaptive thinking for Opus 4.6 / Sonnet 4.6 (interleaved auto-enabled, no beta header needed)
      const _isAdaptive = resolvedModelKey.includes('opus-4-6') || resolvedModelKey.includes('sonnet-4-6');
      const _isSimpleIntent = opts._intent === 'sql' || opts._intent === 'question' || opts._intent === 'shell';
      const _thinkingConfig = _isAdaptive ? {
        thinking: { type: 'adaptive', effort: _isSimpleIntent ? 'low' : 'medium' },
      } : {};
      // display:omitted skips streaming thinking tokens → faster first text token for pipelines
      if (_isAdaptive && !wantStream) _thinkingConfig.thinking = { type: 'adaptive', display: 'omitted' };
      let messages = [...apiMessages];
      if (messages.length >= 2) {
        // Cache the last 2 turns (usually the large tool results)
        for (let i = messages.length - 2; i < messages.length; i++) {
          if (messages[i]) {
            if (typeof messages[i].content === 'string') {
                messages[i].content = [{ type: 'text', text: messages[i].content, cache_control: { type: 'ephemeral' } }];
            } else if (Array.isArray(messages[i].content)) {
                // Find the last text or tool_result part and pin it
                const lastPart = messages[i].content[messages[i].content.length - 1];
                if (lastPart) lastPart.cache_control = { type: 'ephemeral' };
            }
          }
        }
      }

      const body = {
        model: modelKey,
        max_tokens: _isAdaptive ? 16000 : 8192,
        system: [{ type: 'text', text: systemWithWorkspaceHint, cache_control: { type: 'ephemeral' } }],
        messages,
        tools,
        ..._thinkingConfig,
      };
      console.log('[chatWithToolsAnthropic] Sending request to Claude', {
        model: modelKey,
        tools_count: tools.length,
        has_tools_in_body: !!tools && tools.length > 0,
      });
      const res = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'x-api-key': env.ANTHROPIC_API_KEY,
          'anthropic-version': '2023-06-01',
        },
        body: JSON.stringify(body),
      });
      console.log('[chatWithToolsAnthropic] Claude API response', { status: res.status, ok: res.ok });
      if (!res.ok) {
        const err = await res.json().catch(() => ({}));
        console.error('[chatWithToolsAnthropic] Anthropic error', JSON.stringify(err));
        return jsonResponse({ error: err.error?.message || res.statusText, stream: false }, res.status);
      }
      const data = await res.json();
      const content = data.content || [];
      lastUsage = { input_tokens: data.usage?.input_tokens ?? 0, output_tokens: data.usage?.output_tokens ?? 0, cache_creation_input_tokens: data.usage?.cache_creation_input_tokens ?? 0, cache_read_input_tokens: data.usage?.cache_read_input_tokens ?? 0 };
      if (env.DB) {
        try {
          let anthRates = opts.modelRates;
          if (!anthRates) {
            try { anthRates = await loadAiModelRatesMap(env); } catch (_) { anthRates = {}; }
          }
          await writeTelemetry(env, {
            sessionId: conversationId,
            tenantId: resolveTelemetryTenantId(env, opts.routingOpts?.tenantId),
            provider: 'anthropic',
            model: model.model_key,
            inputTokens: lastUsage.input_tokens,
            outputTokens: lastUsage.output_tokens,
            cacheReadTokens: lastUsage.cache_read_input_tokens,
            cacheWriteTokens: lastUsage.cache_creation_input_tokens,
            success: true,
            routingDecisionId: opts.routingOpts?.routingDecisionId,
            agentRunId: opts.agentsamAgentRunId,
          }, anthRates);
        } catch (_) { }
      }
      const toolUseBlocks = content.filter((b) => b.type === 'tool_use');
      for (const b of toolUseBlocks) {
        console.log('[chatWithToolsAnthropic] Claude using tool', { tool_name: b.name, tool_id: b.id });
      }
      const textParts = content.filter((b) => b.type === 'text').map((b) => b.text).filter(Boolean);
      lastContent = textParts.join('');
      // ── Stream text immediately after each Anthropic API call ──
      if (wantStream && _streamWriter && lastContent) {
        try {
          await _streamWriter.write(_streamEnc.encode('data: ' + JSON.stringify({ type: 'text', text: lastContent }) + '\n\n'));
        } catch (_) { }
      }

      if (mode === 'ask' && toolUseBlocks.length > 0) {
        const actionBlock = toolUseBlocks.find((b) => isActionTool(b.name));
        if (actionBlock) {
          const toolDesc = (tools.find((t) => t.name === actionBlock.name) || {}).description || actionBlock.name;
          const preview = toolApprovalPreview(actionBlock.name, actionBlock.input);
          if (wantStream) {
            enqueueAgentTelemetryFinalLlmCall(env, ctx, {
              conversationId,
              provider: 'anthropic',
              modelKey: model.model_key,
              modelRow: model,
              routingOpts: opts.routingOpts || null,
              inputTokens: lastUsage.input_tokens,
              outputTokens: lastUsage.output_tokens,
              cacheReadTokens: lastUsage.cache_read_input_tokens || 0,
              cacheWriteTokens: lastUsage.cache_creation_input_tokens || 0,
              agentId: agent_id,
              agentRunId: opts.agentsamAgentRunId ?? null,
            });
            const streamBody = new ReadableStream({
              start(controller) {
                flushPendingToolStates(controller);
                enqueue(controller, { type: 'text', text: lastContent });
                emitCodeBlocksFromText(lastContent, (obj) => enqueue(controller, obj));
                enqueue(controller, {
                  type: 'tool_approval_request',
                  tool: {
                    name: actionBlock.name,
                    description: toolDesc,
                    parameters: actionBlock.input || {},
                    preview,
                  },
                });
                enqueue(controller, { type: 'done', usage: lastUsage });
                controller.close();
              },
            });
            return new Response(streamBody, { headers: { 'Content-Type': 'text/event-stream' } });
          }
          await enqueueAgentTelemetryFinalLlmCall(env, ctx, {
            conversationId,
            provider: 'anthropic',
            modelKey: model.model_key,
            modelRow: model,
            routingOpts: opts.routingOpts || null,
            inputTokens: lastUsage.input_tokens,
            outputTokens: lastUsage.output_tokens,
            cacheReadTokens: lastUsage.cache_read_input_tokens || 0,
            cacheWriteTokens: lastUsage.cache_creation_input_tokens || 0,
            agentId: agent_id,
            agentRunId: opts.agentsamAgentRunId ?? null,
          });
          return jsonResponse({
            tool_approval_request: true,
            text: lastContent,
            tool: { name: actionBlock.name, description: toolDesc, parameters: actionBlock.input || {}, preview },
            conversation_id: conversationId,
          });
        }
      }

      if (toolUseBlocks.length === 0) {
        const inputTokens = lastUsage.input_tokens;
        const outputTokens = lastUsage.output_tokens;
        const costUsd = calculateCost(model, inputTokens, outputTokens);
        if (wantStream) {
          // Per-iteration writeTelemetry above; streamDoneDbWrites in .then() skips duplicate telemetry (omitTelemetryWrite).
          try {
            for (const evt of pendingStateEvents) {
              await _streamWriter.write(_streamEnc.encode('data: ' + JSON.stringify(evt) + '\n\n'));
            }
            pendingStateEvents.length = 0;
            emitCodeBlocksFromText(lastContent, (obj) => {
              _streamWriter.write(_streamEnc.encode('data: ' + JSON.stringify(obj) + '\n\n')).catch(() => { });
            });
          } catch (_) { }
          return;
        }
        await streamDoneDbWrites(
          env,
          conversationId,
          model,
          lastContent,
          inputTokens,
          outputTokens,
          costUsd,
          agent_id,
          ctx,
          getLastUserMessageText(messages),
          opts.agentsamAgentRunId || null,
          opts.routingOpts || null,
          lastUsage.cache_creation_input_tokens,
          lastUsage.cache_read_input_tokens,
          true,
          opts.persistConversationUserId ?? null,
        );
        await logAssistantCodeArtifactIfPresent(env, {
          fullText: lastContent,
          modelKey: model.model_key,
          conversationId,
          provider: 'anthropic',
          inputTokens,
          outputTokens,
          computedCostUsd: costUsd,
        });
        enqueueAgentChatDoPersist(env, ctx, conversationId, model.model_key, lastContent, inputTokens, outputTokens);
        await enqueueAgentTelemetryFinalLlmCall(env, ctx, {
          conversationId,
          provider: 'anthropic',
          modelKey: model.model_key,
          modelRow: model,
          routingOpts: opts.routingOpts || null,
          inputTokens,
          outputTokens,
          cacheReadTokens: lastUsage.cache_read_input_tokens || 0,
          cacheWriteTokens: lastUsage.cache_creation_input_tokens || 0,
          agentId: agent_id,
          agentRunId: opts.agentsamAgentRunId ?? null,
        });
        return jsonResponse({
          content: [{ type: 'text', text: lastContent }],
          message: { content: lastContent, role: 'assistant', tool_calls: allToolCalls.length ? allToolCalls : undefined },
          conversation_id: conversationId,
          stream: false,
          input_tokens: inputTokens,
          output_tokens: outputTokens,
          cost_usd: costUsd,
        });
      }
      if (mode === 'ask') {
        const actionBlock = toolUseBlocks.find((b) => isActionTool(b.name));
        if (actionBlock) {
          const toolDesc = (tools.find((t) => t.name === actionBlock.name) || {}).description || actionBlock.name;
          const preview = toolApprovalPreview(actionBlock.name, actionBlock.input);
          return jsonResponse({
            tool_approval_request: true,
            text: lastContent ?? '',
            tool: { name: actionBlock.name, description: toolDesc, parameters: actionBlock.input || {}, preview },
            conversation_id: conversationId,
          });
        }
      }
      console.log('[chatWithToolsAnthropic] Tool use detected, invoking after response', { count: toolUseBlocks.length });
      // If any excalidraw tool detected, emit open_panel SSE immediately
      if (wantStream && toolUseBlocks.some(b => b.name.startsWith('excalidraw_'))) {
        pendingStateEvents.push({ type: 'open_panel', panel: 'draw' });
      }
      const toolResults = [];
      for (const block of toolUseBlocks) {
        const name = block.name;
        const input = block.input || {};
        if (wantStream) {
          const toolLabel = TOOL_DISPLAY[name] ?? name;
          // Emit tool_start immediately via opts.streamWriter if available
          if (opts.streamWriter && opts.streamEnc) {
            try {
              await opts.streamWriter.write(opts.streamEnc.encode('data: ' + JSON.stringify({ type: 'tool_start', tool: name, label: toolLabel }) + '\n\n'));
            } catch (_) { }
          }
          pendingStateEvents.push({ type: 'state', state: 'TOOL_CALL', context: { tool: toolLabel } });
        }
        const out = await invokeMcpToolFromChat(env, name, input, conversationId, {
          executionCtx: ctx,
          oauthUserId: opts.oauthUserId,
          tenantId: opts.routingOpts?.tenantId,
        });
        if (wantStream) {
          pendingStateEvents.push({ type: 'state', state: 'THINKING', context: {} });
        }
        console.log('[chatWithToolsAnthropic] Tool invoked', {
          tool_name: name,
          tool_id: block.id,
          success: !out.error,
          error: out.error,
        });
        const resultText = out.error ? JSON.stringify({ error: out.error }) : (typeof out.result === 'string' ? out.result : JSON.stringify(out.result || {}));
        // Emit ui_event SSE immediately if tool returned one (e.g. excalidraw tools, r2_write, preview_in_browser)
        if (wantStream && !out.error) {
          try {
            const resultObj = typeof out.result === 'string' ? JSON.parse(out.result) : (out.result || {});
            const events = [];
            if (Array.isArray(resultObj.ui_events) && resultObj.ui_events.length) {
              events.push(...resultObj.ui_events);
            } else if (resultObj.ui_event) {
              events.push(resultObj.ui_event);
            }
            if (events.length) {
              pendingStateEvents.push({ type: 'tool_result', tool: name, result: JSON.stringify(resultObj) });
              for (const evt of events) {
                if (
                  opts.streamWriter &&
                  opts.streamEnc &&
                  evt &&
                  (evt.type === 'r2_file_updated' || evt.type === 'browser_navigate')
                ) {
                  await opts.streamWriter.write(opts.streamEnc.encode('data: ' + JSON.stringify(evt) + '\n\n'));
                }
              }
            }
          } catch (_) { }
        }
        toolResults.push({ type: 'tool_result', tool_use_id: block.id, content: resultText.slice(0, 2000) });
        allToolCalls.push({ id: block.id, name, input, result: resultText.slice(0, 500) });
      }
      messages.push({ role: 'assistant', content });
      messages.push({ role: 'user', content: toolResults });
      console.log('[chatWithToolsAnthropic] Tool results added to messages, sending follow-up request to Claude', { tool_results_count: toolResults.length });
      // Cap messages to last 12 entries to prevent context blowout
      if (messages.length > 12) messages = [messages[0], ...messages.slice(-11)];
      // Delay between iterations to avoid TPM rate limit
      await new Promise(r => setTimeout(r, 1000));
    }

    if (iter >= maxToolLoopResolved && (!lastContent || lastContent.trim().length < 10)) {
      const finalSystem = systemWithWorkspaceHint + '\n\nYou must reply with a single concise final answer based on the conversation and tool results above. Do not use any tools.';
      const finalRes = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'x-api-key': env.ANTHROPIC_API_KEY,
          'anthropic-version': '2023-06-01',
          'anthropic-beta': 'prompt-caching-2024-07-31',
        },
        body: JSON.stringify({
          model: modelKey,
          max_tokens: 4096,
          system: [{ type: 'text', text: finalSystem, cache_control: { type: 'ephemeral' } }],
          messages,
        }),
      });
      if (finalRes.ok) {
        const finalData = await finalRes.json();
        const finalText = (finalData.content || []).filter((b) => b.type === 'text').map((b) => b.text).filter(Boolean).join('');
        if (finalText.trim()) {
          lastContent = finalText.trim();
          lastUsage = { input_tokens: lastUsage.input_tokens + (finalData.usage?.input_tokens ?? 0), output_tokens: lastUsage.output_tokens + (finalData.usage?.output_tokens ?? 0), cache_creation_input_tokens: lastUsage.cache_creation_input_tokens + (finalData.usage?.cache_creation_input_tokens ?? 0), cache_read_input_tokens: lastUsage.cache_read_input_tokens + (finalData.usage?.cache_read_input_tokens ?? 0) };
        }
      }
    }

    // ── END _runLoop ──
  }; // end _runLoop async function

  if (wantStream) {
    // Fire the loop in background, return stream immediately
    _runLoop().then(async (result) => {
      try {
        if (result instanceof Response) {
          await _streamWriter.close().catch(() => { });
          return;
        }
        // Flush any remaining state/tool_result events
        for (const evt of pendingStateEvents) {
          await _streamWriter.write(_streamEnc.encode('data: ' + JSON.stringify(evt) + '\n\n'));
        }
        pendingStateEvents.length = 0;
        // Final done event with cost tracking
        const finalInputTokens = lastUsage.input_tokens || 0;
        const finalOutputTokens = lastUsage.output_tokens || 0;
        const finalCost = calculateCost(model, finalInputTokens, finalOutputTokens);
        await streamDoneDbWrites(
          env,
          conversationId,
          model,
          lastContent,
          finalInputTokens,
          finalOutputTokens,
          finalCost,
          agent_id,
          ctx,
          getLastUserMessageText(messages),
          opts.agentsamAgentRunId || null,
          opts.routingOpts || null,
          lastUsage.cache_creation_input_tokens,
          lastUsage.cache_read_input_tokens,
          true,
          opts.persistConversationUserId ?? null,
        );
        await logAssistantCodeArtifactIfPresent(env, {
          fullText: lastContent,
          modelKey: model.model_key,
          conversationId,
          provider: 'anthropic',
          inputTokens: finalInputTokens,
          outputTokens: finalOutputTokens,
          computedCostUsd: finalCost,
        });
        enqueueAgentChatDoPersist(env, ctx, conversationId, model.model_key, lastContent, finalInputTokens, finalOutputTokens);
        await enqueueAgentTelemetryFinalLlmCall(env, ctx, {
          conversationId,
          provider: 'anthropic',
          modelKey: model.model_key,
          modelRow: model,
          routingOpts: opts.routingOpts || null,
          inputTokens: finalInputTokens,
          outputTokens: finalOutputTokens,
          cacheReadTokens: lastUsage.cache_read_input_tokens || 0,
          cacheWriteTokens: lastUsage.cache_creation_input_tokens || 0,
          agentId: agent_id,
          agentRunId: opts.agentsamAgentRunId ?? null,
        });
        await _streamWriter.write(_streamEnc.encode('data: ' + JSON.stringify({
          type: 'done',
          input_tokens: finalInputTokens,
          output_tokens: finalOutputTokens,
          cost_usd: finalCost,
          conversation_id: conversationId,
          model_used: model.model_key,
        }) + '\n\n'));
      } catch (e) {
        try { await _streamWriter.write(_streamEnc.encode('data: ' + JSON.stringify({ type: 'error', error: e?.message }) + '\n\n')); } catch (_) { }
      } finally {
        await _streamWriter.close().catch(() => { });
      }
    }).catch(async (e) => {
      try { await _streamWriter.write(_streamEnc.encode('data: ' + JSON.stringify({ type: 'error', error: e?.message }) + '\n\n')); } catch (_) { }
      await _streamWriter.close().catch(() => { });
    });
    return _streamResponse;
  }
  // Non-streaming: run loop synchronously
  const _loopOut = await _runLoop();
  if (_loopOut instanceof Response) return _loopOut;
  const _finalIn = lastUsage.input_tokens || 0;
  const _finalOut = lastUsage.output_tokens || 0;
  const _finalText = lastContent || '(Tool loop limit reached.)';
  enqueueAgentChatDoPersist(env, ctx, conversationId, model.model_key, _finalText, _finalIn, _finalOut);
  await enqueueAgentTelemetryFinalLlmCall(env, ctx, {
    conversationId,
    provider: 'anthropic',
    modelKey: model.model_key,
    modelRow: model,
    routingOpts: opts.routingOpts || null,
    inputTokens: _finalIn,
    outputTokens: _finalOut,
    cacheReadTokens: lastUsage.cache_read_input_tokens || 0,
    cacheWriteTokens: lastUsage.cache_creation_input_tokens || 0,
    agentId: agent_id,
    agentRunId: opts.agentsamAgentRunId ?? null,
  });
  return jsonResponse({
    content: [{ type: 'text', text: _finalText }],
    message: { content: _finalText, role: 'assistant', tool_calls: allToolCalls },
    conversation_id: conversationId,
    stream: false,
  });
}

async function processQueues(env) {
  if (!env.DB) return;
  try {
    const { results: sessions } = await env.DB.prepare(
      `SELECT DISTINCT session_id FROM agent_request_queue WHERE status = 'queued'`
    ).all();
    for (const { session_id } of sessions || []) {
      const task = await env.DB.prepare(
        `SELECT * FROM agent_request_queue WHERE session_id = ? AND status = 'queued' ORDER BY position ASC, created_at ASC LIMIT 1`
      ).bind(session_id).first();
      if (!task) continue;
      try {
        await env.DB.prepare(
          `UPDATE agent_request_queue SET status = 'running', updated_at = unixepoch() WHERE id = ?`
        ).bind(task.id).run();
        const payload = task.payload_json ? JSON.parse(task.payload_json) : {};
        await env.DB.prepare(
          `UPDATE agent_request_queue SET status = 'done', result_json = ?, updated_at = unixepoch() WHERE id = ?`
        ).bind(JSON.stringify({ success: true, payload: payload }), task.id).run();
      } catch (e) {
        await env.DB.prepare(
          `UPDATE agent_request_queue SET status = 'failed', result_json = ?, updated_at = unixepoch() WHERE id = ?`
        ).bind(JSON.stringify({ error: String(e?.message || e) }), task.id).run();
      }
    }
  } catch (e) {
    console.warn('[processQueues]', e?.message || e);
  }
}

/** Nightly: update model_routing_rules performance scores from routing_decisions telemetry. */
async function updateRoutingPerformanceScores(env) {
  if (!env.DB) return;
  try {
    await env.DB.prepare(`
      UPDATE model_routing_rules
      SET
        performance_score = (
          SELECT ROUND(AVG(CASE WHEN had_error = 0 THEN 100.0 ELSE 0.0 END), 2)
          FROM routing_decisions
          WHERE task_type = model_routing_rules.task_type
            AND created_at > unixepoch('now', '-7 days')
        ),
        avg_latency_ms = (
          SELECT ROUND(AVG(latency_ms), 0)
          FROM routing_decisions
          WHERE task_type = model_routing_rules.task_type
            AND latency_ms IS NOT NULL
            AND created_at > unixepoch('now', '-7 days')
        )
      WHERE task_type IN (
        SELECT DISTINCT task_type FROM routing_decisions
        WHERE created_at > unixepoch('now', '-7 days')
      )
    `).run();
    console.log('[cron] routing performance scores updated');
  } catch (e) {
    console.warn('[cron] updateRoutingPerformanceScores', e?.message ?? e);
  }
}

/** Close terminal_sessions idle > 24h so active-count stays accurate. */
async function sweepStaleTerminalSessions(env) {
  if (!env.DB) return;
  try {
    const r = await env.DB.prepare(
      `UPDATE terminal_sessions
       SET status = 'closed', closed_at = unixepoch(), updated_at = unixepoch()
       WHERE status = 'active'
         AND updated_at < unixepoch() - 86400`
    ).run();
    const closed = r.meta?.changes ?? r.changes ?? 0;
    if (closed > 0) console.log('[cron] terminal_sessions swept:', closed, 'stale sessions closed');
  } catch (e) {
    console.warn('[cron] sweepStaleTerminalSessions', e?.message ?? e);
  }
}

async function runAgentMemoryDecay(env) {
  if (!env.DB) return;
  const tid = tenantIdFromEnv(env);
  if (!tid) return;
  try {
    const r = await env.DB.prepare(
      `UPDATE agent_memory_index
       SET importance_score = importance_score * decay_rate,
           updated_at = unixepoch()
       WHERE last_accessed_at < unixepoch() - 604800
       AND importance_score > 0.1
       AND tenant_id = ?`
    ).bind(tid).run();
    console.log('[cron] agent_memory_index decay changes:', r.meta?.changes ?? r.changes ?? 0);
  } catch (e) {
    console.warn('[cron] agent_memory_index decay', e?.message ?? e);
  }
}

/** Daily 09:00 UTC: compare spend_ledger today vs ai_guardrails metadata daily budget; email if over. */
async function runFinancialCommandCron(env, ctx) {
  if (!env.DB) return;
  let dailyBudgetUsd = 50;
  try {
    const { results } = await env.DB.prepare(
      `SELECT metadata FROM ai_guardrails WHERE is_active = 1 ORDER BY priority DESC LIMIT 10`
    ).all();
    for (const row of results || []) {
      if (!row?.metadata) continue;
      try {
        const m = JSON.parse(String(row.metadata));
        if (typeof m.daily_budget_usd === 'number') {
          dailyBudgetUsd = m.daily_budget_usd;
          break;
        }
        if (typeof m.daily_spend_cap_usd === 'number') {
          dailyBudgetUsd = m.daily_spend_cap_usd;
          break;
        }
      } catch (_) { /* next row */ }
    }
  } catch (e) {
    console.warn('[cron] financial guardrails read', e?.message ?? e);
  }
  try {
    const finTid = tenantIdFromEnv(env);
    if (!finTid) return;
    const row = await env.DB.prepare(
      `SELECT COALESCE(SUM(amount_usd), 0) AS total FROM spend_ledger
       WHERE tenant_id = ?
       AND date(occurred_at, 'unixepoch') = date('now')`
    ).bind(finTid).first();
    const total = Number(row?.total ?? 0);
    if (total > dailyBudgetUsd) {
      notifySam(env, {
        subject: `Daily spend alert: $${total.toFixed(2)} over cap $${dailyBudgetUsd.toFixed(2)}`,
        body: `Today's spend (spend_ledger): $${total.toFixed(2)}\nConfigured daily budget (ai_guardrails metadata): $${dailyBudgetUsd.toFixed(2)}\n`,
        category: 'finance',
      }, ctx);
    }
  } catch (e) {
    console.warn('[cron] runFinancialCommandCron', e?.message ?? e);
  }
}

/**
 * Allowlisted tables for D1 data_retention_policies purge (column + compare mode).
 * compare: datetime | unix | date_col (TEXT YYYY-MM-DD day bucket: date(col) < date('now','-Nd'))
 * Do NOT add config/registry tables here (mcp_registered_tools, mcp_services, mcp_workflows,
 * mcp_server_allowlist, mcp_service_credentials, terminal_connections) — policies on those names are skipped.
 */
const RETENTION_PURGE_TABLE_CONFIG = {
  github_webhook_events: { dateColumn: 'received_at', compare: 'datetime' },
  webhook_events: { dateColumn: 'processed_at', compare: 'datetime' },
  hook_executions: { dateColumn: 'completed_at', compare: 'datetime' },
  worker_analytics_events: { dateColumn: 'timestamp', compare: 'unix' },
  worker_analytics_errors: { dateColumn: 'created_at', compare: 'unix' },
  notifications: { dateColumn: 'created_at', compare: 'datetime' },
  deployment_notifications: { dateColumn: 'created_at', compare: 'datetime' },
  terminal_history: { dateColumn: 'created_at', compare: 'unix' },
  mcp_tool_calls: { dateColumn: 'created_at', compare: 'datetime' },
  mcp_usage_log: { dateColumn: 'date', compare: 'date_col' },
  mcp_audit_log: { dateColumn: 'created_at', compare: 'unix' },
  mcp_agent_sessions: { dateColumn: 'created_at', compare: 'unix' },
  mcp_tool_call_stats: { dateColumn: 'date', compare: 'date_col' },
  mcp_workflow_runs: { dateColumn: 'created_at', compare: 'unix' },
  mcp_command_suggestions: { dateColumn: 'created_at', compare: 'unix' },
  terminal_sessions: { dateColumn: 'updated_at', compare: 'unix' },
  cicd_runs: { dateColumn: 'created_at', compare: 'datetime' },
  cicd_events: { dateColumn: 'created_at', compare: 'unix' },
  agent_messages: { dateColumn: 'created_at', compare: 'datetime' },
};

function retentionConditionIsSafe(cond) {
  const c = String(cond || '').trim();
  if (!c) return true;
  if (/[;]/.test(c)) return false;
  if (/--|\/\*|\*\//.test(c)) return false;
  if (/\b(attach|detach|pragma|vacuum)\b/i.test(c)) return false;
  if (c.length > 2000) return false;
  return true;
}

/**
 * Midnight cron: batch-delete old rows per data_retention_policies (LIMIT 500 per table per run).
 * Unknown table_name values are skipped. Optional policy.condition appended as AND (...); use D1 for e.g.
 * agent_messages: session_id NOT IN (SELECT id FROM agent_sessions WHERE status = 'active')
 */
async function runRetentionPurge(env) {
  if (!env?.DB) return;
  let policies = [];
  try {
    const q = await env.DB.prepare(
      `SELECT * FROM data_retention_policies WHERE COALESCE(is_active, 1) = 1`
    ).all();
    policies = q.results || [];
  } catch (e) {
    console.warn('[cron] retention policies load', e?.message ?? e);
    await writeAuditLog(env, {
      event_type: 'retention_purge',
      message: 'Failed to load data_retention_policies',
      metadata: { error: String(e?.message || e) },
    });
    return;
  }
  let grandTotal = 0;
  const perTable = [];
  for (const policy of policies) {
    const table = policy.table_name != null ? String(policy.table_name).trim() : '';
    const cfg = RETENTION_PURGE_TABLE_CONFIG[table];
    if (!cfg) {
      console.warn('[cron] retention skip unknown table:', table);
      continue;
    }
    const days = Number(policy.retention_days);
    if (!Number.isFinite(days) || days < 0) continue;
    const dateCol = cfg.dateColumn;
    const ageClause =
      cfg.compare === 'unix'
        ? `${dateCol} < unixepoch('now', '-${days} days')`
        : cfg.compare === 'date_col'
          ? `date(${dateCol}) < date('now', '-${days} days')`
          : `${dateCol} < datetime('now', '-${days} days')`;
    let condClause = '';
    const rawCond = policy.condition != null ? String(policy.condition).trim() : '';
    if (rawCond) {
      if (!retentionConditionIsSafe(rawCond)) {
        console.warn('[cron] retention skip unsafe condition for table:', table);
        perTable.push({ table, deleted: 0, skipped: 'unsafe_condition' });
        continue;
      }
      condClause = ` AND (${rawCond})`;
    }
    const delSql = `DELETE FROM ${table} WHERE ${ageClause}${condClause} LIMIT 500`;
    let deleted = 0;
    try {
      const r = await env.DB.prepare(delSql).run();
      deleted = r.meta?.changes ?? r.changes ?? 0;
    } catch (e) {
      console.warn('[cron] retention DELETE', table, e?.message ?? e);
      perTable.push({ table, deleted: 0, error: String(e?.message || e) });
      continue;
    }
    grandTotal += deleted;
    perTable.push({ table, deleted, capped: deleted === 500 });
    if (deleted === 500) {
      console.log('[cron] retention deleted 500 rows from', table, '(more may remain until next cron)');
    }
    try {
      const rid = policy.id != null ? String(policy.id).trim() : '';
      if (rid) {
        await env.DB.prepare(
          `UPDATE data_retention_policies SET last_purged_at = datetime('now'), rows_purged_total = COALESCE(rows_purged_total, 0) + ? WHERE id = ?`
        ).bind(deleted, rid).run();
      } else {
        await env.DB.prepare(
          `UPDATE data_retention_policies SET last_purged_at = datetime('now'), rows_purged_total = COALESCE(rows_purged_total, 0) + ? WHERE table_name = ?`
        ).bind(deleted, table).run();
      }
    } catch (e) {
      console.warn('[cron] retention policy UPDATE', table, e?.message ?? e);
    }
  }
  await writeAuditLog(env, {
    event_type: 'retention_purge',
    message: `Retention purge completed: ${grandTotal} rows deleted (batch max 500 per table)`,
    metadata: { total: grandTotal, per_table: perTable },
  });
}

async function runWebhookEventsMaintenanceCron(env) {
  if (!env.DB) return;
  try {
    const del = await env.DB.prepare(
      `DELETE FROM webhook_events
       WHERE received_at < datetime('now', '-30 days')
       AND status IN ('processed','ignored','duplicate')`
    ).run();
    console.log('[cron] webhook_events cleanup changes:', del.meta?.changes ?? del.changes ?? 0);
  } catch (e) {
    console.warn('[cron] webhook_events DELETE cleanup', e?.message ?? e);
  }
  try {
    const upd = await env.DB.prepare(
      `UPDATE webhook_events
       SET payload_json = NULL, headers_json = NULL
       WHERE received_at < datetime('now', '-7 days')
       AND status = 'processed'
       AND payload_json IS NOT NULL`
    ).run();
    console.log('[cron] webhook_events payload compression changes:', upd.meta?.changes ?? upd.changes ?? 0);
  } catch (e) {
    console.warn('[cron] webhook_events payload compress', e?.message ?? e);
  }
  try {
    await env.DB.prepare(
      `INSERT OR REPLACE INTO webhook_event_stats
        (date, source, event_type, total, succeeded, failed)
       SELECT
        date(received_at) as date,
        source,
        event_type,
        COUNT(*) as total,
        SUM(CASE WHEN status='processed' THEN 1 ELSE 0 END) as succeeded,
        SUM(CASE WHEN status='failed' THEN 1 ELSE 0 END) as failed
       FROM webhook_events
       WHERE date(received_at) = date('now', '-1 day')
       GROUP BY date, source, event_type`
    ).run();
    console.log('[cron] webhook_event_stats rollup completed');
  } catch (e) {
    console.warn('[cron] webhook_event_stats rollup', e?.message ?? e);
  }
}

async function runSpendLedgerRollup(env) {
  if (!env?.DB) return;
  const now = Math.floor(Date.now() / 1000);
  const currentMonth = new Date().toISOString().slice(0, 7);

  const { results: months = [] } = await env.DB.prepare(
    `SELECT
      tenant_id, workspace_id, brand_id, provider, provider_slug,
      strftime('%Y-%m', occurred_at, 'unixepoch') as month,
      COUNT(*) as row_count,
      ROUND(SUM(amount_usd), 6) as total_usd,
      SUM(tokens_in) as tokens_in,
      SUM(tokens_out) as tokens_out
    FROM spend_ledger
    WHERE strftime('%Y-%m', occurred_at, 'unixepoch') < ?
    GROUP BY tenant_id, provider, month`
  ).bind(currentMonth).all();

  if (!months.length) {
    console.log('[rollup] No completed months to roll up.');
    return;
  }

  for (const row of months) {
    const id = `slr_${row.tenant_id}_${row.provider}_${row.month}`.replace(/[^a-z0-9_]/gi, '_');
    await env.DB.prepare(
      `INSERT INTO spend_ledger_monthly_rollup
        (id, tenant_id, workspace_id, brand_id, provider, provider_slug, month,
         row_count, total_usd, tokens_in, tokens_out, source_deleted, created_at, updated_at)
      VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 0, ?, ?)
      ON CONFLICT(tenant_id, provider, month) DO UPDATE SET
        row_count = excluded.row_count,
        total_usd = excluded.total_usd,
        tokens_in = excluded.tokens_in,
        tokens_out = excluded.tokens_out,
        updated_at = excluded.updated_at`
    ).bind(
      id,
      row.tenant_id,
      row.workspace_id,
      row.brand_id,
      row.provider,
      row.provider_slug,
      row.month,
      row.row_count,
      row.total_usd,
      row.tokens_in,
      row.tokens_out,
      now,
      now
    ).run();
  }

  await env.DB.prepare(
    `DELETE FROM spend_ledger
    WHERE strftime('%Y-%m', occurred_at, 'unixepoch') < ?
      AND source = 'api_direct'`
  ).bind(currentMonth).run();

  await env.DB.prepare(
    `UPDATE spend_ledger_monthly_rollup
     SET source_deleted = 1, updated_at = ?
     WHERE month < ?`
  ).bind(now, currentMonth).run();

  console.log(`[rollup] Completed. ${months.length} provider/month combos rolled up.`);
}

worker.scheduled = async function scheduled(event, env, ctx) {
  if (event.cron === '*/30 * * * *') {
    ctx.waitUntil(processQueues(env));
    ctx.waitUntil(runOvernightCronStep(env));
    ctx.waitUntil(sweepStaleTerminalSessions(env));
  }
  if (event.cron === '0 0 * * *') {
    if (env?.DB) ctx.waitUntil(runRetentionPurge(env));
    if (env?.DB && env?.R2) {
      ctx.waitUntil(
        archiveOldConversations(env).then((r) => {
          console.log('[archive]', JSON.stringify(r));
        })
      );
    }
    if (!env?.DB) return;
    const today = new Date().toISOString().slice(0, 10);
    const already = await env.DB.prepare(
      `SELECT id FROM email_logs
       WHERE subject LIKE '%Daily Digest%'
       AND created_at >= ? LIMIT 1`
    ).bind(`${today}T00:00:00`).first().catch(() => null);
    if (already) return;
    ctx.waitUntil(writeDailySnapshot(env, 'cron_midnight').catch(() => { }));
    ctx.waitUntil(sendDailyDigest(env));
    return;
  }
  if (event.cron === '0 6 * * *') {
    console.log('[cron] Starting daily doc sync (compact -> knowledge sync -> Vectorize index)');
    ctx.waitUntil(
      compactAgentChatsToR2(env)
        .then((r) => {
          if (r.error) console.error('[cron] RAG compact-chats failed:', r.error);
          else console.log('[cron] RAG compact-chats:', r.conversations, 'conversations,', r.messages, 'messages ->', r.key);
        })
        .then(() => runKnowledgeDailySync(env))
        .then((r) => {
          if (r.memory_key || r.priorities_key) console.log('[cron] knowledge sync:', r.memory_key, r.priorities_key);
        })
        .then(() => indexMemoryMarkdownToVectorize(env))
        .then((r) => {
          console.log('[cron] RAG index-memory:', r?.chunks ?? 0, 'chunks from', r?.indexed ?? 0, 'keys');
        })
        .then(() => runAgentMemoryDecay(env))
        .catch((e) => console.error('[cron] RAG sync failed:', e?.message || e))
    );
    ctx.waitUntil(runWebhookEventsMaintenanceCron(env));
    ctx.waitUntil(writeDailySnapshot(env, 'cron_6am').catch(() => { }));
  }
  if (event.cron === '0 9 * * *') {
    ctx.waitUntil(runFinancialCommandCron(env, ctx));
  }
  if (event.cron === '0 9 * * 1') {
    ctx.waitUntil(
      runIntegritySnapshot(env, 'cron').catch((e) => console.warn('[cron] runIntegritySnapshot', e?.message ?? e))
    );
  }
  if (event.cron === '30 13 * * *') {
    ctx.waitUntil(sendDailyPlanEmail(env));
  }
  if (event.cron === '0 0 1 * *') {
    ctx.waitUntil(runSpendLedgerRollup(env));
  }
};
export default worker;

const OAUTH_STATE_TTL = 600;
const DEFAULT_TENANT = 'system';
const PROJECT_ID = 'inneranimalmedia';
function origin(url) { return url.origin; }

/** True when X-Ingest-Secret matches vault/env INGEST_SECRET (MCP / trusted automation). */
function isIngestSecretAuthorized(request, env, secretFn) {
  const h = request.headers.get('X-Ingest-Secret');
  const ingestSecret = secretFn('INGEST_SECRET') ?? env.INGEST_SECRET;
  return !!(ingestSecret && h && h === ingestSecret);
}

/** spend_ledger CHECK expects cloudflare_workers_ai; ai_models may still say workers_ai. */
function spendLedgerProvider(provider) {
  return provider === 'workers_ai' ? 'cloudflare_workers_ai' : provider;
}

function jsonResponse(body, status = 200) {
  const st = Number(status) || 200;
  if (st >= 500 && st < 600 && __iamResponseLog?.env?.DB && __iamResponseLog?.ctx?.waitUntil) {
    const meta = __iamResponseLog;
    const msg =
      body && typeof body.error === 'string'
        ? body.error
        : body && typeof body.message === 'string'
          ? body.message
          : (() => {
            try {
              return JSON.stringify(body).slice(0, 800);
            } catch (_) {
              return '5xx json response';
            }
          })();
    meta.ctx.waitUntil(
      recordWorkerAnalyticsError(meta.env, {
        path: meta.path != null ? String(meta.path) : '',
        method: meta.method != null ? String(meta.method) : 'GET',
        status_code: st,
        error_message: msg,
      })
    );
  }
  return new Response(JSON.stringify(body), {
    status: st,
    headers: { 'Content-Type': 'application/json' },
  });
}

async function handleFederatedSearch(request, env) {
  if (!env.DB) return jsonResponse({ error: 'DB unavailable' }, 503);
  const session = await getSession(env, request);
  if (!session) return jsonResponse({ error: 'Unauthorized' }, 401);

  let body = {};
  try {
    body = await request.json();
  } catch (_) { }
  const query = (body?.query || '').toString().trim();
  if (!query) return jsonResponse({ error: 'query required' }, 400);
  const limit = Math.max(1, Math.min(20, Number(body?.limit || 8)));

  try {
    const out = await unifiedRagSearch(env, query, { topK: limit, federated: true });
    const results = (out.results || []).map((r) => ({
      text: r.text,
      source: r.source,
      source_type: r.source_type,
      score: r.score,
      doc_type: r.doc_type,
      url: r.url != null && r.url !== '' ? r.url : null,
    }));
    return jsonResponse({
      results,
      sources_searched: out._meta?.sources_searched || [],
      query,
      count: out.count ?? 0,
    });
  } catch (e) {
    return jsonResponse({ error: e?.message || String(e) }, 500);
  }
}

/** Subsequence fuzzy bonus (template-style). */
function iamUnifiedSearchFuzzySubsequence(hay, needle) {
  if (!needle) return 0;
  const h = String(hay).toLowerCase();
  const n = String(needle).toLowerCase();
  let qi = 0;
  let score = 0;
  for (let i = 0; i < h.length && qi < n.length; i++) {
    if (h[i] === n[qi]) {
      score += 1;
      qi += 1;
    }
  }
  return qi === n.length ? score : 0;
}

/** Exact / prefix / word / substring scoring (aligned with pasted spec, escaped for regex). */
function iamUnifiedSearchTextScore(text, query, base) {
  const lowerText = String(text || '').toLowerCase();
  const q = String(query || '').toLowerCase().trim();
  if (!q) return base;
  if (lowerText === q) return base + 50;
  if (lowerText.startsWith(q)) return base + 30;
  try {
    const escaped = q.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    if (new RegExp(`\\b${escaped}\\b`).test(lowerText)) return base + 20;
  } catch (_) { }
  if (lowerText.includes(q)) return base + 10;
  return base + iamUnifiedSearchFuzzySubsequence(lowerText, q);
}

function iamD1QuoteIdent(ident) {
  return `"${String(ident).replace(/"/g, '""')}"`;
}

function iamUnifiedSearchDedupeKey(r) {
  const t = r.type;
  const id = r.id != null ? String(r.id) : '';
  if (t === 'conversation') return `conversation:${id}`;
  if (t === 'table') return `table:${id}`;
  if (t === 'snippet') return `snippet:${id}`;
  if (t === 'query') return `query:${id}`;
  if (t === 'deployment') return `deployment:${id}`;
  if (t === 'knowledge') return `knowledge:${id}`;
  if (t === 'column') return `column:${id}`;
  return `${t}:${id || r.title || ''}`;
}

/**
 * Cmd+K palette: parallel-style gather + ranked `results`.
 * Does not use project_files / KV recent / Supabase AutoRAG placeholders (schema differs; KV is MCP-bound).
 */
async function handleUnifiedSearchDashboard(request, env) {
  if (!env.DB) return jsonResponse({ error: 'DB not configured' }, 503);
  const authUser = await getAuthUser(request, env);
  if (!authUser) return jsonResponse({ error: 'Unauthorized' }, 401);
  let body = {};
  try {
    body = await request.json();
  } catch (_) { }
  const query = (body?.query || '').toString().trim();
  if (!query) return jsonResponse({ error: 'query required' }, 400);
  const limit = Math.max(1, Math.min(30, Number(body?.limit) || 20));
  void (body?.workspace_id || '').toString().trim();

  const qlow = query.toLowerCase();
  const like = `%${qlow}%`;
  const uid = authUser.id != null ? String(authUser.id).trim() : '';

  let allTableNames = [];
  const tables = [];
  try {
    const tq = await env.DB.prepare(
      `SELECT name FROM sqlite_master WHERE type = 'table' AND name NOT LIKE 'sqlite_%' ORDER BY name`
    ).all();
    allTableNames = (tq.results || []).map((r) => String(r.name || '').trim()).filter(Boolean);
    for (const name of allTableNames) {
      if (name.toLowerCase().includes(qlow)) {
        tables.push({ type: 'table', id: name, title: name, subtitle: 'D1 table' });
        if (tables.length >= limit) break;
      }
    }
  } catch (e) {
    console.warn('[unified-search] tables', e?.message ?? e);
  }

  const columns = [];
  try {
    const colCap = Math.min(14, limit);
    const maxPragma = Math.min(28, allTableNames.length);
    for (let ti = 0; ti < maxPragma && columns.length < colCap; ti++) {
      const tname = allTableNames[ti];
      const qtbl = iamD1QuoteIdent(tname);
      const pi = await env.DB.prepare(`PRAGMA table_info(${qtbl})`).all();
      for (const col of pi.results || []) {
        const cn = col.name != null ? String(col.name) : '';
        if (!cn || !cn.toLowerCase().includes(qlow)) continue;
        const qtCol = iamD1QuoteIdent(cn);
        const sql_text = `SELECT ${qtCol} FROM ${qtbl} LIMIT 100;`;
        columns.push({
          type: 'column',
          id: `${tname}.${cn}`,
          title: cn,
          subtitle: `${tname} (${col.type != null ? String(col.type) : ''})`,
          sql_text,
        });
        if (columns.length >= colCap) break;
      }
    }
  } catch (e) {
    console.warn('[unified-search] columns', e?.message ?? e);
  }

  const conversations = [];
  try {
    const tenantId = env.TENANT_ID || 'system';
    const sq = await env.DB.prepare(
      `SELECT s.id,
              COALESCE(s.name, ac.name, ac.title, 'Chat') AS name
       FROM agent_sessions s
       LEFT JOIN agent_conversations ac ON ac.id = s.id
       WHERE s.tenant_id = ?
         AND (
           LOWER(COALESCE(s.name, '')) LIKE ?
           OR LOWER(COALESCE(ac.name, '')) LIKE ?
           OR LOWER(COALESCE(ac.title, '')) LIKE ?
         )
       ORDER BY s.updated_at DESC
       LIMIT ?`
    )
      .bind(tenantId, like, like, like, limit)
      .all();
    for (const r of sq.results || []) {
      const id = r.id != null ? String(r.id) : '';
      const title = r.name != null ? String(r.name) : 'Chat';
      if (id) conversations.push({ type: 'conversation', id, title, subtitle: 'Agent Sam chat' });
    }
  } catch (e) {
    console.warn('[unified-search] conversations', e?.message ?? e);
  }

  const convoMessages = [];
  try {
    const tenantId = env.TENANT_ID || 'system';
    const mq = await env.DB.prepare(
      `SELECT am.conversation_id AS id, am.content, am.created_at
       FROM agent_messages am
       JOIN agent_sessions s ON s.id = am.conversation_id
       WHERE s.tenant_id = ?
         AND LOWER(COALESCE(am.content, '')) LIKE ?
       ORDER BY am.created_at DESC
       LIMIT ?`
    )
      .bind(tenantId, like, Math.min(36, limit * 3))
      .all();
    const seen = new Set();
    for (const r of mq.results || []) {
      const id = r.id != null ? String(r.id) : '';
      const content = r.content != null ? String(r.content) : '';
      if (!id || seen.has(id)) continue;
      seen.add(id);
      const preview = content.replace(/\s+/g, ' ').trim().slice(0, 100);
      convoMessages.push({
        type: 'conversation',
        id,
        title: preview || 'Message match',
        subtitle: 'Message match',
      });
      if (convoMessages.length >= Math.min(12, limit)) break;
    }
  } catch (e) {
    console.warn('[unified-search] message body', e?.message ?? e);
  }

  let knowledge = [];
  try {
    const out = await unifiedRagSearch(env, query, { topK: Math.min(10, limit), federated: true });
    knowledge = (out.results || []).map((r, i) => ({
      type: 'knowledge',
      id: `rag:${i}:${(r.text || '').slice(0, 48)}`,
      title: (r.doc_type || r.source_type || r.source || 'chunk').toString().slice(0, 120),
      subtitle: (r.text || '').toString().replace(/\s+/g, ' ').trim().slice(0, 160),
      score: typeof r.score === 'number' ? r.score : null,
      url: r.url != null && r.url !== '' ? String(r.url) : null,
    }));
  } catch (e) {
    console.warn('[unified-search] rag', e?.message ?? e);
  }

  const snippets = [];
  try {
    if (uid) {
      const lim = Math.min(limit, 12);
      const sn = await env.DB.prepare(
        `SELECT id, title, sql_text FROM ai_query_snippets
         WHERE user_id = ? AND (LOWER(title) LIKE ? OR LOWER(sql_text) LIKE ?)
         ORDER BY updated_at DESC LIMIT ?`
      )
        .bind(uid, like, like, lim)
        .all();
      for (const r of sn.results || []) {
        const st = r.sql_text != null ? String(r.sql_text) : '';
        snippets.push({
          type: 'snippet',
          id: r.id != null ? String(r.id) : '',
          title: r.title != null ? String(r.title) : 'Snippet',
          subtitle: st.replace(/\s+/g, ' ').trim().slice(0, 140),
          sql_text: st,
        });
      }
    }
  } catch (e) {
    console.warn('[unified-search] snippets', e?.message ?? e);
  }

  const past_queries = [];
  try {
    if (uid) {
      const lim = Math.min(limit, 12);
      const pq = await env.DB.prepare(
        `SELECT id, sql_text FROM ai_query_history
         WHERE user_id = ? AND LOWER(sql_text) LIKE ?
         ORDER BY created_at DESC LIMIT ?`
      )
        .bind(uid, like, lim)
        .all();
      for (const r of pq.results || []) {
        const st = r.sql_text != null ? String(r.sql_text) : '';
        past_queries.push({
          type: 'query',
          id: r.id != null ? String(r.id) : '',
          title: st.replace(/\s+/g, ' ').trim().slice(0, 100),
          subtitle: 'SQL history',
          sql_text: st,
        });
      }
    }
  } catch (e) {
    console.warn('[unified-search] query history', e?.message ?? e);
  }

  const deployments = [];
  try {
    const lim = Math.min(limit, 12);
    const dq = await env.DB.prepare(
      `SELECT id, worker_name, environment, status, version, timestamp, notes
       FROM deployments
       WHERE LOWER(COALESCE(worker_name, '')) LIKE ?
          OR LOWER(COALESCE(environment, '')) LIKE ?
          OR LOWER(COALESCE(CAST(version AS TEXT), '')) LIKE ?
          OR LOWER(COALESCE(notes, '')) LIKE ?
       ORDER BY timestamp DESC LIMIT ?`
    )
      .bind(like, like, like, like, lim)
      .all();
    for (const r of dq.results || []) {
      const wn = r.worker_name != null ? String(r.worker_name) : '';
      const envn = r.environment != null ? String(r.environment) : '';
      const ver = r.version != null ? String(r.version) : '';
      const st = r.status != null ? String(r.status) : '';
      const ts = r.timestamp != null ? String(r.timestamp) : '';
      deployments.push({
        type: 'deployment',
        id: r.id != null ? String(r.id) : '',
        title: wn || 'deployment',
        subtitle: [envn, st, ver, ts].filter(Boolean).join(' · ').slice(0, 200),
        summary: [wn, envn, ver, st, ts].filter(Boolean).join(' | '),
      });
    }
  } catch (e) {
    console.warn('[unified-search] deployments', e?.message ?? e);
  }

  const scored = [];
  const pushScored = (row, textForScore, base) => {
    scored.push({
      ...row,
      path: row.id || row.path || row.title,
      score: iamUnifiedSearchTextScore(textForScore, query, base),
    });
  };

  for (const d of deployments) pushScored(d, `${d.title} ${d.subtitle || ''}`, 70);
  for (const s of snippets) pushScored(s, `${s.title} ${s.subtitle || ''}`, 68);
  for (const p of past_queries) pushScored(p, `${p.title}`, 62);
  for (const t of tables) pushScored(t, t.title, 100);
  for (const c of columns) pushScored(c, `${c.title} ${c.subtitle || ''}`, 85);
  for (const c of conversations) pushScored(c, `${c.title} ${c.subtitle || ''}`, 88);
  for (const c of convoMessages) pushScored(c, `${c.title} ${c.subtitle || ''}`, 77);
  for (const k of knowledge) {
    const rs = typeof k.score === 'number' ? k.score : 0;
    scored.push({
      ...k,
      path: k.id,
      score: 32 + Math.min(48, rs * 20),
    });
  }

  scored.sort((a, b) => (b.score || 0) - (a.score || 0));
  const merged = new Map();
  for (const r of scored) {
    const key = iamUnifiedSearchDedupeKey(r);
    const prev = merged.get(key);
    if (!prev || (r.score || 0) > (prev.score || 0)) merged.set(key, r);
  }
  const results = Array.from(merged.values())
    .sort((a, b) => (b.score || 0) - (a.score || 0))
    .slice(0, limit);

  const bucketCount =
    deployments.length +
    snippets.length +
    past_queries.length +
    tables.length +
    columns.length +
    conversations.length +
    knowledge.length;

  return jsonResponse({
    query,
    deployments,
    snippets,
    past_queries,
    tables,
    columns,
    conversations,
    knowledge,
    results,
    count: bucketCount,
    results_count: results.length,
  });
}

